CREATE OR REPLACE FUNCTION "battles"."award_battle_xp"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'xp', 'lensers'
    AS $$
DECLARE
    v_contender RECORD;
    v_voter     RECORD;
BEGIN
    -- Only fire when status transitions to 'closed'
    IF NEW.status <> 'closed' OR OLD.status = 'closed' THEN
        RETURN NEW;
    END IF;

    -- Award XP to all human contenders (use contender_ref_id directly)
    FOR v_contender IN
        SELECT c.contender_ref_id AS lenser_id
        FROM battles.contenders c
        WHERE c.battle_id = NEW.id
          AND c.contender_type = 'human'
          AND c.contender_ref_id IS NOT NULL
    LOOP
        PERFORM xp.apply(
            p_lenser_id       := v_contender.lenser_id,
            p_rule_key        := 'BATTLE_PARTICIPATED',
            p_source          := 'battle'::xp.source_enum,
            p_source_ref_type := 'battle',
            p_source_ref_id   := NEW.id,
            p_app_id          := '00000000-0000-0000-0000-000000000002'::uuid
        );
    END LOOP;

    -- Award XP to the winner (if human)
    IF NEW.winner_contender_id IS NOT NULL THEN
        DECLARE
            v_winner RECORD;
        BEGIN
            SELECT
                c.contender_ref_id AS lenser_id,
                c.contender_type::text AS resolved_type
            INTO v_winner
            FROM battles.contenders c
            WHERE c.id = NEW.winner_contender_id;

            IF v_winner.resolved_type = 'human' AND v_winner.lenser_id IS NOT NULL THEN
                PERFORM xp.apply(
                    p_lenser_id       := v_winner.lenser_id,
                    p_rule_key        := 'BATTLE_WON',
                    p_source          := 'battle'::xp.source_enum,
                    p_source_ref_type := 'battle',
                    p_source_ref_id   := NEW.id,
                    p_app_id          := '00000000-0000-0000-0000-000000000002'::uuid
                );
            END IF;
        END;
    END IF;

    -- Award XP to all voters
    FOR v_voter IN
        SELECT v.voter_lenser_id AS lenser_id
        FROM battles.votes v
        WHERE v.battle_id = NEW.id
    LOOP
        PERFORM xp.apply(
            p_lenser_id       := v_voter.lenser_id,
            p_rule_key        := 'BATTLE_VOTED',
            p_source          := 'battle'::xp.source_enum,
            p_source_ref_type := 'battle',
            p_source_ref_id   := NEW.id,
            p_app_id          := '00000000-0000-0000-0000-000000000002'::uuid
        );
    END LOOP;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "battles"."award_battle_xp"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_advance_tournament"("p_match_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_match       battles.tournament_matches;
  v_battle      battles.battles;
  v_winner_tc   battles.tournament_contenders;
  v_contender_a battles.contenders;
  v_contender_b battles.contenders;
  v_winner_id   UUID;
  v_pending     INT;
  v_round       battles.tournament_rounds;
BEGIN
  SELECT * INTO v_match FROM battles.tournament_matches WHERE id = p_match_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Match not found: %', p_match_id; END IF;

  SELECT * INTO v_battle FROM battles.battles WHERE id = v_match.battle_id;

  -- Determine winner from battle result
  IF v_battle.winner_contender_id IS NOT NULL THEN
    -- Find which tournament contender maps to the winner
    SELECT tc.id INTO v_winner_id
    FROM   battles.tournament_contenders tc
    JOIN   battles.contenders c ON c.battle_id = v_battle.id
    WHERE  c.id = v_battle.winner_contender_id
    AND    tc.tournament_id = v_match.tournament_id
    LIMIT 1;
  END IF;

  IF v_winner_id IS NOT NULL THEN
    UPDATE battles.tournament_matches
    SET winner_tournament_contender_id = v_winner_id
    WHERE id = p_match_id;

    UPDATE battles.tournament_contenders
    SET status = 'eliminated'
    WHERE tournament_id = v_match.tournament_id
    AND   id IN (v_match.contender_a_id, v_match.contender_b_id)
    AND   id <> v_winner_id;
  END IF;

  -- Check if round is complete
  SELECT * INTO v_round FROM battles.tournament_rounds WHERE id = v_match.round_id;

  SELECT COUNT(*) INTO v_pending
  FROM   battles.tournament_matches
  WHERE  round_id    = v_match.round_id
  AND    winner_tournament_contender_id IS NULL;

  IF v_pending = 0 THEN
    UPDATE battles.tournament_rounds SET status = 'completed' WHERE id = v_match.round_id;

    -- Check if tournament is complete (only one non-eliminated contender)
    SELECT COUNT(*) INTO v_pending
    FROM   battles.tournament_contenders
    WHERE  tournament_id = v_match.tournament_id
    AND    status        = 'active';

    IF v_pending <= 1 THEN
      UPDATE battles.tournament_contenders
      SET status = 'winner'
      WHERE tournament_id = v_match.tournament_id AND status = 'active';

      UPDATE battles.tournaments
      SET status = 'completed', updated_at = now()
      WHERE id = v_match.tournament_id;
    ELSE
      -- Create next round (simple: pair remaining active contenders)
      PERFORM battles.fn_create_next_tournament_round(v_match.tournament_id, v_round.round_number + 1);
    END IF;
  END IF;
END;
$$;


ALTER FUNCTION "battles"."fn_advance_tournament"("p_match_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_auto_close_voting"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  r      RECORD;
  closed INT := 0;
BEGIN
  FOR r IN
    SELECT id
    FROM   battles.battles
    WHERE  status          = 'voting'
    AND    voting_closes_at < now()
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      UPDATE battles.battles
      SET    status = 'scoring'
      WHERE  id = r.id;

      INSERT INTO audit.events (event_type, payload)
      VALUES ('battle.voting_auto_closed', jsonb_build_object('battle_id', r.id));

      closed := closed + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'fn_auto_close_voting: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN closed;
END;
$$;


ALTER FUNCTION "battles"."fn_auto_close_voting"() OWNER TO "postgres";


