CREATE OR REPLACE FUNCTION "battles"."fn_claim_battle_execution_job"("p_worker_id" "text") RETURNS TABLE("job_id" "uuid", "battle_id" "uuid", "contender_id" "uuid", "slot" "text", "task_prompt" "text", "provider_key" "text", "model_key" "text", "byok_key_ref_id" "uuid", "lens_id" "uuid", "version_id" "uuid", "max_tokens" integer, "temperature" numeric, "retry_count" integer, "ai_lenser_id" "uuid", "personality_note" "text", "personality_version_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'public'
    AS $$
DECLARE
  v_job  battles.battle_execution_jobs;
BEGIN
  SELECT j.*
  INTO   v_job
  FROM   battles.battle_execution_jobs j
  WHERE  j.status = 'queued'
    -- Respect backoff: fn_requeue_battle_job_with_backoff encodes the earliest
    -- pickup time in claimed_at. NULL = never been claimed; future = on backoff.
    AND    (j.claimed_at IS NULL OR j.claimed_at <= now())
  ORDER  BY j.created_at
  LIMIT  1
  FOR UPDATE SKIP LOCKED;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  UPDATE battles.battle_execution_jobs
  SET    status     = 'claimed',
         worker_id  = p_worker_id,
         claimed_at = now()
  WHERE  id = v_job.id;

  RETURN QUERY
    SELECT
      v_job.id,
      v_job.battle_id,
      v_job.contender_id,
      v_job.slot,
      b.task_prompt,
      COALESCE(ec.provider_key, ''),
      COALESCE(ec.model_key,    ''),
      ec.byok_key_ref_id,
      cla.lens_id,
      cla.version_id,
      COALESCE(ec.max_tokens,   4096),
      COALESCE(ec.temperature,  0.7),
      v_job.retry_count,
      al.id,
      al.personality_note,
      plb.version_id
    FROM battles.battles b
    LEFT JOIN battles.execution_configs ec
           ON ec.battle_id    = v_job.battle_id
          AND (ec.contender_id = v_job.contender_id OR ec.contender_id IS NULL)
    LEFT JOIN battles.contender_lens_assignments cla
           ON cla.contender_id = v_job.contender_id
    LEFT JOIN battles.contenders con
           ON con.id              = v_job.contender_id
          AND con.contender_type  = 'ai_agent'
    LEFT JOIN agents.ai_lensers al
           ON al.profile_id      = con.contender_ref_id
    LEFT JOIN agents.lens_bindings plb
           ON plb.ai_lenser_id   = al.id
          AND plb.is_default     = TRUE
          AND 'personality'      = ANY(plb.category_tags)
    WHERE b.id = v_job.battle_id
    ORDER BY ec.contender_id NULLS LAST
    LIMIT 1;
END;
$$;


ALTER FUNCTION "battles"."fn_claim_battle_execution_job"("p_worker_id" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "battles"."fn_claim_battle_execution_job"("p_worker_id" "text") IS 'CU fix: adds (claimed_at IS NULL OR claimed_at <= now()) guard so fn_requeue_battle_job_with_backoff exponential delays are respected. Previously, requeued jobs were immediately re-claimed on the next tick.';



CREATE OR REPLACE FUNCTION "battles"."fn_clone_battle_for_rematch"("p_parent_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_parent          battles.battles%ROWTYPE;
  v_new_id          uuid;
  v_new_slug        text;
  v_invite_code     text;
  v_active_count    int;
  v_slot_count      int;
BEGIN
  SELECT * INTO v_parent
    FROM battles.battles
   WHERE id = p_parent_id
     AND deleted_at IS NULL;

  IF v_parent.id IS NULL THEN
    RAISE EXCEPTION 'parent_battle_not_found: %', p_parent_id
      USING ERRCODE = 'P0002';
  END IF;

  IF v_parent.status NOT IN ('closed','published','archived') THEN
    RAISE EXCEPTION
      'parent_battle_not_terminal: status=% (must be closed/published/archived)',
      v_parent.status
      USING ERRCODE = '22023';
  END IF;

  -- Slug: parent slug + '-r' + 6 random hex chars. Truncate parent prefix to
  -- 200 chars to keep the result well under any reasonable length cap.
  v_new_slug := substr(v_parent.slug, 1, 200) || '-r' ||
                substr(replace(gen_random_uuid()::text, '-', ''), 1, 6);

  v_invite_code := substr(replace(gen_random_uuid()::text, '-', ''), 1, 12);

  INSERT INTO battles.battles (
    creator_lenser_id, title, slug, task_prompt, rubric_id,
    status, invite_code, max_contenders,
    battle_type, voter_eligibility, handicap_config,
    workflow_id, lens_id, content_type,
    parent_battle_id
  )
  VALUES (
    v_parent.creator_lenser_id,
    'Rematch: ' || v_parent.title,
    v_new_slug,
    v_parent.task_prompt,
    v_parent.rubric_id,
    'draft'::battles.battle_status_enum,
    v_invite_code,
    v_parent.max_contenders,
    v_parent.battle_type,
    v_parent.voter_eligibility,
    v_parent.handicap_config,
    v_parent.workflow_id,
    v_parent.lens_id,
    v_parent.content_type,
    v_parent.id
  )
  RETURNING id INTO v_new_id;

  -- Count active parent contenders so we can compute the rotation modulus.
  SELECT count(*) INTO v_active_count
    FROM battles.contenders
   WHERE battle_id = v_parent.id
     AND contender_status = 'active';

  IF v_active_count = 0 THEN
    RETURN v_new_id;
  END IF;

  -- Distinct slots across active contenders (used as rotation modulus).
  -- We rotate within the *occupied* slots, sorted ascending.
  WITH active AS (
    SELECT id, slot, contender_type, contender_ref_id, display_name,
           team_id, entry_mode,
           ROW_NUMBER() OVER (ORDER BY slot ASC) - 1 AS idx,
           COUNT(*)     OVER ()                       AS total
      FROM battles.contenders
     WHERE battle_id = v_parent.id
       AND contender_status = 'active'
  ),
  slot_order AS (
    SELECT slot,
           ROW_NUMBER() OVER (ORDER BY slot ASC) - 1 AS slot_idx
      FROM (
        SELECT DISTINCT slot
          FROM battles.contenders
         WHERE battle_id = v_parent.id
           AND contender_status = 'active'
      ) s
  )
  INSERT INTO battles.contenders (
    battle_id, slot, contender_type, contender_ref_id,
    display_name, team_id, entry_mode, contender_status
  )
  SELECT
    v_new_id,
    -- Rotation: contender at idx i is reseated into the slot at position
    -- (i - 1) mod total, taken from slot_order. For total=2 this is a swap;
    -- for total>=3 this is a left rotation by one position.
    (SELECT slot FROM slot_order
       WHERE slot_idx = ((a.idx - 1 + a.total) % a.total)),
    a.contender_type,
    a.contender_ref_id,
    a.display_name,
    a.team_id,
    a.entry_mode,
    -- Reset lifecycle: the rematch starts fresh, so reseated contenders
    -- enter as 'pending' rather than inheriting 'active'. The owner must
    -- re-open / re-publish the rematch.
    'pending'::text
  FROM active a;

  RETURN v_new_id;
END;
$$;


ALTER FUNCTION "battles"."fn_clone_battle_for_rematch"("p_parent_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "battles"."fn_clone_battle_for_rematch"("p_parent_id" "uuid") IS 'Phase V1 internal helper. Clones a terminal-state parent battle (closed/published/archived) into a fresh draft, copies the structural columns, rotates contender slots by one position, and links parent_battle_id. Performs NO ownership check — callers must enforce that. Service role only; the public-facing wrapper is public.fn_battles_create_rematch.';



CREATE OR REPLACE FUNCTION "battles"."fn_complete_battle_execution_job"("p_job_id" "uuid", "p_status" "text", "p_output_text" "text" DEFAULT NULL::"text", "p_error" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_job           battles.battle_execution_jobs;
  v_battle        battles.battles;
  v_pending_count INT;
BEGIN
  SELECT * INTO v_job FROM battles.battle_execution_jobs WHERE id = p_job_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'job not found: %', p_job_id; END IF;

  SELECT * INTO v_battle FROM battles.battles WHERE id = v_job.battle_id;

  -- Update job terminal state
  UPDATE battles.battle_execution_jobs
  SET    status       = p_status,
         completed_at = now(),
         error_message = p_error
  WHERE  id = p_job_id;

  -- On success: record the submission
  IF p_status = 'completed' AND p_output_text IS NOT NULL THEN
    INSERT INTO battles.submissions (battle_id, contender_id, content_text, content_url, status)
    VALUES (v_job.battle_id, v_job.contender_id, p_output_text, NULL, 'submitted')
    ON CONFLICT (battle_id, contender_id) DO UPDATE SET content_text = EXCLUDED.content_text, status = 'submitted';
  END IF;

  -- If both jobs are now done (completed or failed), auto-start voting
  SELECT COUNT(*)
  INTO   v_pending_count
  FROM   battles.battle_execution_jobs
  WHERE  battle_id = v_job.battle_id
  AND    status    NOT IN ('completed','failed');

  IF v_pending_count = 0 AND v_battle.status = 'executing' THEN
    PERFORM battles.fn_battles_start_voting_internal(
      v_job.battle_id,
      now() + (v_battle.voting_duration_hours || ' hours')::INTERVAL
    );
  END IF;

  INSERT INTO audit.events (event_type, payload)
  VALUES ('battle.execution_job_completed', jsonb_build_object(
    'job_id',     p_job_id,
    'battle_id',  v_job.battle_id,
    'slot',       v_job.slot,
    'status',     p_status
  ));
END;
$$;


ALTER FUNCTION "battles"."fn_complete_battle_execution_job"("p_job_id" "uuid", "p_status" "text", "p_output_text" "text", "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_create_next_tournament_round"("p_tournament_id" "uuid", "p_round_number" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  v_tournament  battles.tournaments;
  v_contenders  battles.tournament_contenders[];
  v_round       battles.tournament_rounds;
  i             INT;
  v_a           battles.tournament_contenders;
  v_b           battles.tournament_contenders;
  v_battle      battles.battles;
BEGIN
  SELECT * INTO v_tournament FROM battles.tournaments WHERE id = p_tournament_id;

  SELECT array_agg(tc ORDER BY tc.seed)
  INTO   v_contenders
  FROM   battles.tournament_contenders tc
  WHERE  tc.tournament_id = p_tournament_id AND tc.status = 'active';

  IF array_length(v_contenders, 1) < 2 THEN RETURN; END IF;

  INSERT INTO battles.tournament_rounds (tournament_id, round_number, status)
  VALUES (p_tournament_id, p_round_number, 'active')
  RETURNING * INTO v_round;

  i := 1;
  WHILE i <= array_length(v_contenders, 1) / 2 LOOP
    v_a := v_contenders[i * 2 - 1];
    v_b := v_contenders[i * 2];

    INSERT INTO battles.battles (
      title, task_prompt, battle_type, voter_eligibility, status, slug,
      execution_starts_at, auto_publish, voting_duration_hours,
      ai_judge_enabled, ai_judge_model_key, creator_lenser_id
    )
    SELECT
      v_tournament.title || ' — Round ' || p_round_number || ' Match ' || i,
      'Tournament match',
      v_tournament.battle_type,
      'open', 'open',
      lower(regexp_replace(v_tournament.title, '[^a-zA-Z0-9]', '-', 'g')) || '-r' || p_round_number || 'm' || i,
      now() + INTERVAL '5 minutes',
      TRUE, 24,
      v_tournament.ai_judge_enabled,
      CASE WHEN v_tournament.ai_judge_enabled THEN 'claude-sonnet-4-6' ELSE NULL END,
      v_tournament.creator_lenser_id
    RETURNING * INTO v_battle;

    INSERT INTO battles.tournament_matches
      (tournament_id, round_id, battle_id, contender_a_id, contender_b_id)
    VALUES
      (p_tournament_id, v_round.id, v_battle.id, v_a.id, v_b.id);

    i := i + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "battles"."fn_create_next_tournament_round"("p_tournament_id" "uuid", "p_round_number" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_create_rematch_internal"("p_parent_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public', 'battles', 'lensers'
    AS $$
BEGIN
  RETURN battles.fn_clone_battle_for_rematch(p_parent_id);
END;
$$;


ALTER FUNCTION "battles"."fn_create_rematch_internal"("p_parent_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "battles"."fn_create_rematch_internal"("p_parent_id" "uuid") IS 'Phase V1/V4: service-role-only entry point that bypasses caller ownership. Used by battles.fn_dispatch_series_rematches to chain a series. NEVER grant this to authenticated.';



CREATE OR REPLACE FUNCTION "battles"."fn_dispatch_recurring_battle_templates"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  t           RECORD;
  new_battle  battles.battles;
  dispatched  INT := 0;
BEGIN
  FOR t IN
    SELECT * FROM battles.templates
    WHERE  recurrence_rule IS NOT NULL
    AND    next_run_at     IS NOT NULL
    AND    next_run_at     <= now()
  LOOP
    -- Create battle from template
    INSERT INTO battles.battles (
      title, task_prompt, battle_type, voter_eligibility,
      status, slug, execution_starts_at, auto_publish,
      voting_duration_hours, creator_lenser_id
    )
    SELECT
      t.title,
      t.task_prompt,
      t.battle_type,
      t.voter_eligibility,
      'open',
      lower(regexp_replace(t.title, '[^a-zA-Z0-9]', '-', 'g')) || '-' || to_char(now(), 'YYYYMMDD-HH24MISS'),
      now() + (t.auto_start_delay_hours || ' hours')::INTERVAL,
      TRUE,
      COALESCE(t.voting_duration_hours, 24),
      t.creator_lenser_id
    RETURNING * INTO new_battle;

    -- Advance next_run_at by a simple daily/weekly interval parsed from recurrence_rule.
    -- Full RRULE parsing is left to application layer; here we support FREQ=DAILY and FREQ=WEEKLY.
    UPDATE battles.templates
    SET next_run_at = CASE
      WHEN recurrence_rule LIKE '%FREQ=DAILY%'  THEN next_run_at + INTERVAL '1 day'
      WHEN recurrence_rule LIKE '%FREQ=WEEKLY%' THEN next_run_at + INTERVAL '7 days'
      WHEN recurrence_rule LIKE '%FREQ=HOURLY%' THEN next_run_at + INTERVAL '1 hour'
      ELSE NULL
    END
    WHERE id = t.id;

    dispatched := dispatched + 1;
  END LOOP;
  RETURN dispatched;
END;
$$;


ALTER FUNCTION "battles"."fn_dispatch_recurring_battle_templates"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_dispatch_series_rematches"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public', 'battles', 'lensers', 'lenses'
    AS $$
DECLARE
  v_series       record;
  v_parent_id    uuid;
  v_new_id       uuid;
  v_next_pos     int;
  v_count        int := 0;
  v_now          timestamptz := now();
BEGIN
  FOR v_series IN
    SELECT id, seed_battle_id, cron_expr
      FROM battles.series
     WHERE is_active = true
       AND next_dispatch_at <= v_now
     ORDER BY next_dispatch_at ASC
  LOOP
    BEGIN
      -- Cron-gate. If the expression doesn't match this hour, advance the
      -- pointer and move on.
      IF NOT lenses.fn_cron_matches_now(v_series.cron_expr, v_now) THEN
        UPDATE battles.series
           SET next_dispatch_at = date_trunc('hour', v_now) + interval '1 hour'
         WHERE id = v_series.id;
        CONTINUE;
      END IF;

      -- Find the parent: most recent member of the chain, fallback to seed.
      SELECT sb.battle_id, sb.position + 1
        INTO v_parent_id, v_next_pos
        FROM battles.series_battles sb
       WHERE sb.series_id = v_series.id
       ORDER BY sb.position DESC
       LIMIT 1;

      IF v_parent_id IS NULL THEN
        v_parent_id := v_series.seed_battle_id;
        v_next_pos  := 1;
      END IF;

      -- Spawn the rematch via the service-role internal entry point. This
      -- bypasses the caller-ownership check, which is correct here because
      -- the dispatcher runs as service_role and only iterates series that
      -- their owners explicitly created.
      v_new_id := battles.fn_create_rematch_internal(v_parent_id);

      INSERT INTO battles.series_battles (series_id, battle_id, position)
      VALUES (v_series.id, v_new_id, v_next_pos);

      UPDATE battles.series
         SET next_dispatch_at = date_trunc('hour', v_now) + interval '1 hour'
       WHERE id = v_series.id;

      v_count := v_count + 1;

    EXCEPTION WHEN OTHERS THEN
      -- Per-series isolation: never let one bad series block the rest.
      -- Advance the pointer so we don't busy-loop on a permanently broken
      -- series at every dispatcher tick.
      UPDATE battles.series
         SET next_dispatch_at = date_trunc('hour', v_now) + interval '1 hour'
       WHERE id = v_series.id;
      RAISE WARNING 'series_dispatch_failed: series_id=%, sqlstate=%, message=%',
        v_series.id, SQLSTATE, SQLERRM;
    END;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "battles"."fn_dispatch_series_rematches"() OWNER TO "postgres";


COMMENT ON FUNCTION "battles"."fn_dispatch_series_rematches"() IS 'Phase V4 dispatcher. Hourly cron entry point. Advances every active series whose cron expression matches now(), spawning a rematch via battles.fn_create_rematch_internal. Per-series errors are swallowed and logged as WARNING so one bad series cannot block the rest. Service role only.';



CREATE OR REPLACE FUNCTION "battles"."fn_get_ai_judge_verdicts"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "contender_id" "uuid", "criterion_id" "uuid", "score" numeric, "rationale" "text", "model_key" "text", "run_id" "uuid", "created_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT
    v.id,
    v.contender_id,
    v.criterion_id,
    v.score,
    v.rationale,
    v.model_key,
    v.run_id,
    v.created_at
  FROM battles.ai_judge_verdicts v
  WHERE v.battle_id = p_battle_id
    AND EXISTS (
      SELECT 1
      FROM battles.battles b
      WHERE b.id = p_battle_id
        AND b.status IN ('published', 'closed')
    )
  ORDER BY v.contender_id, v.criterion_id NULLS LAST;
$$;


ALTER FUNCTION "battles"."fn_get_ai_judge_verdicts"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_get_public_execution_jobs"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "slot" "text", "status" "text", "claimed_at" timestamp with time zone, "completed_at" timestamp with time zone, "retry_count" integer, "created_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT
    j.id,
    j.battle_id,
    j.slot,
    j.status,
    j.claimed_at,
    j.completed_at,
    j.retry_count,
    j.created_at
  FROM battles.battle_execution_jobs j
  WHERE j.battle_id = p_battle_id
    AND EXISTS (
      SELECT 1
      FROM battles.battles b
      WHERE b.id = p_battle_id
        AND b.status IN ('executing', 'voting', 'scoring', 'closed', 'published')
    )
  ORDER BY j.slot;
$$;


ALTER FUNCTION "battles"."fn_get_public_execution_jobs"("p_battle_id" "uuid") OWNER TO "postgres";


