CREATE OR REPLACE FUNCTION "battles"."fn_move_battle_job_to_dlq"("p_job_id" "uuid", "p_error_code" "text" DEFAULT NULL::"text", "p_error_msg" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  v_job battles.battle_execution_jobs;
  v_dlq_id UUID;
BEGIN
  SELECT * INTO v_job FROM battles.battle_execution_jobs WHERE id = p_job_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'job not found: %', p_job_id; END IF;

  INSERT INTO battles.battle_execution_dead_letters
    (job_id, battle_id, contender_id, slot, error_code, error_message, attempt_count)
  VALUES
    (p_job_id, v_job.battle_id, v_job.contender_id, v_job.slot,
     p_error_code, p_error_msg, v_job.retry_count + 1)
  RETURNING id INTO v_dlq_id;

  UPDATE battles.battle_execution_jobs
  SET    status = 'failed', error_message = p_error_msg
  WHERE  id = p_job_id;

  RETURN v_dlq_id;
END;
$$;


ALTER FUNCTION "battles"."fn_move_battle_job_to_dlq"("p_job_id" "uuid", "p_error_code" "text", "p_error_msg" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_populate_contender_entity_map"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
BEGIN
  INSERT INTO battles.contender_entity_map (
    contender_id,
    profile_id,
    ai_lenser_id
  )
  VALUES (
    NEW.id,
    CASE WHEN NEW.contender_type = 'human'
         THEN NEW.contender_ref_id
         ELSE NULL END,
    CASE WHEN NEW.contender_type IN ('ai_model', 'ai_agent')
         THEN NEW.contender_ref_id
         ELSE NULL END
  )
  ON CONFLICT (contender_id) DO NOTHING;
  RETURN NEW;
END;
$$;


