COMMENT ON FUNCTION "battles"."fn_populate_contender_entity_map"() IS 'AFTER INSERT trigger on battles.contenders. Auto-populates battles.contender_entity_map from contender_ref_id + contender_type. Ensures the canonical typed reference is always created with the contender.';



CREATE OR REPLACE FUNCTION "battles"."fn_reclaim_stale_battle_jobs"("p_stale_after_minutes" integer DEFAULT 10) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'public'
    AS $$
DECLARE
  r         RECORD;
  reclaimed integer := 0;
BEGIN
  FOR r IN
    SELECT j.id, j.battle_id, j.contender_id, j.slot, j.retry_count, j.max_retries
    FROM   battles.battle_execution_jobs j
    WHERE  j.status     = 'claimed'
      AND  j.claimed_at < now() - (p_stale_after_minutes || ' minutes')::interval
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      IF r.retry_count >= r.max_retries - 1 THEN
        -- Max retries exhausted: move to DLQ.
        UPDATE battles.battle_execution_jobs
        SET    status        = 'failed',
               error_message = 'stale_claim: worker did not complete within timeout',
               completed_at  = now()
        WHERE  id = r.id;

        -- Re-use the existing DLQ function (handles the dead-letter insert).
        PERFORM battles.fn_move_battle_job_to_dlq(
          r.id,
          'stale_claim.max_retries_exceeded',
          format(
            'Worker did not complete job within %s minutes (retry_count=%s, max_retries=%s)',
            p_stale_after_minutes, r.retry_count, r.max_retries
          )
        );
      ELSE
        -- Still have retries left: return to queued immediately (no backoff added
        -- here — the worker will apply exponential backoff on its next failure).
        UPDATE battles.battle_execution_jobs
        SET    status        = 'queued',
               worker_id     = NULL,
               claimed_at    = NULL,
               retry_count   = retry_count + 1,
               error_message = format(
                 'stale_claim: requeued after %s-minute worker timeout (attempt %s)',
                 p_stale_after_minutes, retry_count + 1
               )
        WHERE  id = r.id;
      END IF;

      INSERT INTO audit.events (event_type, payload)
      VALUES (
        'battle.stale_job_reclaimed',
        jsonb_build_object(
          'job_id',      r.id,
          'battle_id',   r.battle_id,
          'slot',        r.slot,
          'retry_count', r.retry_count,
          'to_dlq',      r.retry_count >= r.max_retries - 1
        )
      );

      reclaimed := reclaimed + 1;
    EXCEPTION WHEN OTHERS THEN
      -- Per-job errors must not abort the sweep.
      RAISE WARNING 'fn_reclaim_stale_battle_jobs: job % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN reclaimed;
END;
$$;


ALTER FUNCTION "battles"."fn_reclaim_stale_battle_jobs"("p_stale_after_minutes" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "battles"."fn_reclaim_stale_battle_jobs"("p_stale_after_minutes" integer) IS 'CU: Reclaims battle execution jobs stuck in ''claimed'' status when a worker crashes mid-execution. Returns them to ''queued'' (with retry++) or moves them to the DLQ when max_retries is exhausted. Runs every 2 min via pg_cron.';



CREATE OR REPLACE FUNCTION "battles"."fn_record_ai_judge_verdict"("p_battle_id" "uuid", "p_verdicts" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  v        JSONB;
  inserted INT := 0;
BEGIN
  FOR v IN SELECT * FROM jsonb_array_elements(p_verdicts)
  LOOP
    INSERT INTO battles.ai_judge_verdicts
      (battle_id, contender_id, criterion_id, score, rationale, model_key, run_id)
    VALUES (
      p_battle_id,
      (v->>'contender_id')::UUID,
      CASE WHEN v->>'criterion_id' IS NOT NULL THEN (v->>'criterion_id')::UUID ELSE NULL END,
      (v->>'score')::NUMERIC,
      v->>'rationale',
      COALESCE(v->>'model_key', 'claude-sonnet-4-6'),
      CASE WHEN v->>'run_id' IS NOT NULL THEN (v->>'run_id')::UUID ELSE NULL END
    );
    inserted := inserted + 1;
  END LOOP;

  -- Trigger finalization when ai_judge_enabled
  IF EXISTS (
    SELECT 1 FROM battles.battles
    WHERE id = p_battle_id AND ai_judge_enabled = TRUE AND status IN ('scoring', 'voting')
  ) THEN
    PERFORM public.fn_battles_finalize(p_battle_id);
  END IF;

  RETURN inserted;
END;
$$;


ALTER FUNCTION "battles"."fn_record_ai_judge_verdict"("p_battle_id" "uuid", "p_verdicts" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_refresh_all_vote_velocities"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  r        RECORD;
  refreshed INT := 0;
BEGIN
  FOR r IN
    SELECT DISTINCT b.id
    FROM   battles.battles b
    JOIN   battles.votes v ON v.battle_id = b.id
    WHERE  b.status = 'published'
    AND    v.created_at >= now() - INTERVAL '48 hours'
  LOOP
    PERFORM battles.fn_refresh_vote_velocity(r.id);
    refreshed := refreshed + 1;
  END LOOP;
  RETURN refreshed;
END;
$$;


ALTER FUNCTION "battles"."fn_refresh_all_vote_velocities"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_refresh_vote_velocity"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  v_published_at TIMESTAMPTZ;
  v_hours        NUMERIC;
  v_votes_24h    INT;
BEGIN
  SELECT published_at INTO v_published_at FROM battles.battles WHERE id = p_battle_id;
  IF v_published_at IS NULL THEN RETURN; END IF;

  v_hours := GREATEST(1, EXTRACT(EPOCH FROM (now() - v_published_at)) / 3600.0);

  SELECT COUNT(*) INTO v_votes_24h
  FROM   battles.votes
  WHERE  battle_id  = p_battle_id
  AND    created_at >= now() - INTERVAL '24 hours';

  UPDATE battles.battles
  SET    vote_velocity = ROUND((v_votes_24h / v_hours)::NUMERIC, 4)
  WHERE  id = p_battle_id;
END;
$$;


ALTER FUNCTION "battles"."fn_refresh_vote_velocity"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_requeue_battle_job_with_backoff"("p_job_id" "uuid", "p_backoff_ms" integer, "p_error" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
BEGIN
  UPDATE battles.battle_execution_jobs
  SET    status        = 'queued',
         worker_id     = NULL,
         claimed_at    = now() + (p_backoff_ms || ' milliseconds')::INTERVAL,
         retry_count   = retry_count + 1,
         error_message = p_error
  WHERE  id = p_job_id;
END;
$$;


ALTER FUNCTION "battles"."fn_requeue_battle_job_with_backoff"("p_job_id" "uuid", "p_backoff_ms" integer, "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_retry_dead_letter_battle_job"("p_dead_letter_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles'
    AS $$
DECLARE
  v_dlq battles.battle_execution_dead_letters;
BEGIN
  SELECT * INTO v_dlq FROM battles.battle_execution_dead_letters WHERE id = p_dead_letter_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'dead letter not found: %', p_dead_letter_id; END IF;
  IF v_dlq.resolved_at IS NOT NULL THEN RAISE EXCEPTION 'dead letter already resolved'; END IF;

  -- Requeue the original job
  UPDATE battles.battle_execution_jobs
  SET    status        = 'queued',
         worker_id     = NULL,
         claimed_at    = NULL,
         retry_count   = retry_count + 1,
         error_message = NULL
  WHERE  id = v_dlq.job_id;

  -- Mark DLQ entry as resolved
  UPDATE battles.battle_execution_dead_letters
  SET    resolved_at = now()
  WHERE  id = p_dead_letter_id;
END;
$$;


ALTER FUNCTION "battles"."fn_retry_dead_letter_battle_job"("p_dead_letter_id" "uuid") OWNER TO "postgres";


