CREATE OR REPLACE FUNCTION "public"."fn_admin_get_stuck_battles"("p_threshold_minutes" integer DEFAULT 30) RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "status" "text", "updated_at" timestamp with time zone, "stale_seconds" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
BEGIN
  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'INSUFFICIENT_PRIVILEGE';
  END IF;
  RETURN QUERY
    SELECT
      b.id,
      b.slug,
      b.title,
      b.status::TEXT,
      b.updated_at,
      ROUND(EXTRACT(EPOCH FROM (now() - b.updated_at))::NUMERIC, 1) AS stale_seconds
    FROM battles.battles b
    WHERE b.status IN ('executing', 'scoring')
      AND b.updated_at < now() - (p_threshold_minutes || ' minutes')::INTERVAL
    ORDER BY b.updated_at ASC;
END;
$$;


ALTER FUNCTION "public"."fn_admin_get_stuck_battles"("p_threshold_minutes" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_admin_get_vote_anomalies"("p_status" "text" DEFAULT 'pending'::"text", "p_battle_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 100) RETURNS SETOF "audit"."vote_anomalies"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
BEGIN
  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'Forbidden: super_admin required' USING ERRCODE = 'P0003';
  END IF;

  RETURN QUERY
    SELECT *
      FROM audit.vote_anomalies
     WHERE (
       p_status = 'all'
       OR (p_status = 'pending'  AND resolved_at IS NULL)
       OR (p_status = 'resolved' AND resolved_at IS NOT NULL)
     )
       AND (p_battle_id IS NULL OR battle_id = p_battle_id)
     ORDER BY detected_at DESC
     LIMIT LEAST(p_limit, 500);
END;
$$;


