CREATE OR REPLACE FUNCTION "public"."fn_battles_auto_promote"("p_battle_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'public'
    AS $$
DECLARE
  v_readiness JSONB;
  v_battle    RECORD;
BEGIN
  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id AND status = 'draft';
  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  v_readiness := public.fn_battles_check_readiness(p_battle_id);

  IF NOT (v_readiness ->> 'ready')::BOOLEAN THEN
    RETURN FALSE;
  END IF;

  UPDATE battles.battles
     SET status = 'open',
         updated_at = now()
   WHERE id = p_battle_id
     AND status = 'draft';

  IF FOUND THEN
    INSERT INTO audit.events (actor_id, event_type, resource_type, resource_id, meta)
    VALUES (
      NULL,
      'battle.auto_promoted',
      'battle',
      p_battle_id,
      jsonb_build_object('readiness', v_readiness)
    );
    RETURN TRUE;
  END IF;

  RETURN FALSE;
END;
$$;


