COMMENT ON FUNCTION "public"."fn_battles_auto_promote"("p_battle_id" "uuid") IS 'CB: Promotes draft→open when readiness check passes. service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_auto_schedule_contenders"("p_battle_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_max_contenders INT;
  v_existing_count INT;
  v_to_assign      INT;
  v_assigned       INT := 0;
  rec              RECORD;
BEGIN
  -- Read max_contenders; default to 2
  SELECT COALESCE(max_contenders, 2)
    INTO v_max_contenders
    FROM battles.battles
   WHERE id = p_battle_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Battle not found' USING ERRCODE = 'P0002';
  END IF;

  SELECT COUNT(*)
    INTO v_existing_count
    FROM battles.contenders
   WHERE battle_id = p_battle_id;

  v_to_assign := v_max_contenders - v_existing_count;
  IF v_to_assign <= 0 THEN
    RETURN 0;
  END IF;

  FOR rec IN
    SELECT al.id AS lenser_id
      FROM lensers.ai_lensers al
     WHERE al.is_available = TRUE
       AND NOT EXISTS (
         SELECT 1 FROM battles.contenders c
          WHERE c.battle_id = p_battle_id
            AND c.lenser_id = al.id
       )
     ORDER BY al.last_active_at DESC NULLS LAST
     LIMIT v_to_assign
  LOOP
    INSERT INTO battles.contenders (battle_id, lenser_id, slot, status)
    VALUES (p_battle_id, rec.lenser_id,
      CASE WHEN v_assigned = 0 THEN 'A' ELSE 'B' END,
      'pending')
    ON CONFLICT DO NOTHING;
    v_assigned := v_assigned + 1;
  END LOOP;

  RETURN v_assigned;
END;
$$;


ALTER FUNCTION "public"."fn_battles_auto_schedule_contenders"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battles_auto_schedule_contenders"("p_battle_id" "uuid") IS 'CB: Assigns available AI lensers up to max_contenders for auto-assign battles.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_change_vote"("p_battle_id" "uuid", "p_new_contender_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_voter      UUID;
  v_status     TEXT;
  v_existing   battles.votes%ROWTYPE;
  v_old_cid    UUID;
BEGIN
  v_voter := lensers.get_auth_lenser_id();
  IF v_voter IS NULL THEN
    RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501';
  END IF;

  SELECT status::text INTO v_status
    FROM battles.battles WHERE id = p_battle_id;

  IF v_status IS NULL THEN
    RAISE EXCEPTION 'battle_not_found' USING ERRCODE = '42501';
  END IF;
  IF v_status <> 'voting' THEN
    RAISE EXCEPTION 'battle_closed: status=%', v_status USING ERRCODE = 'P0001';
  END IF;

  -- contender must belong to this battle
  IF NOT EXISTS (
    SELECT 1 FROM battles.contenders
     WHERE id = p_new_contender_id AND battle_id = p_battle_id
  ) THEN
    RAISE EXCEPTION 'contender_not_in_battle' USING ERRCODE = '22023';
  END IF;

  SELECT * INTO v_existing
    FROM battles.votes
   WHERE battle_id = p_battle_id
     AND voter_lenser_id = v_voter
   FOR UPDATE;

  IF v_existing.id IS NULL THEN
    -- First vote — just delegate to fn_submit_vote semantics inline.
    INSERT INTO battles.votes (
      battle_id, voter_lenser_id, vote_value, voted_contender_id, is_draw, rationale
    )
    VALUES (
      p_battle_id, v_voter, 'contender_a'::battles.vote_value_enum,
      p_new_contender_id, false, NULL
    )
    RETURNING * INTO v_existing;

    INSERT INTO battles.vote_aggregates (
      battle_id, contender_id, raw_vote_count, weighted_vote_sum, draw_count
    ) VALUES (
      p_battle_id, p_new_contender_id, 1, 1, 0
    )
    ON CONFLICT (battle_id, contender_id) DO UPDATE SET
      raw_vote_count    = battles.vote_aggregates.raw_vote_count + 1,
      weighted_vote_sum = battles.vote_aggregates.weighted_vote_sum + 1,
      updated_at        = now();

    UPDATE battles.battles
       SET total_vote_count = total_vote_count + 1
     WHERE id = p_battle_id;

    RETURN jsonb_build_object(
      'vote_id',    v_existing.id,
      'updated_at', v_existing.updated_at,
      'status',     'created'
    );
  END IF;

  v_old_cid := v_existing.voted_contender_id;
  IF v_old_cid IS NOT DISTINCT FROM p_new_contender_id THEN
    -- No-op; touch updated_at so callers can see the action.
    UPDATE battles.votes
       SET updated_at = now()
     WHERE id = v_existing.id
     RETURNING updated_at INTO v_existing.updated_at;

    RETURN jsonb_build_object(
      'vote_id',    v_existing.id,
      'updated_at', v_existing.updated_at,
      'status',     'unchanged'
    );
  END IF;

  -- Swap: decrement the old aggregate, increment the new one, update the row.
  UPDATE battles.vote_aggregates
     SET raw_vote_count    = GREATEST(raw_vote_count    - 1, 0),
         weighted_vote_sum = GREATEST(weighted_vote_sum - 1, 0),
         updated_at        = now()
   WHERE battle_id = p_battle_id
     AND contender_id = v_old_cid;

  INSERT INTO battles.vote_aggregates (
    battle_id, contender_id, raw_vote_count, weighted_vote_sum, draw_count
  ) VALUES (
    p_battle_id, p_new_contender_id, 1, 1, 0
  )
  ON CONFLICT (battle_id, contender_id) DO UPDATE SET
    raw_vote_count    = battles.vote_aggregates.raw_vote_count + 1,
    weighted_vote_sum = battles.vote_aggregates.weighted_vote_sum + 1,
    updated_at        = now();

  UPDATE battles.votes
     SET voted_contender_id = p_new_contender_id
   WHERE id = v_existing.id
   RETURNING * INTO v_existing;

  RETURN jsonb_build_object(
    'vote_id',    v_existing.id,
    'updated_at', v_existing.updated_at,
    'status',     'changed'
  );
END $$;


ALTER FUNCTION "public"."fn_battles_change_vote"("p_battle_id" "uuid", "p_new_contender_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_check_readiness"("p_battle_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_battle         RECORD;
  v_contender_cnt  INT;
  v_blockers       TEXT[] := '{}';
  v_render_ok      BOOLEAN := TRUE;
  v_byok_ok        BOOLEAN := TRUE;
  v_byok_result    JSONB;
  rec              RECORD;
BEGIN
  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ready', false, 'blockers', ARRAY['battle_not_found']);
  END IF;

  -- Check template valid (template_id set)
  IF v_battle.template_id IS NULL AND (v_battle.task_prompt IS NULL OR v_battle.task_prompt = '') THEN
    v_blockers := v_blockers || ARRAY['no_template_or_task_prompt'];
  END IF;

  -- Check render prompt succeeds (only if template_id set)
  IF v_battle.template_id IS NOT NULL THEN
    BEGIN
      PERFORM public.fn_battles_render_prompt(p_battle_id, '{}'::JSONB);
    EXCEPTION WHEN OTHERS THEN
      v_render_ok := FALSE;
      v_blockers  := v_blockers || ARRAY[CONCAT('prompt_render_failed:', SQLERRM)];
    END;
  END IF;

  -- Check ≥2 contenders assigned
  SELECT COUNT(*) INTO v_contender_cnt
    FROM battles.contenders
   WHERE battle_id = p_battle_id;

  IF v_contender_cnt < 2 THEN
    v_blockers := v_blockers || ARRAY[CONCAT('insufficient_contenders:', v_contender_cnt::TEXT)];
  END IF;

  -- Check BYOK valid for AI contenders
  FOR rec IN
    SELECT c.id AS contender_id
      FROM battles.contenders c
     WHERE c.battle_id = p_battle_id
       AND c.contender_type IN ('ai_model', 'ai_agent')
  LOOP
    v_byok_result := public.fn_byok_validate_for_battle(p_battle_id, rec.contender_id);
    IF NOT (v_byok_result ->> 'valid')::BOOLEAN THEN
      v_blockers := v_blockers || ARRAY[
        CONCAT('byok_invalid:contender=', rec.contender_id,
               ':reason=', v_byok_result ->> 'reason')
      ];
      v_byok_ok := FALSE;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'ready',    array_length(v_blockers, 1) IS NULL,
    'blockers', v_blockers
  );
END;
$$;


ALTER FUNCTION "public"."fn_battles_check_readiness"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battles_check_readiness"("p_battle_id" "uuid") IS 'CB: Returns {ready, blockers[]} for a battle. Used before auto-promote.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_clone"("p_battle_id" "uuid", "p_title" "text", "p_slug" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_lenser_id uuid;
    v_source RECORD;
    v_new_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT * INTO v_source
    FROM battles.battles
    WHERE id = p_battle_id
      AND deleted_at IS NULL;

    IF v_source IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    INSERT INTO battles.battles (
        creator_lenser_id, title, slug, task_prompt,
        rubric_id, status, max_contenders
    )
    VALUES (
        v_lenser_id, p_title, p_slug, v_source.task_prompt,
        v_source.rubric_id, 'draft', v_source.max_contenders
    )
    RETURNING id INTO v_new_id;

    -- Log the event
    INSERT INTO battles.events (battle_id, event_type, actor_id, metadata)
    VALUES (
        v_new_id,
        'status_change',
        v_lenser_id,
        jsonb_build_object('action', 'cloned', 'source_battle_id', p_battle_id)
    );

    RETURN v_new_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_clone"("p_battle_id" "uuid", "p_title" "text", "p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_close"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_lenser_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id != v_lenser_id THEN
        RAISE EXCEPTION 'Only the battle creator can close';
    END IF;

    IF v_battle.status NOT IN ('open', 'scoring') THEN
        RAISE EXCEPTION 'Battle must be in open or scoring status to close (current: %)', v_battle.status;
    END IF;

    UPDATE battles.battles
    SET status = 'closed',
        finalized_at = now(),
        updated_at = now()
    WHERE id = p_battle_id;

    -- Log the event
    INSERT INTO battles.events (battle_id, event_type, actor_id, metadata)
    VALUES (
        p_battle_id,
        'status_change',
        v_lenser_id,
        jsonb_build_object('from', v_battle.status::text, 'to', 'closed')
    );
END;
$$;


ALTER FUNCTION "public"."fn_battles_close"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_create"("p_title" "text", "p_slug" "text", "p_task_prompt" "text", "p_rubric_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_lenser_id   uuid;
  v_battle_id   uuid;
  v_count       integer;
  v_oldest_at   timestamptz;
  v_retry_after integer;
BEGIN
  v_lenser_id := lensers.get_auth_lenser_id();
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT count(*), min(created_at)
    INTO v_count, v_oldest_at
    FROM battles.battles
   WHERE creator_lenser_id = v_lenser_id
     AND created_at > now() - interval '1 hour';

  IF v_count >= 20 THEN
    v_retry_after := GREATEST(0, EXTRACT(epoch FROM (v_oldest_at + interval '1 hour' - now()))::integer);
    RAISE EXCEPTION 'battle_rate_limit_exceeded'
      USING HINT   = 'p0429',
            DETAIL = '{"retry_after":' || v_retry_after || '}';
  END IF;

  INSERT INTO battles.battles (creator_lenser_id, title, slug, task_prompt, rubric_id, status)
  VALUES (v_lenser_id, p_title, p_slug, p_task_prompt, p_rubric_id, 'draft')
  RETURNING id INTO v_battle_id;

  RETURN v_battle_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_create"("p_title" "text", "p_slug" "text", "p_task_prompt" "text", "p_rubric_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_create_from_template"("p_template_id" "uuid", "p_title" "text", "p_slug" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_template RECORD;
  v_lenser_id uuid;
  v_battle_id uuid;
BEGIN
  v_lenser_id := lensers.get_auth_lenser_id();

  SELECT * INTO v_template
    FROM battles.templates
   WHERE id = p_template_id
     AND deleted_at IS NULL
     AND (is_public = true OR creator_lenser_id = v_lenser_id);

  IF v_template IS NULL THEN
    RAISE EXCEPTION 'Template not found or not accessible';
  END IF;

  INSERT INTO battles.battles (
    creator_lenser_id, title, slug, task_prompt, rubric_id,
    status, max_contenders, template_id
  )
  VALUES (
    v_lenser_id, p_title, p_slug, v_template.task_prompt,
    v_template.rubric_id, 'draft', v_template.max_contenders, p_template_id
  )
  RETURNING id INTO v_battle_id;

  RETURN v_battle_id;
END $$;


