COMMENT ON FUNCTION "public"."fn_battles_notify_webhooks"("p_battle_id" "uuid", "p_event_type" "text", "p_payload" "jsonb") IS 'CB: Inserts webhook_outbox entries for matching active subscriptions.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_open"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_code text;
BEGIN
    SELECT * INTO v_battle
    FROM battles.battles
    WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id <> lensers.get_auth_lenser_id() THEN
        RAISE EXCEPTION 'Only the battle creator can open a battle';
    END IF;

    IF v_battle.status <> 'draft' THEN
        RAISE EXCEPTION 'Battle must be in draft status to open (current: %)', v_battle.status;
    END IF;

    -- Generate invite code if not set
    v_code := v_battle.invite_code;
    IF v_code IS NULL THEN
        v_code := upper(substr(md5(gen_random_uuid()::text), 1, 8));
    END IF;

    UPDATE battles.battles
    SET status = 'open', invite_code = v_code, updated_at = now()
    WHERE id = p_battle_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_open"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_publish"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_lenser_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id != v_lenser_id THEN
        RAISE EXCEPTION 'Only the battle creator can publish';
    END IF;

    IF v_battle.status != 'closed' THEN
        RAISE EXCEPTION 'Battle must be in closed status to publish (current: %)', v_battle.status;
    END IF;

    UPDATE battles.battles
    SET status = 'published',
        published_at = now(),
        updated_at = now()
    WHERE id = p_battle_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_publish"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_render_prompt"("p_template_id" "uuid", "p_variables" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
DECLARE
  v_template     RECORD;
  v_rendered     TEXT;
  v_var          RECORD;
  v_value        TEXT;
BEGIN
  SELECT id, task_prompt, creator_lenser_id, is_public
    INTO v_template
    FROM battles.templates
   WHERE id = p_template_id
     AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'template_not_found' USING ERRCODE = '42501';
  END IF;

  -- Accessibility: owner OR public template OR anonymous read of public.
  IF NOT v_template.is_public
     AND v_template.creator_lenser_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'template_not_accessible' USING ERRCODE = '42501';
  END IF;

  v_rendered := v_template.task_prompt;

  FOR v_var IN
    SELECT variable_key, default_value, required
      FROM battles.template_prompt_variables
     WHERE template_id = p_template_id
     ORDER BY ordinal, variable_key
  LOOP
    v_value := COALESCE(
      NULLIF(p_variables->>v_var.variable_key, ''),
      v_var.default_value
    );

    IF v_value IS NULL THEN
      IF v_var.required THEN
        RAISE EXCEPTION 'missing_required_variable: %', v_var.variable_key
          USING ERRCODE = '22023';
      END IF;
      v_value := '';
    END IF;

    -- Plain text substitution, including the braces.
    v_rendered := REPLACE(
      v_rendered,
      '{{' || v_var.variable_key || '}}',
      v_value
    );
  END LOOP;

  RETURN v_rendered;
END $$;


ALTER FUNCTION "public"."fn_battles_render_prompt"("p_template_id" "uuid", "p_variables" "jsonb") OWNER TO "postgres";


