CREATE OR REPLACE FUNCTION "public"."fn_clone_lens"("p_source_lens_id" "uuid", "p_version_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers', 'content'
    AS $$
  SELECT lenses.fn_clone_lens(p_source_lens_id, p_version_id);
$$;


ALTER FUNCTION "public"."fn_clone_lens"("p_source_lens_id" "uuid", "p_version_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_clone_workflow"("p_source_workflow_id" "uuid") RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "title" "text", "description" "text", "visibility" "text", "battle_count" integer, "reaction_totals" "jsonb", "fork_count" integer, "parent_workflow_id" "uuid", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'xp', 'lensers', 'auth'
    AS $$
DECLARE
  v_caller_id uuid;
  v_source    lenses.workflows%ROWTYPE;
  v_new_id    uuid := gen_random_uuid();
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT wf.* INTO v_source
  FROM lenses.workflows wf
  WHERE wf.id = p_source_workflow_id;

  IF NOT FOUND OR v_source.visibility::text != 'public' THEN
    RAISE EXCEPTION 'Workflow not found or not public';
  END IF;

  -- Create new workflow (private, owned by caller)
  INSERT INTO lenses.workflows (id, lenser_id, title, description, visibility, battle_count, fork_count)
  VALUES (
    v_new_id,
    v_caller_id,
    'Fork of ' || v_source.title,
    v_source.description,
    'private',
    0,
    0
  );

  UPDATE lenses.workflows wf2
  SET parent_workflow_id = p_source_workflow_id
  WHERE wf2.id = v_new_id;

  -- Copy nodes with config, building old->new id map
  CREATE TEMP TABLE _clone_node_map (old_id uuid, new_id uuid) ON COMMIT DROP;

  INSERT INTO _clone_node_map (old_id, new_id)
  SELECT n.id, gen_random_uuid()
  FROM lenses.workflow_nodes n
  WHERE n.workflow_id = p_source_workflow_id;

  INSERT INTO lenses.workflow_nodes (id, workflow_id, lens_id, version_id, position_x, position_y, label, ordinal, config)
  SELECT m.new_id, v_new_id, n.lens_id, n.version_id, n.position_x, n.position_y, n.label, n.ordinal, n.config
  FROM lenses.workflow_nodes n
  JOIN _clone_node_map m ON m.old_id = n.id;

  -- Copy edges, translating old node ids to new ids
  INSERT INTO lenses.workflow_edges (id, workflow_id, source_node_id, target_node_id, source_output_key, target_param_label)
  SELECT
    gen_random_uuid(),
    v_new_id,
    ms.new_id,
    mt.new_id,
    e.source_output_key,
    e.target_param_label
  FROM lenses.workflow_edges e
  JOIN _clone_node_map ms ON ms.old_id = e.source_node_id
  JOIN _clone_node_map mt ON mt.old_id = e.target_node_id
  WHERE e.workflow_id = p_source_workflow_id;

  -- Increment fork_count on source
  UPDATE lenses.workflows src
  SET fork_count = src.fork_count + 1
  WHERE src.id = p_source_workflow_id;

  -- Award XP (best-effort)
  BEGIN
    PERFORM xp.apply(
      v_caller_id,
      'WORKFLOW_FORKED',
      'content'::xp.source_enum,
      'workflow',
      v_new_id
    );
    PERFORM xp.apply(
      v_source.lenser_id,
      'WORKFLOW_FORK_RECEIVED',
      'content'::xp.source_enum,
      'workflow',
      p_source_workflow_id
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN QUERY
    SELECT
      w.id, w.lenser_id, w.title, w.description, w.visibility::text,
      w.battle_count, w.reaction_totals, w.fork_count, w.parent_workflow_id,
      w.created_at, w.updated_at
    FROM lenses.workflows w
    WHERE w.id = v_new_id;
END;
$$;


ALTER FUNCTION "public"."fn_clone_workflow"("p_source_workflow_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_clone_workflow"("p_source_workflow_id" "uuid") IS 'Clones a public workflow including nodes (with config), edges, and XP awards. Returns the new workflow row.';



CREATE OR REPLACE FUNCTION "public"."fn_complete_onboarding"("p_handle" "text", "p_display_name" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_existing_profile_id UUID;
BEGIN
  -- Confirm the caller owns a profile
  SELECT id INTO v_existing_profile_id
  FROM lensers.profiles
  WHERE user_id = auth.uid()
  LIMIT 1;

  IF v_existing_profile_id IS NULL THEN
    RAISE EXCEPTION 'PROFILE_NOT_FOUND';
  END IF;

  -- Guard handle uniqueness (raise on conflict so UI can show a clear error)
  IF EXISTS (
    SELECT 1 FROM lensers.profiles
    WHERE handle = lower(p_handle)
      AND id <> v_existing_profile_id
  ) THEN
    RAISE EXCEPTION 'HANDLE_TAKEN';
  END IF;

  UPDATE lensers.profiles
  SET
    handle              = lower(p_handle),
    display_name        = p_display_name,
    onboarding_step     = 2,
    onboarding_completed_at = now(),
    updated_at          = now()
  WHERE id = v_existing_profile_id;
END;
$$;


ALTER FUNCTION "public"."fn_complete_onboarding"("p_handle" "text", "p_display_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_complete_scratchpad_run"("p_run_id" "uuid", "p_output" "text", "p_status" "text" DEFAULT 'completed'::"text", "p_cost_credits" integer DEFAULT 0, "p_error" "text" DEFAULT NULL::"text") RETURNS "agents"."scratchpad_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_existing agents.scratchpad_runs;
  v_row      agents.scratchpad_runs;
BEGIN
  SELECT * INTO v_existing FROM agents.scratchpad_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'scratchpad run not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_existing.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;
  IF p_status NOT IN ('running', 'completed', 'failed', 'cancelled') THEN
    RAISE EXCEPTION 'invalid status' USING ERRCODE = '22023';
  END IF;

  UPDATE agents.scratchpad_runs
  SET output       = p_output,
      status       = p_status,
      cost_credits = COALESCE(p_cost_credits, 0),
      error        = p_error,
      completed_at = CASE
                       WHEN p_status IN ('completed', 'failed', 'cancelled') THEN now()
                       ELSE completed_at
                     END
  WHERE id = p_run_id
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."fn_complete_scratchpad_run"("p_run_id" "uuid", "p_output" "text", "p_status" "text", "p_cost_credits" integer, "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_complete_tool_invocation"("p_invocation_id" "uuid", "p_status" "text", "p_output" "jsonb" DEFAULT NULL::"jsonb", "p_error" "text" DEFAULT NULL::"text", "p_cost" numeric DEFAULT NULL::numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_inv agents.tool_invocations;
BEGIN
  SELECT * INTO v_inv FROM agents.tool_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'invocation not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_inv.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;
  IF p_status NOT IN ('completed','failed') THEN
    RAISE EXCEPTION 'completion status must be completed or failed' USING ERRCODE = '22023';
  END IF;

  UPDATE agents.tool_invocations
     SET status        = p_status,
         output        = COALESCE(p_output, output),
         error         = COALESCE(p_error, error),
         cost_estimate = COALESCE(p_cost, cost_estimate),
         completed_at  = now()
   WHERE id = p_invocation_id;
END;
$$;


