CREATE OR REPLACE FUNCTION "public"."fn_create_battle"("p_title" "text", "p_task_prompt" "text", "p_battle_type" "text", "p_voter_eligibility" "text" DEFAULT 'open'::"text", "p_handicap_config" "jsonb" DEFAULT '{}'::"jsonb", "p_workflow_id" "uuid" DEFAULT NULL::"uuid", "p_lens_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "task_prompt" "text", "status" "text", "total_vote_count" integer, "published_at" timestamp with time zone, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "handicap_config" "jsonb", "creator_lenser_id" "uuid", "forum_thread_id" "text", "workflow_id" "uuid", "lens_id" "uuid", "execution_starts_at" timestamp with time zone, "auto_publish" boolean, "voting_duration_hours" integer, "vote_velocity" numeric, "og_image_url" "text", "winner_contender_id" "uuid", "parent_battle_id" "uuid", "deleted_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
  v_slug      text;
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required.' USING ERRCODE = '42501';
  END IF;

  v_slug := lower(regexp_replace(p_title, '[^a-z0-9\s-]', '', 'gi'));
  v_slug := regexp_replace(v_slug, '\s+', '-', 'g');
  v_slug := regexp_replace(v_slug, '-+', '-', 'g');
  v_slug := left(v_slug, 80) || '-' || substr(md5(random()::text), 1, 6);

  RETURN QUERY
  INSERT INTO battles.battles (
    title, task_prompt, battle_type, voter_eligibility,
    handicap_config, creator_lenser_id, slug, status,
    workflow_id, lens_id
  ) VALUES (
    p_title, p_task_prompt, p_battle_type, p_voter_eligibility,
    COALESCE(p_handicap_config, '{}'::jsonb), v_lenser_id, v_slug, 'draft',
    p_workflow_id, p_lens_id
  )
  RETURNING
    id, slug, title, task_prompt, status, total_vote_count, published_at,
    voting_opens_at, voting_closes_at, battle_type, voter_eligibility, handicap_config,
    creator_lenser_id, forum_thread_id, workflow_id, lens_id,
    execution_starts_at, auto_publish, voting_duration_hours, vote_velocity, og_image_url,
    winner_contender_id, parent_battle_id, deleted_at;
END;
$$;


ALTER FUNCTION "public"."fn_create_battle"("p_title" "text", "p_task_prompt" "text", "p_battle_type" "text", "p_voter_eligibility" "text", "p_handicap_config" "jsonb", "p_workflow_id" "uuid", "p_lens_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_create_battle_config_snapshot"("p_battle_id" "uuid", "p_reason" "text" DEFAULT 'lifecycle'::"text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'extensions', 'public'
    AS $$
DECLARE
  v_actor UUID := lensers.get_auth_lenser_id();
  v_rules_json JSONB;
  v_hash TEXT;
BEGIN
  SELECT jsonb_build_object(
    'snapshot_reason', p_reason,
    'title', b.title,
    'slug', b.slug,
    'task_prompt', b.task_prompt,
    'rubric_id', b.rubric_id,
    'status', b.status,
    'battle_type', b.battle_type,
    'contender_structure', b.contender_structure,
    'judging_mode', b.judging_mode,
    'task_source', b.task_source,
    'challenge_type', b.challenge_type,
    'generated_challenge_id', b.generated_challenge_id,
    'voter_eligibility', b.voter_eligibility,
    'max_contenders', b.max_contenders,
    'handicap_config', b.handicap_config,
    'workflow_id', b.workflow_id,
    'lens_id', b.lens_id,
    'content_type', b.content_type,
    'execution_starts_at', b.execution_starts_at,
    'auto_publish', b.auto_publish,
    'voting_duration_hours', b.voting_duration_hours,
    'ai_judge_enabled', b.ai_judge_enabled,
    'ai_judge_model_key', b.ai_judge_model_key,
    'ai_judge_prompt_hash', CASE
      WHEN b.ai_judge_prompt IS NULL THEN NULL
      ELSE encode(extensions.digest(b.ai_judge_prompt, 'sha256'), 'hex')
    END,
    'published_at', b.published_at,
    'captured_at', now()
  )
  INTO v_rules_json
  FROM battles.battles b
  WHERE b.id = p_battle_id;

  IF v_rules_json IS NULL THEN
    RAISE EXCEPTION 'battle_not_found: %', p_battle_id USING ERRCODE = 'P0002';
  END IF;

  v_hash := encode(extensions.digest(v_rules_json::text, 'sha256'), 'hex');

  INSERT INTO battles.rule_snapshots (battle_id, snapshot_hash, rules_json, created_by)
  VALUES (p_battle_id, v_hash, v_rules_json, v_actor);

  PERFORM public.fn_log_artifact_lifecycle_event(
    'battle',
    p_battle_id,
    'config_snapshot_create',
    v_actor,
    jsonb_build_object('snapshot_hash', v_hash, 'reason', p_reason)
  );

  RETURN v_hash;
END;
$$;


ALTER FUNCTION "public"."fn_create_battle_config_snapshot"("p_battle_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_create_battle_series"("p_template_id" "uuid", "p_title" "text", "p_round_count" integer DEFAULT 3) RETURNS "battles"."series"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
DECLARE
  v_uid       UUID := auth.uid();
  v_template  battles.templates%ROWTYPE;
  v_series    battles.series%ROWTYPE;
  v_battle_id UUID;
  v_slug      TEXT;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501';
  END IF;
  IF p_round_count IS NULL OR p_round_count < 1 OR p_round_count > 16 THEN
    RAISE EXCEPTION 'invalid_round_count' USING ERRCODE = '22023';
  END IF;

  SELECT * INTO v_template
    FROM battles.templates
   WHERE id = p_template_id
     AND deleted_at IS NULL
     AND (is_public = true OR creator_lenser_id = v_uid);
  IF v_template IS NULL THEN
    RAISE EXCEPTION 'template_not_accessible' USING ERRCODE = '42501';
  END IF;

  INSERT INTO battles.series (title, template_id, creator_lenser_id, round_count)
  VALUES (p_title, p_template_id, v_uid, p_round_count)
  RETURNING * INTO v_series;

  v_slug := lower(regexp_replace(p_title, '[^a-zA-Z0-9]+', '-', 'g'))
            || '-r1-' || substr(v_series.id::text, 1, 8);

  v_battle_id := public.fn_battles_create_from_template(
    p_template_id, p_title || ' — Round 1', v_slug
  );

  INSERT INTO battles.series_rounds (series_id, round_number, battle_id)
  VALUES (v_series.id, 1, v_battle_id);

  RETURN v_series;
END $$;


