CREATE OR REPLACE FUNCTION "public"."fn_create_tournament"("p_title" "text", "p_format" "text" DEFAULT 'single_elimination'::"text", "p_max_contenders" integer DEFAULT 8, "p_battle_type" "text" DEFAULT 'ai_vs_ai'::"text", "p_ai_judge_enabled" boolean DEFAULT false) RETURNS "battles"."tournaments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_tournament battles.tournaments;
  v_slug       TEXT;
BEGIN
  v_slug := lower(regexp_replace(p_title, '[^a-zA-Z0-9]', '-', 'g')) || '-' || to_char(now(), 'YYYYMMDD-HH24MI');

  INSERT INTO battles.tournaments
    (title, slug, creator_lenser_id, format, status, max_contenders, battle_type, ai_judge_enabled)
  VALUES
    (p_title, v_slug, auth.uid(), p_format, 'registration', p_max_contenders, p_battle_type, p_ai_judge_enabled)
  RETURNING * INTO v_tournament;

  RETURN v_tournament;
END;
$$;


