CREATE OR REPLACE FUNCTION "public"."fn_get_agent_analytics_summary"("p_ai_lenser_id" "uuid", "p_days" integer DEFAULT 30, "p_model_key" "text" DEFAULT NULL::"text", "p_workflow_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'agents', 'lenses'
    AS $$
DECLARE
  v_cost_by_model    jsonb;
  v_cost_time_series jsonb;
  v_eval_quality     jsonb;
  v_workflow_perf    jsonb;
  v_jwt_role text := coalesce(nullif(trim(both from current_setting('request.jwt.claim.role', true)), ''), '');
BEGIN
  -- Ownership guard: human owners pass agents.can_manage_ai_lenser.
  -- Service-role JWT (platform / trusted workers) may read any agent aggregates.
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    IF v_jwt_role IS DISTINCT FROM 'service_role' THEN
      RAISE EXCEPTION 'Insufficient privilege'
        USING ERRCODE = '42501';
    END IF;
  END IF;

  SELECT jsonb_agg(row_to_json(t)) INTO v_cost_by_model
  FROM (
    SELECT
      model_key,
      provider,
      SUM(total_credits)    AS total_credits,
      SUM(total_tokens_in)  AS total_tokens_in,
      SUM(total_tokens_out) AS total_tokens_out,
      SUM(run_count)        AS run_count
    FROM analytics.agent_cost_daily
    WHERE ai_lenser_id = p_ai_lenser_id
      AND period_date  >= CURRENT_DATE - p_days
      AND (p_model_key IS NULL OR model_key = p_model_key)
    GROUP BY model_key, provider
    ORDER BY SUM(total_credits) DESC
  ) t;

  SELECT jsonb_agg(row_to_json(t)) INTO v_cost_time_series
  FROM (
    SELECT
      period_date,
      SUM(total_credits) AS total_credits
    FROM analytics.agent_cost_daily
    WHERE ai_lenser_id = p_ai_lenser_id
      AND period_date  >= CURRENT_DATE - p_days
      AND (p_model_key IS NULL OR model_key = p_model_key)
    GROUP BY period_date
    ORDER BY period_date
  ) t;

  SELECT jsonb_agg(row_to_json(t)) INTO v_eval_quality
  FROM (
    SELECT
      eqd.period_date,
      e.name                                            AS evaluation_name,
      eqd.pass_count::float / NULLIF(eqd.run_count, 0) AS pass_rate,
      eqd.mean_score
    FROM analytics.eval_quality_daily eqd
    JOIN agents.evaluations e ON e.id = eqd.evaluation_id
    WHERE eqd.ai_lenser_id = p_ai_lenser_id
      AND eqd.period_date  >= CURRENT_DATE - p_days
    ORDER BY eqd.period_date
  ) t;

  SELECT jsonb_agg(row_to_json(t)) INTO v_workflow_perf
  FROM (
    SELECT
      wpd.period_date,
      wf.title                                              AS workflow_title,
      wpd.p50_duration_ms,
      wpd.p95_duration_ms,
      wpd.failed_count::float / NULLIF(wpd.run_count, 0)   AS failure_rate
    FROM analytics.workflow_perf_daily wpd
    JOIN lenses.workflows wf ON wf.id = wpd.workflow_id
    WHERE wpd.ai_lenser_id = p_ai_lenser_id
      AND wpd.period_date  >= CURRENT_DATE - p_days
      AND (p_workflow_id IS NULL OR wpd.workflow_id = p_workflow_id)
    ORDER BY wpd.period_date
  ) t;

  RETURN jsonb_build_object(
    'cost_by_model',    COALESCE(v_cost_by_model,    '[]'::jsonb),
    'cost_time_series', COALESCE(v_cost_time_series, '[]'::jsonb),
    'eval_quality',     COALESCE(v_eval_quality,     '[]'::jsonb),
    'workflow_perf',    COALESCE(v_workflow_perf,    '[]'::jsonb)
  );
END;
$$;


ALTER FUNCTION "public"."fn_get_agent_analytics_summary"("p_ai_lenser_id" "uuid", "p_days" integer, "p_model_key" "text", "p_workflow_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_agent_analytics_summary"("p_ai_lenser_id" "uuid", "p_days" integer, "p_model_key" "text", "p_workflow_id" "uuid") IS 'Owner-only analytics summary for an AI lenser (human owners via agents.can_manage_ai_lenser). Callers with request.jwt.claim.role = service_role may read aggregates for any agent (platform / trusted workers). Returns cost_by_model, cost_time_series, eval_quality, and workflow_perf aggregated over the last p_days days. Optional p_model_key and p_workflow_id narrow cost and workflow results. Reads only from analytics.* pre-aggregated tables; never touches raw logs.';



CREATE OR REPLACE FUNCTION "public"."fn_get_agent_automation_feed"("p_ai_lenser_id" "uuid", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("kind" "text", "id" "text", "occurred_at" timestamp with time zone, "title" "text", "result" "text", "workflow_id" "uuid", "workflow_title" "text", "run_id" "uuid", "schedule_id" "uuid", "action_type" "text", "event_type" "text", "payload" "jsonb")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lenses', 'lensers'
    AS $$
  WITH authorized_agent AS (
    SELECT al.id AS ai_lenser_id, al.profile_id
    FROM agents.ai_lensers al
    JOIN agents.ownerships o ON o.ai_lenser_id = al.id
    WHERE al.id = p_ai_lenser_id
      AND o.owner_lenser_id = lensers.get_auth_human_lenser_id()
      AND o.revoked_at IS NULL
    LIMIT 1
  ),
  action_items AS (
    SELECT
      CASE
        WHEN l.action_type IN ('dispatch_schedule', 'schedule_skipped') THEN 'schedule_dispatch'
        ELSE 'agent_action'
      END AS kind,
      l.id::text AS id,
      l.occurred_at,
      COALESCE(l.action_type, 'agent_action') AS title,
      l.result,
      CASE WHEN l.metadata ? 'workflow_id' THEN (l.metadata ->> 'workflow_id')::uuid END AS workflow_id,
      NULL::text AS workflow_title,
      CASE WHEN l.metadata ? 'run_id' THEN (l.metadata ->> 'run_id')::uuid END AS run_id,
      CASE WHEN l.metadata ? 'schedule_id' THEN (l.metadata ->> 'schedule_id')::uuid END AS schedule_id,
      l.action_type,
      NULL::text AS event_type,
      l.metadata AS payload
    FROM agents.action_logs l
    JOIN authorized_agent aa ON aa.ai_lenser_id = l.ai_lenser_id
  ),
  run_items AS (
    SELECT
      'workflow_run'::text AS kind,
      r.id::text AS id,
      COALESCE(r.completed_at, r.started_at, r.created_at) AS occurred_at,
      r.status AS title,
      r.status AS result,
      w.id AS workflow_id,
      w.title AS workflow_title,
      r.id AS run_id,
      r.schedule_id,
      NULL::text AS action_type,
      NULL::text AS event_type,
      jsonb_build_object(
        'status', r.status,
        'trigger_mode', r.trigger_mode,
        'spent_credits', r.spent_credits
      ) AS payload
    FROM authorized_agent aa
    JOIN lenses.workflows w ON w.lenser_id = aa.profile_id
    JOIN lenses.workflow_runs r ON r.workflow_id = w.id
  ),
  event_items AS (
    SELECT
      'workflow_event'::text AS kind,
      concat(e.run_id::text, ':', e.event_id::text) AS id,
      e.created_at AS occurred_at,
      e.type AS title,
      NULL::text AS result,
      w.id AS workflow_id,
      w.title AS workflow_title,
      e.run_id AS run_id,
      r.schedule_id,
      NULL::text AS action_type,
      e.type AS event_type,
      COALESCE(e.payload, '{}'::jsonb) AS payload
    FROM authorized_agent aa
    JOIN lenses.workflows w ON w.lenser_id = aa.profile_id
    JOIN lenses.workflow_runs r ON r.workflow_id = w.id
    JOIN lenses.workflow_run_events e ON e.run_id = r.id
  )
  SELECT *
  FROM (
    SELECT * FROM action_items
    UNION ALL
    SELECT * FROM run_items
    UNION ALL
    SELECT * FROM event_items
  ) feed
  ORDER BY occurred_at DESC, id DESC
  LIMIT LEAST(GREATEST(COALESCE(p_limit, 100), 1), 250)
  OFFSET GREATEST(COALESCE(p_offset, 0), 0);
$$;


ALTER FUNCTION "public"."fn_get_agent_automation_feed"("p_ai_lenser_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_agent_automation_feed"("p_ai_lenser_id" "uuid", "p_limit" integer, "p_offset" integer) IS 'Owner-only unified automation feed for AI workspace panels. Unions agents.action_logs with workflow_runs and workflow_run_events for workflows owned by the AI lenser profile.';



CREATE OR REPLACE FUNCTION "public"."fn_get_agent_cost_summary"("p_ai_lenser_id" "uuid") RETURNS TABLE("period_date" "date", "credits_spent" integer, "battles_used" integer, "votes_used" integer, "spending_limit" integer)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
  SELECT qs.period_date, qs.credits_spent, qs.battles_used, qs.votes_used,
         pol.spending_limit_credits
  FROM agents.quota_snapshots qs
  LEFT JOIN agents.policies pol ON pol.ai_lenser_id = qs.ai_lenser_id
  WHERE qs.ai_lenser_id = p_ai_lenser_id
    AND (
      EXISTS (
        SELECT 1 FROM agents.ownerships o
        WHERE o.ai_lenser_id = p_ai_lenser_id
          AND o.owner_lenser_id = lensers.get_auth_human_lenser_id()
          AND o.revoked_at IS NULL
      ) OR public.is_admin()
    )
  ORDER BY qs.period_date DESC
  LIMIT 30;
$$;


