CREATE TABLE IF NOT EXISTS "battles"."battles" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "creator_lenser_id" "uuid" DEFAULT "lensers"."get_auth_lenser_id"() NOT NULL,
    "title" "text" NOT NULL,
    "slug" "text" NOT NULL,
    "task_prompt" "text" NOT NULL,
    "rubric_id" "uuid",
    "status" "battles"."battle_status_enum" DEFAULT 'draft'::"battles"."battle_status_enum" NOT NULL,
    "invite_code" "text",
    "forum_thread_id" "uuid",
    "max_contenders" integer DEFAULT 2 NOT NULL,
    "voting_opens_at" timestamp with time zone,
    "voting_closes_at" timestamp with time zone,
    "published_at" timestamp with time zone,
    "finalized_at" timestamp with time zone,
    "winner_contender_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "total_vote_count" integer DEFAULT 0 NOT NULL,
    "battle_type" "battles"."battle_type_enum" DEFAULT 'human_vs_human_open_votes'::"battles"."battle_type_enum" NOT NULL,
    "voter_eligibility" "battles"."voter_eligibility_enum" DEFAULT 'open'::"battles"."voter_eligibility_enum" NOT NULL,
    "handicap_config" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "workflow_id" "uuid",
    "lens_id" "uuid",
    "content_type" "text" DEFAULT 'text'::"text" NOT NULL,
    "execution_starts_at" timestamp with time zone,
    "executing_started_at" timestamp with time zone,
    "auto_publish" boolean DEFAULT true NOT NULL,
    "voting_duration_hours" integer DEFAULT 24 NOT NULL,
    "vote_velocity" numeric(8,4) DEFAULT 0 NOT NULL,
    "og_image_url" "text",
    "ai_judge_enabled" boolean DEFAULT false,
    "ai_judge_model_key" "text" DEFAULT 'claude-sonnet-4-6'::"text",
    "ai_judge_prompt" "text",
    "parent_battle_id" "uuid",
    "template_id" "uuid",
    "auto_assign_contenders" boolean DEFAULT false NOT NULL,
    "auto_promote" boolean DEFAULT false NOT NULL,
    "shared_input_snapshot" "jsonb",
    "lenser_battle_policy" "jsonb",
    "contender_structure" "battles"."contender_structure_enum",
    "judging_mode" "battles"."judging_mode_enum",
    "task_source" "text",
    "challenge_type" "text",
    "generated_challenge_id" "uuid",
    "archived_at" timestamp with time zone,
    "benchmark_config" "jsonb",
    "normalized_score" numeric(5,4) DEFAULT NULL::numeric,
    CONSTRAINT "battles_content_type_check" CHECK (("content_type" = ANY (ARRAY['text'::"text", 'code'::"text", 'poem'::"text", 'drawing'::"text", 'image'::"text", 'video'::"text", 'audio'::"text", 'workflow'::"text", 'map'::"text", 'avatar'::"text", 'image_edit'::"text", 'kaggle'::"text"]))),
    CONSTRAINT "battles_max_contenders_min" CHECK (("max_contenders" >= 2)),
    CONSTRAINT "battles_normalized_score_range" CHECK ((("normalized_score" IS NULL) OR (("normalized_score" >= (0)::numeric) AND ("normalized_score" <= (1)::numeric)))),
    CONSTRAINT "battles_voting_window_order" CHECK ((("voting_opens_at" IS NULL) OR ("voting_closes_at" IS NULL) OR ("voting_opens_at" < "voting_closes_at"))),
    CONSTRAINT "chk_challenge_type_values" CHECK ((("challenge_type" IS NULL) OR ("challenge_type" = ANY (ARRAY['writing_contest'::"text", 'math_calculation'::"text", 'grammar_quiz'::"text", 'hand_drawing'::"text", 'fill_in_blanks'::"text", 'first_code_error'::"text", 'logic_puzzle'::"text", 'prompt_duel'::"text", 'debate'::"text", 'code_completion_benchmark'::"text", 'instruction_following_benchmark'::"text", 'reasoning_benchmark'::"text"])))),
    CONSTRAINT "chk_lenser_battle_policy_format" CHECK ((("lenser_battle_policy" IS NULL) OR ((("lenser_battle_policy" ->> 'memory_mode'::"text") = ANY (ARRAY['clean_room'::"text", 'personality'::"text", 'unrestricted'::"text"])) AND (("lenser_battle_policy" ->> 'instruction_disclosure'::"text") = ANY (ARRAY['hidden'::"text", 'visible_after_close'::"text", 'always_visible'::"text"]))))),
    CONSTRAINT "chk_task_source_battle_type_compat" CHECK ((("task_source" IS NULL) OR ("task_source" = 'challenge'::"text") OR (("task_source" = ANY (ARRAY['lens'::"text", 'workflow'::"text"])) AND ("battle_type" = ANY (ARRAY['ai_vs_ai'::"battles"."battle_type_enum", 'workflow_battle'::"battles"."battle_type_enum", 'lenser_battle'::"battles"."battle_type_enum"]))))),
    CONSTRAINT "chk_task_source_values" CHECK ((("task_source" IS NULL) OR ("task_source" = ANY (ARRAY['lens'::"text", 'workflow'::"text", 'challenge'::"text"])))),
    CONSTRAINT "ck_battles_battles_ai_judge_prompt_len" CHECK ((("ai_judge_prompt" IS NULL) OR ("length"("ai_judge_prompt") <= 8000))),
    CONSTRAINT "ck_battles_battles_invite_code_len" CHECK ((("invite_code" IS NULL) OR ("length"("invite_code") <= 32))),
    CONSTRAINT "ck_battles_battles_task_prompt_len" CHECK ((("task_prompt" IS NULL) OR ("length"("task_prompt") <= 32000))),
    CONSTRAINT "ck_battles_battles_title_len" CHECK ((("title" IS NULL) OR ("length"("title") <= 200))),
    CONSTRAINT "ck_battles_battles_total_vote_count_nonneg" CHECK ((("total_vote_count" IS NULL) OR ("total_vote_count" >= 0)))
);


ALTER TABLE "battles"."battles" OWNER TO "postgres";


COMMENT ON COLUMN "battles"."battles"."battle_type" IS 'Determines who the contenders are: ai_vs_ai, human_vs_human_ai_votes, human_vs_human_open_votes, human_vs_ai.';



COMMENT ON COLUMN "battles"."battles"."voter_eligibility" IS 'Who is allowed to cast votes: open (everyone), human_only, ai_only, verified_lenser.';



COMMENT ON COLUMN "battles"."battles"."handicap_config" IS 'JSONB snapshot of the active ai_handicap_policies row for read-only audit. Authoritative config lives in battles.ai_handicap_policies.';



COMMENT ON COLUMN "battles"."battles"."parent_battle_id" IS 'Phase V1: when this battle was created as a rematch of another battle, this points to the parent. NULL for organic battles. ON DELETE SET NULL preserves rematch history when an upstream parent is hard-deleted.';



COMMENT ON COLUMN "battles"."battles"."template_id" IS 'Phase BF: NULL for ad-hoc battles, populated when created via fn_battles_create_from_template. Used by trg_notify_template_battle_status.';



COMMENT ON COLUMN "battles"."battles"."auto_assign_contenders" IS 'CB: When true, fn_battles_auto_schedule_contenders assigns AI lensers up to max_contenders.';



COMMENT ON COLUMN "battles"."battles"."auto_promote" IS 'CB: When true, fn_battles_auto_promote transitions draft→open when readiness check passes.';



COMMENT ON COLUMN "battles"."battles"."shared_input_snapshot" IS 'Immutable snapshot of shared Lens [[parameter]] values resolved at battle creation time. All contenders receive these identical inputs.';



COMMENT ON COLUMN "battles"."battles"."lenser_battle_policy" IS 'Memory mode, instruction disclosure, and model binding override rules for Lenser Battles. NULL for non-Lenser Battle formats.';



COMMENT ON COLUMN "battles"."battles"."contender_structure" IS 'V2 axis: who competes — ai_vs_ai, human_vs_ai, or human_vs_human. For lens/workflow task sources this is always ai_vs_ai (enforced by chk_task_source_battle_type_compat).';



COMMENT ON COLUMN "battles"."battles"."judging_mode" IS 'V2 axis: how the winner is decided — community_vote, ai_judge, rubric_score, or auto_score.';



COMMENT ON COLUMN "battles"."battles"."task_source" IS 'V2 axis: the execution contract that defines the battle — lens, workflow, or challenge. Lens and workflow task sources are AI-only; human contenders are only valid for challenge.';



COMMENT ON COLUMN "battles"."battles"."challenge_type" IS 'V2: challenge game type ID for human contests (e.g. writing_contest, math_calculation).';



COMMENT ON COLUMN "battles"."battles"."generated_challenge_id" IS 'V2: reference to the locked AI-generated challenge for human contest battles.';



COMMENT ON COLUMN "battles"."battles"."benchmark_config" IS 'Benchmark game metadata. NULL = non-benchmark battle. Shape: { game_key, export_eligible, anonymization_policy, required_capabilities[], dataset_schema_version }.';



COMMENT ON COLUMN "battles"."battles"."normalized_score" IS 'Normalized winner score 0.0–1.0 for benchmark dataset comparison. NULL for non-benchmark battles. Populated after finalization.';



CREATE TABLE IF NOT EXISTS "battles"."contender_entity_map" (
    "contender_id" "uuid" NOT NULL,
    "profile_id" "uuid",
    "ai_lenser_id" "uuid",
    "group_id" "uuid",
    "redacted_agent_snapshot" "jsonb",
    "redacted_agent_snapshot_hash" "text",
    CONSTRAINT "exactly_one_entity_ref" CHECK (((((("profile_id" IS NOT NULL))::integer + (("ai_lenser_id" IS NOT NULL))::integer) + (("group_id" IS NOT NULL))::integer) = 1))
);


ALTER TABLE "battles"."contender_entity_map" OWNER TO "postgres";


COMMENT ON TABLE "battles"."contender_entity_map" IS 'CANONICAL typed identity resolution for battle contenders. battles.contenders.contender_ref_id is a deprecated compatibility alias. CHECK constraint enforces exactly one FK: profile, ai_lenser, or group. Auto-populated by trg_populate_contender_entity_map on contenders INSERT.';



CREATE TABLE IF NOT EXISTS "battles"."contenders" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "slot" character(1) NOT NULL,
    "contender_type" "battles"."contender_type_enum" NOT NULL,
    "contender_ref_id" "uuid" NOT NULL,
    "display_name" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "team_id" "uuid",
    "entry_mode" "text" DEFAULT 'direct'::"text" NOT NULL,
    "contender_status" "text" DEFAULT 'active'::"text" NOT NULL,
    "joined_at" timestamp with time zone DEFAULT "now"(),
    "accepted_at" timestamp with time zone,
    "withdrawn_at" timestamp with time zone,
    CONSTRAINT "contenders_entry_mode_check" CHECK (("entry_mode" = ANY (ARRAY['direct'::"text", 'invited'::"text", 'qualified'::"text", 'wildcard'::"text", 'auto_join'::"text"]))),
    CONSTRAINT "contenders_slot_letter" CHECK ((("slot" >= 'A'::"bpchar") AND ("slot" <= 'Z'::"bpchar"))),
    CONSTRAINT "contenders_status_check" CHECK (("contender_status" = ANY (ARRAY['pending'::"text", 'accepted'::"text", 'active'::"text", 'withdrawn'::"text", 'disqualified'::"text", 'eliminated'::"text"])))
);


ALTER TABLE "battles"."contenders" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."rule_snapshots" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "snapshot_hash" "text" NOT NULL,
    "rules_json" "jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid"
);


ALTER TABLE "battles"."rule_snapshots" OWNER TO "postgres";


COMMENT ON TABLE "battles"."rule_snapshots" IS 'Append-only snapshot of battle rules at publication. Frozen by public.fn_publish_battle. snapshot_hash = SHA-256(rules_json::text). One row per publication event (re-publication creates a new row).';



COMMENT ON COLUMN "battles"."rule_snapshots"."rules_json" IS 'Frozen JSON: {title, task_prompt, battle_type, voter_eligibility, max_contenders, rubric_id, handicap_config, published_at}. Does not include mutable fields (vote counts, winner, etc.).';



CREATE TABLE IF NOT EXISTS "battles"."vote_aggregates" (
    "battle_id" "uuid" NOT NULL,
    "contender_id" "uuid" NOT NULL,
    "raw_vote_count" integer DEFAULT 0 NOT NULL,
    "weighted_vote_sum" numeric DEFAULT 0 NOT NULL,
    "draw_count" integer DEFAULT 0 NOT NULL,
    "rank_position" integer,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "ck_battles_vote_aggregates_draw_count_nonneg" CHECK ((("draw_count" IS NULL) OR ("draw_count" >= 0))),
    CONSTRAINT "ck_battles_vote_aggregates_raw_vote_count_nonneg" CHECK ((("raw_vote_count" IS NULL) OR ("raw_vote_count" >= 0))),
    CONSTRAINT "ck_battles_vote_aggregates_weighted_vote_sum_nonneg" CHECK ((("weighted_vote_sum" IS NULL) OR ("weighted_vote_sum" >= (0)::numeric)))
);


ALTER TABLE "battles"."vote_aggregates" OWNER TO "postgres";


CREATE OR REPLACE VIEW "battles"."v_battle_full" AS
 SELECT "b"."id",
    "b"."slug",
    "b"."title",
    "b"."task_prompt",
    "b"."status",
    "b"."battle_type",
    "b"."voter_eligibility",
    "b"."handicap_config",
    "b"."max_contenders",
    "b"."rubric_id",
    "b"."total_vote_count",
    "b"."published_at",
    "b"."voting_opens_at",
    "b"."voting_closes_at",
    "b"."finalized_at",
    "b"."winner_contender_id",
    "b"."creator_lenser_id",
    "b"."created_at",
    "b"."updated_at",
    "ca"."id" AS "contender_a_id",
    "ca"."display_name" AS "contender_a_name",
    "ca"."contender_type" AS "contender_a_type",
    "ca"."contender_status" AS "contender_a_status",
    "ema"."profile_id" AS "contender_a_profile_id",
    "ema"."ai_lenser_id" AS "contender_a_ai_lenser_id",
    "sa"."id" AS "submission_a_id",
    "sa"."content_text" AS "submission_a_text",
    "sa"."content_url" AS "submission_a_url",
    "sa"."status" AS "submission_a_status",
    "va"."raw_vote_count" AS "votes_a",
    "va"."weighted_vote_sum" AS "score_a",
    "va"."draw_count" AS "draw_count_a",
    "cb"."id" AS "contender_b_id",
    "cb"."display_name" AS "contender_b_name",
    "cb"."contender_type" AS "contender_b_type",
    "cb"."contender_status" AS "contender_b_status",
    "emb"."profile_id" AS "contender_b_profile_id",
    "emb"."ai_lenser_id" AS "contender_b_ai_lenser_id",
    "sb"."id" AS "submission_b_id",
    "sb"."content_text" AS "submission_b_text",
    "sb"."content_url" AS "submission_b_url",
    "sb"."status" AS "submission_b_status",
    "vb"."raw_vote_count" AS "votes_b",
    "vb"."weighted_vote_sum" AS "score_b",
        CASE
            WHEN ("b"."winner_contender_id" = "ca"."id") THEN 'A'::"text"
            WHEN ("b"."winner_contender_id" = "cb"."id") THEN 'B'::"text"
            ELSE NULL::"text"
        END AS "winner_slot",
    "rs"."snapshot_hash" AS "rule_snapshot_hash"
   FROM ((((((((("battles"."battles" "b"
     LEFT JOIN "battles"."contenders" "ca" ON ((("ca"."battle_id" = "b"."id") AND ("ca"."slot" = 'A'::"bpchar"))))
     LEFT JOIN "battles"."contender_entity_map" "ema" ON (("ema"."contender_id" = "ca"."id")))
     LEFT JOIN "battles"."submissions" "sa" ON ((("sa"."contender_id" = "ca"."id") AND ("sa"."is_final" = true) AND ("sa"."status" = 'submitted'::"battles"."submission_status_enum"))))
     LEFT JOIN "battles"."vote_aggregates" "va" ON ((("va"."battle_id" = "b"."id") AND ("va"."contender_id" = "ca"."id"))))
     LEFT JOIN "battles"."contenders" "cb" ON ((("cb"."battle_id" = "b"."id") AND ("cb"."slot" = 'B'::"bpchar"))))
     LEFT JOIN "battles"."contender_entity_map" "emb" ON (("emb"."contender_id" = "cb"."id")))
     LEFT JOIN "battles"."submissions" "sb" ON ((("sb"."contender_id" = "cb"."id") AND ("sb"."is_final" = true) AND ("sb"."status" = 'submitted'::"battles"."submission_status_enum"))))
     LEFT JOIN "battles"."vote_aggregates" "vb" ON ((("vb"."battle_id" = "b"."id") AND ("vb"."contender_id" = "cb"."id"))))
     LEFT JOIN LATERAL ( SELECT "rule_snapshots"."snapshot_hash"
           FROM "battles"."rule_snapshots"
          WHERE ("rule_snapshots"."battle_id" = "b"."id")
          ORDER BY "rule_snapshots"."created_at" DESC
         LIMIT 1) "rs" ON (true))
  WHERE ("b"."deleted_at" IS NULL);


ALTER VIEW "battles"."v_battle_full" OWNER TO "postgres";


COMMENT ON VIEW "battles"."v_battle_full" IS 'Full battle lobby state for BattleDetailPage. Used by fn_get_battle_full. Covers contenders, entity map, final submissions, vote aggregates, and rule snapshot hash in a single join. contender_entity_map is the canonical identity source for slot resolution.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle_full"("p_slug" "text") RETURNS "battles"."v_battle_full"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT *
  FROM battles.v_battle_full
  WHERE slug = p_slug
  LIMIT 1;
$$;


ALTER FUNCTION "public"."fn_get_battle_full"("p_slug" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battle_full"("p_slug" "text") IS 'Returns full battle state for BattleDetailPage by slug. Single roundtrip covers contenders, submissions, vote aggregates, entity map, and rule snapshot hash via v_battle_full view.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle_public_execution_jobs"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "slot" "text", "status" "text", "claimed_at" timestamp with time zone, "completed_at" timestamp with time zone, "retry_count" integer, "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles'
    AS $$
  SELECT id, battle_id, slot, status, claimed_at, completed_at, retry_count, created_at
  FROM battles.v_execution_jobs_public
  WHERE battle_id = p_battle_id
  ORDER BY slot;
$$;


ALTER FUNCTION "public"."fn_get_battle_public_execution_jobs"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_results"("p_battle_slug" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_battle        battles.battles;
  v_battle_id     UUID;
  v_contenders    JSONB;
  v_submissions   JSONB;
  v_aggregates    JSONB;
  v_scorecards    JSONB;
  v_criteria      JSONB;
  v_verdicts      JSONB;
BEGIN
  -- Fetch battle and enforce status guard
  SELECT * INTO v_battle
  FROM battles.battles
  WHERE slug = p_battle_slug
    AND status IN ('published', 'closed');

  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  v_battle_id := v_battle.id;

  SELECT COALESCE(jsonb_agg(row_to_json(c)), '[]')
  INTO v_contenders
  FROM (
    SELECT id, battle_id, slot, contender_type, display_name, lenser_id,
           contender_ref_id, status, invited_at, joined_at
    FROM battles.contenders
    WHERE battle_id = v_battle_id
    ORDER BY slot
  ) c;

  SELECT COALESCE(jsonb_agg(row_to_json(s)), '[]')
  INTO v_submissions
  FROM (
    SELECT id, battle_id, contender_id, content_text, content_url,
           submitted_at, word_count, char_count
    FROM battles.submissions
    WHERE battle_id = v_battle_id
  ) s;

  SELECT COALESCE(jsonb_agg(row_to_json(a)), '[]')
  INTO v_aggregates
  FROM (
    SELECT battle_id, contender_id, raw_vote_count, weighted_vote_sum,
           draw_count, rank_position
    FROM battles.vote_aggregates
    WHERE battle_id = v_battle_id
  ) a;

  SELECT COALESCE(jsonb_agg(row_to_json(sc)), '[]')
  INTO v_scorecards
  FROM (
    SELECT id, battle_id, contender_id, rubric_criterion_id, result, explanation
    FROM battles.scorecards
    WHERE battle_id = v_battle_id
  ) sc;

  SELECT COALESCE(jsonb_agg(row_to_json(cr)), '[]')
  INTO v_criteria
  FROM (
    SELECT id, title AS name, description, weight
    FROM battles.rubric_criteria
    WHERE id IN (
      SELECT rubric_criterion_id FROM battles.scorecards WHERE battle_id = v_battle_id
    )
  ) cr;

  SELECT COALESCE(jsonb_agg(row_to_json(v)), '[]')
  INTO v_verdicts
  FROM (
    SELECT id, contender_id, criterion_id, score, rationale, model_key, run_id, created_at
    FROM battles.ai_judge_verdicts
    WHERE battle_id = v_battle_id
  ) v;

  RETURN jsonb_build_object(
    'battle',       row_to_json(v_battle),
    'contenders',   v_contenders,
    'submissions',  v_submissions,
    'aggregates',   v_aggregates,
    'scorecards',   v_scorecards,
    'criteria',     v_criteria,
    'verdicts',     v_verdicts
  );
END;
$$;


ALTER FUNCTION "public"."fn_get_battle_results"("p_battle_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_scorecards"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "contender_id" "uuid", "rubric_criterion_id" "uuid", "result" "text", "explanation" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles'
    AS $$
  SELECT sc.id, sc.battle_id, sc.contender_id, sc.rubric_criterion_id,
         sc.result, sc.explanation
  FROM battles.scorecards sc
  WHERE sc.battle_id = p_battle_id;
$$;


ALTER FUNCTION "public"."fn_get_battle_scorecards"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_share_card"("p_slug" "text") RETURNS TABLE("battle_id" "uuid", "slug" "text", "title" "text", "status" "text", "total_vote_count" integer, "finalized_at" timestamp with time zone, "winner_contender_id" "uuid", "deleted_at" timestamp with time zone, "contender_a_id" "uuid", "contender_a_name" "text", "contender_b_id" "uuid", "contender_b_name" "text", "elo_winner_before" numeric, "elo_winner_after" numeric, "elo_loser_before" numeric, "elo_loser_after" numeric, "elo_is_draw" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'reputation'
    AS $$
DECLARE
  v_battle_id uuid;
  v_status    text;
  v_deleted   timestamptz;
BEGIN
  SELECT b.id, b.status, b.deleted_at
  INTO v_battle_id, v_status, v_deleted
  FROM battles.battles b
  WHERE b.slug = p_slug
  LIMIT 1;

  IF NOT FOUND OR v_deleted IS NOT NULL OR v_status = 'draft' THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    b.id, b.slug, b.title, b.status, b.total_vote_count, b.finalized_at,
    b.winner_contender_id, b.deleted_at,
    a_c.id, a_c.display_name,
    b_c.id, b_c.display_name,
    el.winner_score_before, el.winner_score_after,
    el.loser_score_before, el.loser_score_after,
    el.is_draw
  FROM battles.battles b
  LEFT JOIN battles.contenders a_c ON a_c.battle_id = b.id AND a_c.slot = 'A'
  LEFT JOIN battles.contenders b_c ON b_c.battle_id = b.id AND b_c.slot = 'B'
  LEFT JOIN reputation.elo_battle_log el ON el.battle_id = b.id
  WHERE b.id = v_battle_id
  LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."fn_get_battle_share_card"("p_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_submissions"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "contender_id" "uuid", "content_text" "text", "content_url" "text", "status" "text", "submitted_at" timestamp with time zone, "execution_run_id" "uuid", "is_final" boolean, "media_url" "text", "mime_type" "text", "output_modality" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles'
    AS $$
  SELECT s.id, s.battle_id, s.contender_id, s.content_text, s.content_url,
         s.status::text, s.submitted_at, s.execution_run_id, s.is_final,
         s.media_url, s.mime_type, s.output_modality
  FROM battles.submissions s
  JOIN battles.battles b ON b.id = s.battle_id
  WHERE s.battle_id = p_battle_id
    AND b.deleted_at IS NULL
    AND (
      b.status::text = 'published'   -- anon: only published results are public
      OR auth.uid() IS NOT NULL      -- authenticated: any non-deleted battle is accessible
    );
$$;


ALTER FUNCTION "public"."fn_get_battle_submissions"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battles_feed"("p_status" "text" DEFAULT NULL::"text", "p_battle_type" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20, "p_cursor" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "status" "text", "published_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "total_vote_count" integer, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "contender_a_id" "uuid", "contender_a_name" "text", "contender_a_type" "text", "contender_b_id" "uuid", "contender_b_name" "text", "contender_b_type" "text", "winner_slot" "text", "content_type" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT
    v.id,
    v.slug,
    v.title,
    v.status::text,
    v.published_at,
    v.battle_type::text,
    v.voter_eligibility::text,
    v.total_vote_count,
    v.voting_opens_at,
    v.voting_closes_at,
    v.contender_a_id,
    v.contender_a_name,
    v.contender_a_type::text,
    v.contender_b_id,
    v.contender_b_name,
    v.contender_b_type::text,
    v.winner_slot,
    v.content_type
  FROM battles.v_battle_feed_item v
  WHERE
    -- Defence-in-depth: always exclude draft/open regardless of p_status parameter
    v.status::text IN ('voting', 'scoring', 'closed', 'published', 'archived')
    AND (p_status      IS NULL OR v.status::text      = p_status)
    AND (p_battle_type IS NULL OR v.battle_type::text = p_battle_type)
    AND (p_cursor      IS NULL OR v.published_at      < p_cursor)
  ORDER BY v.published_at DESC NULLS LAST
  LIMIT LEAST(COALESCE(p_limit, 20), 100);
$$;


ALTER FUNCTION "public"."fn_get_battles_feed"("p_status" "text", "p_battle_type" "text", "p_limit" integer, "p_cursor" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battles_feed"("p_status" "text", "p_battle_type" "text", "p_limit" integer, "p_cursor" timestamp with time zone) IS 'Paginated battle feed. Filters by status and battle_type (both optional text). Always excludes draft/open battles. Keyset pagination via p_cursor (published_at of last item). LIMIT capped at 100. Returns content_type for client-side category badges. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_get_contender_rating"("p_lenser_id" "uuid", "p_category" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "category" "text", "elo_rating" numeric, "uncertainty" numeric, "battles_played" integer, "wins" integer, "draws" integer, "losses" integer, "updated_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'reputation'
    AS $$
  SELECT cr.id, cr.lenser_id, cr.category, cr.elo_rating, cr.uncertainty,
         cr.battles_played, cr.wins, cr.draws, cr.losses, cr.updated_at
  FROM reputation.contender_ratings cr
  WHERE cr.lenser_id = p_lenser_id
    AND (p_category IS NULL OR cr.category = p_category)
  ORDER BY cr.updated_at DESC
  LIMIT 1;
$$;


ALTER FUNCTION "public"."fn_get_contender_rating"("p_lenser_id" "uuid", "p_category" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_contender_rating"("p_lenser_id" "uuid", "p_category" "text") IS 'Security wrapper: fetch the most recent ELO contender rating for a lenser, optionally filtered to a specific category.';



CREATE OR REPLACE FUNCTION "public"."fn_get_contender_ratings"("p_lenser_id" "uuid", "p_limit" integer DEFAULT 20) RETURNS SETOF "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'reputation'
    AS $$
  SELECT to_jsonb(r.*)
  FROM public.fn_get_contender_rating(p_lenser_id) r
  LIMIT LEAST(GREATEST(p_limit, 1), 100);
$$;


ALTER FUNCTION "public"."fn_get_contender_ratings"("p_lenser_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_creator_timeseries"("p_lenser_id" "uuid", "p_days" integer DEFAULT 30) RETURNS TABLE("day" "date", "battles" bigint, "wins" bigint, "votes_received" bigint, "xp_earned" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'xp', 'public'
    AS $$
  WITH date_series AS (
    SELECT generate_series(
      CURRENT_DATE - (p_days - 1) * INTERVAL '1 day',
      CURRENT_DATE,
      INTERVAL '1 day'
    )::date AS day
  ),
  battle_stats AS (
    SELECT
      b.published_at::date       AS day,
      COUNT(*)                   AS battles,
      COUNT(*) FILTER (
        WHERE b.winner_contender_id = c.id
      )                          AS wins
    FROM battles.contenders c
    JOIN battles.battles b ON b.id = c.battle_id
    WHERE c.contender_ref_id = p_lenser_id
      AND b.status IN ('closed', 'published')
      AND b.published_at >= CURRENT_DATE - p_days * INTERVAL '1 day'
    GROUP BY 1
  ),
  vote_stats AS (
    SELECT
      v.created_at::date AS day,
      COUNT(*)           AS votes_received
    FROM battles.votes v
    JOIN battles.contenders c ON c.id = v.voted_contender_id
    WHERE c.contender_ref_id = p_lenser_id
      AND v.created_at >= CURRENT_DATE - p_days * INTERVAL '1 day'
    GROUP BY 1
  ),
  xp_stats AS (
    SELECT
      x.created_at::date AS day,
      COALESCE(SUM(x.xp), 0) AS xp_earned
    FROM xp.events x
    WHERE x.lenser_id = p_lenser_id
      AND x.created_at >= CURRENT_DATE - p_days * INTERVAL '1 day'
    GROUP BY 1
  )
  SELECT
    ds.day,
    COALESCE(bs.battles, 0)        AS battles,
    COALESCE(bs.wins, 0)           AS wins,
    COALESCE(vs.votes_received, 0) AS votes_received,
    COALESCE(xs.xp_earned, 0)      AS xp_earned
  FROM date_series ds
  LEFT JOIN battle_stats bs ON bs.day = ds.day
  LEFT JOIN vote_stats    vs ON vs.day = ds.day
  LEFT JOIN xp_stats      xs ON xs.day = ds.day
  ORDER BY ds.day ASC
$$;


ALTER FUNCTION "public"."fn_get_creator_timeseries"("p_lenser_id" "uuid", "p_days" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_creator_timeseries"("p_lenser_id" "uuid", "p_days" integer) IS 'Returns a daily timeseries of battles, wins, votes received, and XP earned for a given lenser over the last p_days days. SECURITY DEFINER — no RLS bypass needed.';



