CREATE TABLE IF NOT EXISTS "lensers"."profiles" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" DEFAULT "auth"."uid"(),
    "handle" "text" NOT NULL,
    "display_name" "text" NOT NULL,
    "bio" "text",
    "headline" "text",
    "avatar_url" "text",
    "banner_url" "text",
    "location" "text",
    "website_url" "text",
    "status" "lensers"."lenser_status" DEFAULT 'active'::"lensers"."lenser_status" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "visibility" "lensers"."lenser_visibility" DEFAULT 'public'::"lensers"."lenser_visibility",
    "is_in_waiting_list" boolean DEFAULT false,
    "deletion_requested_at" timestamp with time zone,
    "last_handle_changed_at" timestamp with time zone,
    "join_order" bigint,
    "last_login_at" timestamp with time zone,
    "last_active_at" timestamp with time zone,
    "login_count" integer DEFAULT 0,
    "onboarding_step" smallint DEFAULT 0 NOT NULL,
    "onboarding_completed_at" timestamp with time zone,
    "type" "lensers"."lenser_type" DEFAULT 'human'::"lensers"."lenser_type" NOT NULL,
    "ai_model_id" "uuid",
    "deletion_deadline_at" timestamp with time zone,
    "is_super_admin" boolean DEFAULT false NOT NULL,
    "journey_state" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "referral_source" "text",
    CONSTRAINT "ck_lensers_profiles_bio_len" CHECK ((("bio" IS NULL) OR ("length"("bio") <= 500))),
    CONSTRAINT "ck_lensers_profiles_display_name_len" CHECK ((("display_name" IS NULL) OR ("length"("display_name") <= 60))),
    CONSTRAINT "ck_lensers_profiles_headline_len" CHECK ((("headline" IS NULL) OR ("length"("headline") <= 120))),
    CONSTRAINT "ck_lensers_profiles_login_count_nonneg" CHECK ((("login_count" IS NULL) OR ("login_count" >= 0))),
    CONSTRAINT "lensers_handle_format_check" CHECK ((("handle" = "lower"("handle")) AND ("handle" ~ '^[a-z0-9._]+$'::"text") AND (("char_length"("handle") >= 4) AND ("char_length"("handle") <= 24)))),
    CONSTRAINT "lensers_website_url_format_check" CHECK ((("website_url" IS NULL) OR ("website_url" ~ '^https?:\/\/[A-Za-z0-9.-]+\.[A-Za-z]{2,}.*$'::"text")))
);


ALTER TABLE "lensers"."profiles" OWNER TO "postgres";


COMMENT ON COLUMN "lensers"."profiles"."onboarding_step" IS '0=not started, 1=handle/profile created, 2=preferences set (complete)';



COMMENT ON COLUMN "lensers"."profiles"."onboarding_completed_at" IS 'Timestamp when all onboarding steps were finished; NULL means incomplete.';



COMMENT ON COLUMN "lensers"."profiles"."journey_state" IS 'Per-step boolean map written by fn_journey_state_mark; keys match OnboardingStepId product journey steps.';



COMMENT ON COLUMN "lensers"."profiles"."referral_source" IS 'UTM / referral token captured at account creation from a battle invite link.';



CREATE TABLE IF NOT EXISTS "reputation"."contender_ratings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "category" "text" NOT NULL,
    "elo_rating" numeric(10,4) DEFAULT 1000 NOT NULL,
    "uncertainty" numeric(10,4) DEFAULT 350 NOT NULL,
    "battles_played" integer DEFAULT 0 NOT NULL,
    "wins" integer DEFAULT 0 NOT NULL,
    "draws" integer DEFAULT 0 NOT NULL,
    "losses" integer DEFAULT 0 NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "sigma" numeric(10,6) DEFAULT 0.06 NOT NULL,
    "tau" numeric(10,6) DEFAULT 0.0833 NOT NULL,
    "beta" numeric(10,6) DEFAULT 4.1667 NOT NULL,
    CONSTRAINT "ck_reputation_contender_ratings_elo_rating_nonneg" CHECK ((("elo_rating" IS NULL) OR ("elo_rating" >= (0)::numeric))),
    CONSTRAINT "contender_ratings_draws_nonneg" CHECK (("draws" >= 0)),
    CONSTRAINT "contender_ratings_losses_nonneg" CHECK (("losses" >= 0)),
    CONSTRAINT "contender_ratings_played_nonneg" CHECK (("battles_played" >= 0)),
    CONSTRAINT "contender_ratings_wins_nonneg" CHECK (("wins" >= 0))
);


ALTER TABLE "reputation"."contender_ratings" OWNER TO "postgres";


COMMENT ON TABLE "reputation"."contender_ratings" IS 'Per-category ELO battle performance. One row per (lenser_id, category). battles_played = wins + draws + losses must hold after each update (enforced by the trigger, not a CHECK constraint). category is free text to avoid enum rigidity; standardize via app logic.';



COMMENT ON COLUMN "reputation"."contender_ratings"."sigma" IS 'Glicko-2 volatility σ (default 0.06). Updated after each battle via fn_update_elo_on_finalize.';



COMMENT ON COLUMN "reputation"."contender_ratings"."tau" IS 'TrueSkill dynamics factor (sigma/3): models skill drift over time between battles.';



COMMENT ON COLUMN "reputation"."contender_ratings"."beta" IS 'TrueSkill performance variance: models the randomness of a single game performance.';



CREATE TABLE IF NOT EXISTS "reputation"."lenser_scores" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "score_type" "text" NOT NULL,
    "score" numeric(10,4) DEFAULT 1000 NOT NULL,
    "uncertainty" numeric(10,4) DEFAULT 350 NOT NULL,
    "computed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "lenser_scores_type_check" CHECK (("score_type" = ANY (ARRAY['elo'::"text", 'trust'::"text", 'composite'::"text"])))
);


ALTER TABLE "reputation"."lenser_scores" OWNER TO "postgres";


COMMENT ON TABLE "reputation"."lenser_scores" IS 'Overall reputation score per lenser. One row per (lenser_id, score_type). Updated by service_role after battle finalization or scheduled recomputation. uncertainty is the Glicko-2 rating deviation (RD): lower = more confident.';



CREATE OR REPLACE FUNCTION "public"."fn_get_leaderboard"("p_order_by" "text" DEFAULT 'xp'::"text", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS SETOF "xp"."v_leaderboard"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'xp', 'reputation', 'lensers', 'public'
    AS $$
BEGIN
  IF p_order_by = 'elo' THEN
    RETURN QUERY
      SELECT * FROM xp.v_leaderboard
      ORDER BY elo_score DESC, total_xp DESC, lenser_id
      LIMIT  LEAST(COALESCE(p_limit, 50), 100)
      OFFSET GREATEST(COALESCE(p_offset, 0), 0);
  ELSE
    RETURN QUERY
      SELECT * FROM xp.v_leaderboard
      ORDER BY total_xp DESC, elo_score DESC, lenser_id
      LIMIT  LEAST(COALESCE(p_limit, 50), 100)
      OFFSET GREATEST(COALESCE(p_offset, 0), 0);
  END IF;
END;
$$;


