COMMENT ON FUNCTION "public"."fn_get_leaderboard"("p_order_by" "text", "p_limit" integer, "p_offset" integer) IS 'Paginated leaderboard for LeaderboardPage. p_order_by: ''xp'' (default) sorts by total_xp, ''elo'' sorts by elo_score. LIMIT capped at 100. Uses offset pagination (simple for leaderboard UX).';



