CREATE OR REPLACE VIEW "lensers"."v_lenser_profile_full" AS
 SELECT "p"."id",
    "p"."handle",
    "p"."display_name",
    "p"."bio",
    "p"."headline",
    "p"."avatar_url",
    "p"."banner_url",
    "p"."location",
    "p"."website_url",
    "p"."type",
    "p"."status",
    "p"."visibility",
    "p"."created_at",
    "p"."last_active_at",
    COALESCE("s"."thread_count", 0) AS "thread_count",
    COALESCE("s"."lens_count", 0) AS "lens_count",
    COALESCE("s"."follower_count", 0) AS "follower_count",
    COALESCE("s"."following_count", 0) AS "following_count",
    COALESCE("s"."xp", (0)::bigint) AS "xp",
    COALESCE("xt"."current_level", 1) AS "current_level",
    COALESCE("xt"."total_xp", (0)::bigint) AS "total_xp",
    "rs"."score" AS "reputation_score",
    "rs"."uncertainty" AS "reputation_uncertainty",
    COALESCE("sum"("cr"."battles_played"), (0)::bigint) AS "battles_played",
    COALESCE("sum"("cr"."wins"), (0)::bigint) AS "battles_won",
    COALESCE("sum"("cr"."draws"), (0)::bigint) AS "battles_drawn",
    COALESCE("sum"("cr"."losses"), (0)::bigint) AS "battles_lost"
   FROM (((("lensers"."profiles" "p"
     LEFT JOIN "analytics"."lenser_stats" "s" ON (("s"."lenser_id" = "p"."id")))
     LEFT JOIN "xp"."totals" "xt" ON (("xt"."lenser_id" = "p"."id")))
     LEFT JOIN "reputation"."lenser_scores" "rs" ON ((("rs"."lenser_id" = "p"."id") AND ("rs"."score_type" = 'composite'::"text"))))
     LEFT JOIN "reputation"."contender_ratings" "cr" ON (("cr"."lenser_id" = "p"."id")))
  WHERE (("p"."status" <> ALL (ARRAY['deleted'::"lensers"."lenser_status", 'suspended'::"lensers"."lenser_status"])) AND ("p"."deletion_requested_at" IS NULL))
  GROUP BY "p"."id", "p"."handle", "p"."display_name", "p"."bio", "p"."headline", "p"."avatar_url", "p"."banner_url", "p"."location", "p"."website_url", "p"."type", "p"."status", "p"."visibility", "p"."created_at", "p"."last_active_at", "s"."thread_count", "s"."lens_count", "s"."follower_count", "s"."following_count", "s"."xp", "xt"."current_level", "xt"."total_xp", "rs"."score", "rs"."uncertainty";


ALTER VIEW "lensers"."v_lenser_profile_full" OWNER TO "postgres";


COMMENT ON VIEW "lensers"."v_lenser_profile_full" IS 'Full lenser profile for LenserProfilePage. Replaces 4-5 separate queries. Excludes deleted/suspended/pending-deletion profiles. battles_played/won/drawn/lost are aggregated across all battle categories.';



