COMMENT ON FUNCTION "public"."fn_get_media_object"("p_object_id" "uuid") IS 'Security wrapper: fetch a media object row by ID. Returns the row if the caller owns it OR it is public. Callers must check lifecycle_state and visibility themselves.';



CREATE OR REPLACE FUNCTION "public"."fn_get_media_thumbnail_url"("p_media_id" "uuid", "p_width" integer DEFAULT 400) RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'media', 'public'
    AS $$
DECLARE
  v_obj    RECORD;
  v_base   TEXT;
  v_url    TEXT;
BEGIN
  SELECT media_type, bucket, object_key, external_url, lifecycle_state
    INTO v_obj
    FROM media.objects
   WHERE id = p_media_id;

  IF NOT FOUND OR v_obj.lifecycle_state = 'deleted' THEN
    RETURN NULL;
  END IF;

  -- Use external_url as-is for non-storage objects
  IF v_obj.external_url IS NOT NULL THEN
    RETURN v_obj.external_url;
  END IF;

  -- Needs a storage object_key to generate CDN URL
  IF v_obj.bucket IS NULL OR v_obj.object_key IS NULL THEN
    RETURN NULL;
  END IF;

  v_base := current_setting('app.supabase_url', TRUE);
  IF v_base IS NULL OR v_base = '' THEN
    -- Fall back: return null so callers use original URL path
    RETURN NULL;
  END IF;

  -- Image: return webp transform URL
  IF v_obj.media_type = 'image' THEN
    v_url := v_base
      || '/storage/v1/object/public/'
      || v_obj.bucket
      || '/'
      || v_obj.object_key
      || '?width=' || p_width
      || '&format=webp&quality=80';
    RETURN v_url;
  END IF;

  -- Video and audio: return original CDN URL without transforms
  v_url := v_base
    || '/storage/v1/object/public/'
    || v_obj.bucket
    || '/'
    || v_obj.object_key;

  RETURN v_url;
END;
$$;


ALTER FUNCTION "public"."fn_get_media_thumbnail_url"("p_media_id" "uuid", "p_width" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_media_thumbnail_url"("p_media_id" "uuid", "p_width" integer) IS 'CC: Returns CDN URL with ?width=<n>&format=webp&quality=80 for images; original URL for video/audio; NULL if not found or deleted.';



CREATE OR REPLACE FUNCTION "public"."fn_get_memory_entries_by_workflow"("p_workflow_id" "uuid", "p_limit" integer DEFAULT 100) RETURNS TABLE("id" "uuid", "profile_id" "uuid", "ai_lenser_id" "uuid", "team_run_id" "uuid", "scope" "text", "source" "text", "content" "text", "confidence" numeric, "is_redacted" boolean, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'agents', 'public'
    AS $$
DECLARE
  v_limit integer := LEAST(GREATEST(COALESCE(p_limit, 100), 1), 500);
BEGIN
  IF p_workflow_id IS NULL THEN
    RETURN;
  END IF;

  RETURN QUERY
    SELECT
      m.id,
      m.profile_id,
      m.ai_lenser_id,
      m.team_run_id,
      m.scope,
      m.source,
      m.content,
      m.confidence,
      m.is_redacted,
      m.created_at
    FROM agents.memories m
    JOIN agents.team_runs tr ON tr.id = m.team_run_id
    WHERE tr.workflow_id = p_workflow_id
      AND m.is_redacted = false
    ORDER BY m.created_at DESC
    LIMIT v_limit;
END;
$$;


ALTER FUNCTION "public"."fn_get_memory_entries_by_workflow"("p_workflow_id" "uuid", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_memory_entries_by_workflow"("p_workflow_id" "uuid", "p_limit" integer) IS 'Phase N3: Returns memory entries written by any team_run of the given workflow_id. Honors RLS via SECURITY INVOKER. Capped at 500 rows.';



CREATE TABLE IF NOT EXISTS "battles"."model_test_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid",
    "template_id" "uuid",
    "model_provider" "text" NOT NULL,
    "model_id" "text" NOT NULL,
    "prompt_hash" "text" NOT NULL,
    "passed" boolean NOT NULL,
    "duration_ms" integer,
    "raw_output" "jsonb",
    "violations" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "model_test_runs_duration_ms_check" CHECK ((("duration_ms" IS NULL) OR ("duration_ms" >= 0))),
    CONSTRAINT "model_test_runs_model_id_check" CHECK ((("char_length"("model_id") >= 1) AND ("char_length"("model_id") <= 128))),
    CONSTRAINT "model_test_runs_model_provider_check" CHECK ((("char_length"("model_provider") >= 1) AND ("char_length"("model_provider") <= 64))),
    CONSTRAINT "model_test_runs_prompt_hash_check" CHECK ((("char_length"("prompt_hash") >= 8) AND ("char_length"("prompt_hash") <= 128))),
    CONSTRAINT "model_test_runs_target_required" CHECK ((("battle_id" IS NOT NULL) OR ("template_id" IS NOT NULL)))
);


