CREATE OR REPLACE FUNCTION "public"."fn_get_run_provenance"("p_run_id" "uuid") RETURNS TABLE("id" "uuid", "direction" "text", "source_run_id" "uuid", "source_workflow_id" "uuid", "source_node_id" "uuid", "source_output_path" "text", "target_run_id" "uuid", "target_workflow_id" "uuid", "target_node_id" "uuid", "target_input_path" "text", "transform" "jsonb", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
  SELECT
    p.id,
    CASE WHEN p.target_run_id = p_run_id THEN 'upstream' ELSE 'downstream' END AS direction,
    p.source_run_id,
    sr.workflow_id AS source_workflow_id,
    p.source_node_id,
    p.source_output_path,
    p.target_run_id,
    tr.workflow_id AS target_workflow_id,
    p.target_node_id,
    p.target_input_path,
    p.transform,
    p.created_at
  FROM lenses.workflow_run_provenance p
  JOIN lenses.workflow_runs sr ON sr.id = p.source_run_id
  JOIN lenses.workflow_runs tr ON tr.id = p.target_run_id
  WHERE (p.source_run_id = p_run_id OR p.target_run_id = p_run_id)
    AND EXISTS (
      SELECT 1
      FROM lenses.workflow_runs r
      JOIN lenses.workflows w ON w.id = r.workflow_id
      WHERE r.id = p_run_id
        AND (
          r.triggered_by = lensers.get_auth_lenser_id()
          OR w.visibility::text = 'public'
        )
    )
  ORDER BY p.created_at ASC;
$$;


ALTER FUNCTION "public"."fn_get_run_provenance"("p_run_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_run_provenance"("p_run_id" "uuid") IS 'Returns the provenance edges where this run is either the source or the target. Drives the n8n-style "data came from / data used by" tabs in the inspector.';



