    )
  LIMIT 1;
$$;


ALTER FUNCTION "public"."fn_get_workspace_settings"("p_ai_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_grant_standing_approval"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid" DEFAULT NULL::"uuid", "p_gate_kind" "text" DEFAULT NULL::"text", "p_hours" integer DEFAULT 24) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_caller     uuid := lensers.get_auth_lenser_id();
  v_id         uuid;
  v_expires    timestamptz;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not_owner_of_ai_lenser' USING ERRCODE = '42501';
  END IF;

  IF p_workflow_id IS NULL AND (p_gate_kind IS NULL OR length(trim(p_gate_kind)) = 0) THEN
    RAISE EXCEPTION 'standing approval requires workflow_id or gate_kind' USING ERRCODE = '22023';
  END IF;

  v_expires := CASE
    WHEN p_hours IS NULL OR p_hours <= 0 THEN NULL
    ELSE now() + (p_hours::text || ' hours')::interval
  END;

  INSERT INTO agents.standing_approvals (
    ai_lenser_id, workflow_id, gate_kind, expires_at, created_by
  ) VALUES (
    p_ai_lenser_id, p_workflow_id, NULLIF(trim(p_gate_kind), ''), v_expires, v_caller
  )
  RETURNING id INTO v_id;

  INSERT INTO agents.action_logs (
    ai_lenser_id, action_type, result, metadata
  ) VALUES (
    p_ai_lenser_id,
    'standing_approval_granted',
    'success',
    jsonb_build_object(
      'standing_approval_id', v_id,
      'workflow_id',          p_workflow_id,
      'gate_kind',            NULLIF(trim(p_gate_kind), ''),
      'expires_at',            v_expires,
      'granted_by',            v_caller
    )
  );

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_grant_standing_approval"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid", "p_gate_kind" "text", "p_hours" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_grant_standing_approval"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid", "p_gate_kind" "text", "p_hours" integer) IS 'Phase Q2: grants a standing approval for an AI lenser. p_hours<=0 or NULL means no expiry. Returns the standing_approvals.id. Owner-only via agents.can_manage_ai_lenser; writes an action_logs entry.';



