CREATE OR REPLACE FUNCTION "public"."fn_journey_state_mark"("p_step" "text", "p_done" boolean DEFAULT true) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
BEGIN
  UPDATE lensers.profiles
     SET journey_state = journey_state || jsonb_build_object(p_step, p_done),
         updated_at    = NOW()
   WHERE user_id = auth.uid();

  -- Silently no-op if the profile row doesn't exist yet; the CLI handles null.
  IF NOT FOUND THEN
    NULL;
  END IF;
END;
$$;


