CREATE OR REPLACE FUNCTION "public"."fn_lensers_get_profile"("p_handle" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth', 'analytics', 'xp'
    AS $$
DECLARE
  v_viewer_uid uuid;
  v_subject RECORD;
  v_prefs lensers.preferences;
  v_access lensers.profile_access_level;
  v_viewer_profile_id uuid;
  v_rel_state jsonb;
  v_result jsonb;
  v_xp RECORD;
  v_min_xp bigint;
  v_max_xp bigint;
  v_stats RECORD;
  v_join RECORD;
  v_is_owner boolean := false;
  v_completion_score integer;
  v_activity jsonb;
BEGIN
  v_viewer_uid := auth.uid();

  -- Fetch subject profile (without visibility filter)
  SELECT p.id, p.handle, p.display_name, p.avatar_url, p.banner_url,
         p.bio, p.headline, p.status, p.visibility, p.created_at,
         p.type,
         p.user_id, p.deletion_requested_at, p.deletion_deadline_at,
         p.location, p.website_url
  INTO v_subject
  FROM lensers.profiles p
  WHERE p.handle = p_handle;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'route_state', 'UNAVAILABLE_PROFILE',
      'access_reason', 'not_found',
      'relationship_state', null,
      'profile', null
    );
  END IF;

  -- Fetch preferences row (1:1 with profile)
  SELECT * INTO v_prefs
  FROM lensers.preferences
  WHERE lenser_id = v_subject.id;

  -- Resolve access level
  v_access := lensers.fn_can_view_profile(v_viewer_uid, v_subject.id);

  -- Get viewer profile id for relationship state
  IF v_viewer_uid IS NOT NULL THEN
    SELECT p.id INTO v_viewer_profile_id
    FROM lensers.profiles p
    WHERE p.user_id = v_viewer_uid;
  END IF;

  -- Determine ownership
  v_is_owner := (v_viewer_uid IS NOT NULL AND v_viewer_uid = v_subject.user_id);

  -- Build relationship state
  IF v_viewer_profile_id IS NOT NULL AND v_viewer_profile_id <> v_subject.id THEN
    v_rel_state := lensers.fn_relationship_state(v_viewer_profile_id, v_subject.id);
  ELSE
    v_rel_state := null;
  END IF;

  -- UNAVAILABLE → minimal response
  IF v_access = 'UNAVAILABLE_PROFILE' THEN
    RETURN jsonb_build_object(
      'route_state', 'UNAVAILABLE_PROFILE',
      'access_reason', 'unavailable',
      'relationship_state', v_rel_state,
      'profile', null
    );
  END IF;

  -- Fetch XP, stats, join info for full/restricted/recovery
  SELECT t.total_xp, t.current_level, t.app_id INTO v_xp
  FROM xp.totals t WHERE t.lenser_id = v_subject.id;

  IF v_xp.app_id IS NOT NULL AND v_xp.current_level IS NOT NULL THEN
    SELECT lv.min_total_xp, lv.max_total_xp INTO v_min_xp, v_max_xp
    FROM xp.levels lv
    WHERE lv.app_id = v_xp.app_id AND lv.level = v_xp.current_level;
  END IF;

  SELECT s.thread_count, s.lens_count, s.follower_count, s.following_count, s.mutuals_count
  INTO v_stats
  FROM analytics.lenser_stats s WHERE s.lenser_id = v_subject.id;

  SELECT jl.join_order, jl.joined_at INTO v_join
  FROM analytics.lenser_join_log jl WHERE jl.lenser_id = v_subject.id;

  -- RESTRICTED → limited fields (no activity/completion)
  IF v_access = 'RESTRICTED_PROFILE' THEN
    RETURN jsonb_build_object(
      'route_state', 'RESTRICTED_PROFILE',
      'access_reason', 'private_not_following',
      'relationship_state', v_rel_state,
      'profile', jsonb_build_object(
        'id', v_subject.id,
        'handle', v_subject.handle,
        'display_name', v_subject.display_name,
        'avatar_url', v_subject.avatar_url,
        'type', v_subject.type,
        'visibility', v_subject.visibility,
        'total_xp', v_xp.total_xp,
        'current_level', v_xp.current_level,
        'follower_count', COALESCE(v_stats.follower_count, 0),
        'following_count', COALESCE(v_stats.following_count, 0),
        'join_order', v_join.join_order,
        'created_at', v_subject.created_at
      )
    );
  END IF;

  -- ── Completion score (owner only) ──────────────────────────────────────────
  IF v_is_owner THEN
    v_completion_score := 0;

    IF v_subject.bio IS NOT NULL AND length(trim(v_subject.bio)) > 0 THEN
      v_completion_score := v_completion_score + 25;
    END IF;
    IF v_subject.avatar_url IS NOT NULL AND length(trim(v_subject.avatar_url)) > 0 THEN
      v_completion_score := v_completion_score + 25;
    END IF;
    IF v_subject.location IS NOT NULL AND length(trim(v_subject.location)) > 0 THEN
      v_completion_score := v_completion_score + 15;
    END IF;
    IF v_subject.website_url IS NOT NULL AND length(trim(v_subject.website_url)) > 0 THEN
      v_completion_score := v_completion_score + 15;
    END IF;

    -- Battle participation
    IF EXISTS (
      SELECT 1 FROM battles.contenders bc
      JOIN battles.battles b ON b.id = bc.battle_id
      WHERE bc.contender_ref_id = v_subject.id
        AND b.status <> 'draft'::battles.battle_status_enum
    ) THEN
      v_completion_score := v_completion_score + 10;
    END IF;

    -- XP earned
    IF COALESCE((SELECT SUM(xp) FROM xp.events WHERE lenser_id = v_subject.id), 0) > 0 THEN
      v_completion_score := v_completion_score + 10;
    END IF;

    v_completion_score := LEAST(v_completion_score, 100);
  END IF;

  -- ── Activity timeline (365 days) ──────────────────────────────────────────
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object('date', sub.date, 'count', sub.count)
    ORDER BY sub.date
  ), '[]'::jsonb)
  INTO v_activity
  FROM (
    WITH calendar AS (
      SELECT (current_date - s.i)::date AS day
      FROM generate_series(0, 364) AS s(i)
    ),
    events AS (
      -- Lens creations
      SELECT date_trunc('day', l.created_at)::date AS day
      FROM   lenses.lenses l
      WHERE  l.lenser_id = v_subject.id
        AND  l.visibility IN ('public', 'community')
        AND  l.status = 'published'
        AND  l.created_at >= (current_date - interval '364 days')

      UNION ALL

      -- Thread creations
      SELECT date_trunc('day', t.created_at)::date AS day
      FROM   content.threads t
      WHERE  t.lenser_id = v_subject.id
        AND  t.visibility IN ('public', 'community')
        AND  t.status = 'published'
        AND  t.created_at >= (current_date - interval '364 days')

      UNION ALL

      -- Reactions (skipped when hide_actions = true)
      SELECT date_trunc('day', rx.created_at)::date AS day
      FROM   content.reactions rx
      WHERE  rx.lenser_id = v_subject.id
        AND  COALESCE(v_prefs.hide_actions, false) = false
        AND  rx.created_at >= (current_date - interval '364 days')
    ),
    daily_counts AS (
      SELECT day, count(*) AS cnt
      FROM   events
      GROUP BY day
    )
    SELECT to_char(c.day, 'YYYY-MM-DD') AS date,
           COALESCE(dc.cnt, 0)          AS count
    FROM   calendar c
    LEFT JOIN daily_counts dc ON dc.day = c.day
  ) sub;

  -- Determine access reason
  DECLARE
    v_reason text;
  BEGIN
    IF v_access = 'OWNER_RECOVERY_PROFILE' THEN
      v_reason := 'owner_recovery';
    ELSIF v_subject.visibility = 'private' THEN
      v_reason := 'private_following';
    ELSE
      v_reason := 'public';
    END IF;

    -- FULL / OWNER_RECOVERY → all fields
    v_result := jsonb_build_object(
      'route_state', v_access::text,
      'access_reason', v_reason,
      'relationship_state', v_rel_state,
      'completion_score', v_completion_score,
      'activity_timeline', v_activity,
      'profile', jsonb_build_object(
        'id', v_subject.id,
        'handle', v_subject.handle,
        'display_name', v_subject.display_name,
        'avatar_url', v_subject.avatar_url,
        'banner_url', v_subject.banner_url,
        'bio', v_subject.bio,
        'headline', v_subject.headline,
        'status', v_subject.status,
        'type', v_subject.type,
        'visibility', v_subject.visibility,
        'created_at', v_subject.created_at,
        'total_xp', v_xp.total_xp,
        'current_level', v_xp.current_level,
        'min_xp', v_min_xp,
        'max_xp', v_max_xp,
        'app_id', v_xp.app_id,
        'thread_count', COALESCE(v_stats.thread_count, 0),
        'lens_count', COALESCE(v_stats.lens_count, 0),
        'follower_count', COALESCE(v_stats.follower_count, 0),
        'following_count', COALESCE(v_stats.following_count, 0),
        'join_order', v_join.join_order,
        'joined_at', v_join.joined_at,
        'hide_actions', COALESCE(v_prefs.hide_actions, false),
        'content_visibility', COALESCE(v_prefs.content_visibility, 'public'),
        'deletion_deadline_at', v_subject.deletion_deadline_at
      )
    );

    RETURN v_result;
  END;
END;
$$;


ALTER FUNCTION "public"."fn_lensers_get_profile"("p_handle" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_lensers_get_public_profile"("p_handle" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_verdict     text;
  v_result      jsonb;
  v_route_state text;
BEGIN
  -- ── Governance gate ────────────────────────────────────────────────────────
  -- Validate the incoming handle against the identity_gov registry before
  -- touching the profile table. A 'deny' verdict returns null — same as the
  -- not-found or private-profile path — preventing namespace enumeration.
  SELECT verdict
  INTO   v_verdict
  FROM   identity_gov.fn_validate_handle(p_handle)
  LIMIT  1;

  IF v_verdict = 'deny' THEN
    RETURN null;
  END IF;

  -- ── Normal profile lookup ─────────────────────────────────────────────────
  v_result      := public.fn_lensers_get_profile(p_handle);
  v_route_state := v_result->>'route_state';

  IF v_route_state = 'FULL_PROFILE' THEN
    RETURN v_result->'profile';
  ELSE
    RETURN null;
  END IF;

EXCEPTION WHEN OTHERS THEN
  -- Fail safe: governance error or profile error returns null, not a 500.
  RETURN null;
END;
$$;


ALTER FUNCTION "public"."fn_lensers_get_public_profile"("p_handle" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_lensers_get_public_profile"("p_handle" "text") IS 'Public profile lookup with identity_gov namespace guard. Returns null for denied handles (reserved, impersonation) and for non-FULL_PROFILE route states (private, deactivated, deleted). Callers cannot distinguish denied-by-governance from not-found.';



CREATE OR REPLACE FUNCTION "public"."fn_lensers_get_suggested"("p_lenser_id" "uuid", "p_limit" integer DEFAULT 10) RETURNS TABLE("lenser_id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "total_xp" bigint, "current_level" integer, "lenser_score" double precision, "tag_overlap_score" double precision)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'lenses', 'content', 'xp'
    AS $$
WITH
  interest_tags AS (
    SELECT tag_id FROM lensers.tag_follows WHERE lenser_id = p_lenser_id
  ),
  already_following AS (
    SELECT target_profile_id AS following_id
    FROM lensers.relationships
    WHERE source_profile_id = p_lenser_id
      AND status = 'accepted'
  ),
  thread_author_tags AS (
    SELECT
      t.lenser_id,
      COUNT(DISTINCT it.tag_id)::float
        / GREATEST((SELECT COUNT(*) FROM interest_tags), 1) AS tag_score
    FROM content.threads    t
    JOIN content.tag_map    tm ON tm.entity_id = t.id AND tm.entity_type = 'thread'
    JOIN interest_tags      it ON it.tag_id = tm.tag_id
    WHERE t.visibility = 'public'::content.visibility_enum
    GROUP BY t.lenser_id
  ),
  prompt_author_tags AS (
    SELECT
      pt.lenser_id,
      COUNT(DISTINCT it.tag_id)::float
        / GREATEST((SELECT COUNT(*) FROM interest_tags), 1) AS tag_score
    FROM lenses.lenses pt
    JOIN content.tag_map  tm ON tm.entity_id = pt.id AND tm.entity_type = 'lens'
    JOIN interest_tags    it ON it.tag_id = tm.tag_id
    WHERE pt.visibility = 'public'::content.visibility_enum
    GROUP BY pt.lenser_id
  ),
  author_tag_agg AS (
    SELECT lenser_id, AVG(tag_score) AS tag_overlap_score
    FROM (
      SELECT lenser_id, tag_score FROM thread_author_tags
      UNION ALL
      SELECT lenser_id, tag_score FROM prompt_author_tags
    ) combined
    GROUP BY lenser_id
  ),
  tag_pool AS (
    SELECT
      lp.id          AS lenser_id,
      lp.handle,
      lp.display_name,
      lp.avatar_url,
      COALESCE(xt.total_xp, 0)::bigint    AS total_xp,
      COALESCE(xt.current_level, 1)        AS current_level,
      COALESCE(agg.tag_overlap_score, 0.0) AS tag_overlap_score
    FROM author_tag_agg agg
    JOIN lensers.profiles lp ON lp.id = agg.lenser_id
    LEFT JOIN (
      SELECT t.lenser_id, SUM(t.total_xp) AS total_xp, MAX(t.current_level) AS current_level
      FROM xp.totals t GROUP BY t.lenser_id
    ) xt ON xt.lenser_id = lp.id
    WHERE lp.status                = 'active'
      AND lp.visibility            = 'public'
      AND lp.onboarding_step       = 2
      AND lp.deletion_requested_at IS NULL
      AND lp.id <> p_lenser_id
      AND lp.id NOT IN (SELECT following_id FROM already_following)
  ),
  xp_pool AS (
    SELECT
      lp.id          AS lenser_id,
      lp.handle,
      lp.display_name,
      lp.avatar_url,
      COALESCE(xt.total_xp, 0)::bigint AS total_xp,
      COALESCE(xt.current_level, 1)     AS current_level,
      0.0::double precision             AS tag_overlap_score
    FROM lensers.profiles lp
    LEFT JOIN (
      SELECT t.lenser_id, SUM(t.total_xp) AS total_xp, MAX(t.current_level) AS current_level
      FROM xp.totals t GROUP BY t.lenser_id
    ) xt ON xt.lenser_id = lp.id
    WHERE lp.status                = 'active'
      AND lp.visibility            = 'public'
      AND lp.onboarding_step       = 2
      AND lp.deletion_requested_at IS NULL
      AND lp.id <> p_lenser_id
      AND lp.id NOT IN (SELECT following_id FROM already_following)
  ),
  chosen AS (
    SELECT * FROM tag_pool
    WHERE (SELECT COUNT(*) FROM tag_pool) > 0
    UNION ALL
    SELECT * FROM xp_pool
    WHERE (SELECT COUNT(*) FROM tag_pool) = 0
  ),
  top_candidates AS (
    SELECT * FROM chosen
    ORDER BY tag_overlap_score DESC, total_xp DESC
    LIMIT LEAST(p_limit, 50) * 2
  )
SELECT
  tc.lenser_id,
  tc.handle,
  tc.display_name,
  tc.avatar_url,
  tc.total_xp,
  tc.current_level,
  (
    0.7 * log(GREATEST(1.0, tc.total_xp::double precision))
    + 0.3 * log(GREATEST(1.0, COALESCE(re7.cnt, 0)::double precision))
  ) AS lenser_score,
  tc.tag_overlap_score
FROM top_candidates tc
LEFT JOIN LATERAL (
  SELECT count(*) AS cnt FROM (
    SELECT 1
    FROM content.reactions tr
    JOIN content.threads t ON t.id = tr.entity_id AND t.lenser_id = tc.lenser_id
    WHERE tr.entity_type = 'thread'
      AND tr.created_at > now() - interval '7 days'
    UNION ALL
    SELECT 1
    FROM content.reactions pr
    JOIN lenses.lenses pt ON pt.id = pr.entity_id AND pt.lenser_id = tc.lenser_id
    WHERE pr.entity_type = 'lens'
      AND pr.created_at > now() - interval '7 days'
  ) x
) re7 ON true
ORDER BY (
  0.60 * tc.tag_overlap_score
  + 0.40 * LEAST(
    (0.7 * log(GREATEST(1.0, tc.total_xp::double precision))
     + 0.3 * log(GREATEST(1.0, COALESCE(re7.cnt, 0)::double precision)))
    / 5.0, 1.0)
) DESC
LIMIT LEAST(p_limit, 50);
$$;


ALTER FUNCTION "public"."fn_lensers_get_suggested"("p_lenser_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_lensers_get_trending"("p_limit" integer DEFAULT 10) RETURNS TABLE("lenser_id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "total_xp" bigint, "current_level" integer, "lenser_score" double precision)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'lensers', 'content', 'xp'
    AS $$
  SELECT
    lenser_id,
    handle,
    display_name,
    avatar_url,
    total_xp,
    current_level,
    lenser_score
  FROM lensers.vw_lensers_score
  ORDER BY lenser_score DESC
  LIMIT LEAST(p_limit, 50);
$$;


