CREATE OR REPLACE FUNCTION "public"."fn_list_template_workflows"("p_limit" integer DEFAULT 12, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "title" "text", "description" "text", "visibility" "text", "node_count" bigint, "reaction_totals" "jsonb", "fork_count" integer, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "author_handle" "text", "author_display_name" "text", "kinds" "text"[])
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'content', 'lensers'
    AS $$
  WITH tmpl AS (
    SELECT tm.entity_id AS workflow_id, tm.created_at AS marked_at
    FROM content.tag_map tm
    JOIN content.tags t ON t.id = tm.tag_id
    WHERE tm.entity_type = 'workflow'::content.entity_type_enum
      AND t.slug = 'template'
  )
  SELECT
    w.id,
    w.lenser_id,
    w.title,
    w.description,
    w.visibility::text,
    (
      SELECT count(*) FROM lenses.workflow_nodes wn WHERE wn.workflow_id = w.id
    ) AS node_count,
    w.reaction_totals,
    w.fork_count,
    w.created_at,
    w.updated_at,
    p.handle             AS author_handle,
    p.display_name       AS author_display_name,
    COALESCE(
      (
        SELECT array_agg(DISTINCT t.slug ORDER BY t.slug)
        FROM   lenses.workflow_nodes wn
        JOIN   lenses.lenses   ll  ON ll.id  = wn.lens_id
        JOIN   content.tag_map tm2 ON tm2.entity_id   = ll.id
                                   AND tm2.entity_type = 'lens'::content.entity_type_enum
        JOIN   content.tags    t   ON t.id = tm2.tag_id
                                   AND t.slug IN (
                                     'text','image','video','audio','music',
                                     'research','pdf','transform','orchestration',
                                     'validation','routing',
                                     'code','data','planning','community','documentation'
                                   )
        WHERE  wn.workflow_id = w.id
      ),
      ARRAY[]::text[]
    ) AS kinds
  FROM  tmpl
  JOIN  lenses.workflows   w ON w.id  = tmpl.workflow_id
  LEFT JOIN lensers.profiles p ON p.id = w.lenser_id
  WHERE w.visibility::text = 'public'
  ORDER BY tmpl.marked_at ASC, w.title ASC
  LIMIT  p_limit
  OFFSET p_offset;
$$;


ALTER FUNCTION "public"."fn_list_template_workflows"("p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_list_template_workflows"("p_limit" integer, "p_offset" integer) IS 'Lists curated template workflows that power the "Start from template" strip on WorkflowsPage. A workflow is considered a template when it has a content.tag_map row linking it to the `template` tag.';



CREATE OR REPLACE FUNCTION "public"."fn_list_threads"("p_cursor" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20, "p_tag_slug" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "author_lenser_id" "uuid", "lenser_id" "uuid", "visibility" "text", "title" "text", "content" "text", "lenser_handle" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "reply_count" integer, "view_count" integer, "thumbnail_url" "text", "linked_lens_id" "uuid", "lens_data" "jsonb")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'content', 'lensers'
    AS $$
  SELECT
    t.id,
    t.lenser_id  AS author_lenser_id,
    t.lenser_id,
    t.visibility::text,
    COALESCE(et.title, 'Untitled') AS title,
    COALESCE(et.content, '')       AS content,
    prof.handle                    AS lenser_handle,
    t.created_at,
    t.updated_at,
    t.reply_count,
    t.view_count,
    t.thumbnail_url,
    t.linked_lens_id,
    t.lens_data
  FROM content.threads t
  LEFT JOIN content.entity_translations et
         ON et.entity_id   = t.id
        AND et.entity_type = 'thread'::content.entity_type_enum
        AND et.is_original = true
  LEFT JOIN lensers.profiles prof ON prof.id = t.lenser_id
  WHERE t.lenser_id = lensers.get_auth_lenser_id()
    AND (
      p_cursor IS NULL
      OR t.created_at < (SELECT ct.created_at FROM content.threads ct WHERE ct.id = p_cursor)
    )
    AND (
      p_tag_slug IS NULL
      OR EXISTS (
        SELECT 1
        FROM content.tag_map tm
        JOIN content.tags tg ON tg.id = tm.tag_id
        WHERE tm.entity_id   = t.id
          AND tm.entity_type = 'thread'::content.entity_type_enum
          AND tg.slug = p_tag_slug
      )
    )
  ORDER BY t.created_at DESC
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."fn_list_threads"("p_cursor" "uuid", "p_limit" integer, "p_tag_slug" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_list_threads"("p_cursor" "uuid", "p_limit" integer, "p_tag_slug" "text") IS 'Lists threads owned by the current authenticated user (all visibilities) with title, content, and lenser_handle pre-joined. Used by threadsRepository.getByLenser(includePrivate=true) when the viewer is the profile owner. Supports cursor pagination and optional tag-slug filtering. Title/content come from entity_translations so private threads hydrate correctly without a second public-view lookup.';



