CREATE OR REPLACE FUNCTION "public"."fn_notify_battle_result"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_battle        battles.battles;
  v_winner        battles.contenders;
  v_action_url    TEXT;
  v_email_payload JSONB;
  v_voter_ids     UUID[];
  v_contender     RECORD;
  v_outcome_type  TEXT;
  v_body_text     TEXT;
BEGIN
  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id;
  IF NOT FOUND THEN RETURN; END IF;

  IF v_battle.winner_contender_id IS NOT NULL THEN
    SELECT * INTO v_winner FROM battles.contenders WHERE id = v_battle.winner_contender_id;
    v_body_text := 'Winner: ' || COALESCE(v_winner.display_name, 'Unknown');
  ELSE
    v_body_text := 'The battle ended in a draw.';
  END IF;

  v_action_url := '/battles/' || v_battle.slug || '/result';

  -- ── Contenders: differentiated battle_won / battle_lost ──────────────────
  FOR v_contender IN
    SELECT
      cem.profile_id                                                AS lenser_id,
      c.id                                                          AS contender_id,
      (c.id = v_battle.winner_contender_id)                        AS is_winner
    FROM   battles.contenders c
    JOIN   battles.contender_entity_map cem ON cem.contender_id = c.id
    WHERE  c.battle_id     = p_battle_id
      AND  cem.profile_id  IS NOT NULL
  LOOP
    v_outcome_type := CASE WHEN v_contender.is_winner THEN 'battle_won' ELSE 'battle_lost' END;

    PERFORM public.fn_insert_notification(
      v_contender.lenser_id,
      v_outcome_type,
      'Battle result: ' || v_battle.title,
      v_body_text,
      v_action_url,
      jsonb_build_object(
        'battle_id',     p_battle_id,
        'battle_slug',   v_battle.slug,
        'contender_id',  v_contender.contender_id,
        'winner_id',     v_battle.winner_contender_id,
        'winner_name',   COALESCE(v_winner.display_name, NULL),
        'is_winner',     v_contender.is_winner
      )
      -- p_actor_id = NULL: system outcome, skip block/mute gate
    );
  END LOOP;

  -- ── Voters: keep generic battle_result ───────────────────────────────────
  SELECT array_agg(DISTINCT voter_lenser_id) INTO v_voter_ids
  FROM   battles.votes
  WHERE  battle_id         = p_battle_id
    AND  voter_lenser_id   IS NOT NULL;

  IF v_voter_ids IS NOT NULL AND array_length(v_voter_ids, 1) > 0 THEN
    INSERT INTO public.notifications (lenser_id, type, title, body, action_url, metadata)
    SELECT
      unnest(v_voter_ids),
      'battle_result',
      'Battle result: ' || v_battle.title,
      v_body_text,
      v_action_url,
      jsonb_build_object(
        'battle_id',   p_battle_id,
        'battle_slug', v_battle.slug,
        'winner_id',   v_battle.winner_contender_id,
        'winner_name', COALESCE(v_winner.display_name, NULL)
      )
    ON CONFLICT DO NOTHING;
  END IF;

  -- ── Email edge function (unchanged) ───────────────────────────────────────
  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_net') THEN
    SELECT jsonb_build_object(
      'battle_id',        p_battle_id,
      'battle_title',     v_battle.title,
      'battle_slug',      v_battle.slug,
      'winner_name',      COALESCE(v_winner.display_name, NULL),
      'recipient_emails', (
        SELECT jsonb_agg(email)
        FROM   lensers.profiles
        WHERE  id = ANY(v_voter_ids)
          AND  email IS NOT NULL
      )
    ) INTO v_email_payload;

    PERFORM net.http_post(
      url     := current_setting('app.supabase_url', true) || '/functions/v1/send-battle-result-email',
      headers := jsonb_build_object(
        'Content-Type',  'application/json',
        'Authorization', 'Bearer ' || internal.get_service_role_key()
      ),
      body    := v_email_payload
    );
  END IF;

EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_notify_battle_result failed for battle %: %', p_battle_id, SQLERRM;
END;
$$;


ALTER FUNCTION "public"."fn_notify_battle_result"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_oauth_get_connection_for_refresh"("p_lenser_id" "uuid", "p_ref" "text", "p_workspace_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'vault'
    AS $$
DECLARE
  v_conn          public.user_oauth_connections%ROWTYPE;
  v_refresh_token text;
BEGIN
  SELECT * INTO v_conn
  FROM public.user_oauth_connections
  WHERE lenser_id = p_lenser_id
    AND ref       = p_ref
    AND (p_workspace_id IS NULL OR workspace_id = p_workspace_id)
    AND is_active = true
    AND revoked_at IS NULL;

  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  -- No refresh token stored — caller cannot refresh
  IF v_conn.refresh_token_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- Not near expiry (> 5 min remaining) — no refresh needed
  IF v_conn.expires_at IS NOT NULL
     AND v_conn.expires_at > (now() + interval '5 minutes')
  THEN
    RETURN NULL;
  END IF;

  SELECT decrypted_secret INTO v_refresh_token
  FROM vault.decrypted_secrets
  WHERE id = v_conn.refresh_token_id;

  IF v_refresh_token IS NULL THEN
    RETURN NULL;
  END IF;

  RETURN jsonb_build_object(
    'connection_id',   v_conn.id,
    'workspace_id',    v_conn.workspace_id,
    'refresh_token',   v_refresh_token,
    'expires_at',      v_conn.expires_at,
    'granted_scopes',  v_conn.granted_scopes,
    'provider',        v_conn.provider,
    'capability',      v_conn.capability
  );
END;
$$;


ALTER FUNCTION "public"."fn_oauth_get_connection_for_refresh"("p_lenser_id" "uuid", "p_ref" "text", "p_workspace_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_oauth_list_connections"() RETURNS TABLE("id" "uuid", "workspace_id" "uuid", "provider" "text", "capability" "text", "connection_label" "text", "ref" "text", "granted_scopes" "text"[], "expires_at" timestamp with time zone, "is_active" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
  SELECT
    c.id,
    c.workspace_id,
    c.provider,
    c.capability,
    c.connection_label,
    c.ref,
    c.granted_scopes,
    c.expires_at,
    c.is_active,
    c.created_at,
    c.updated_at
  FROM public.user_oauth_connections c
  JOIN lensers.profiles p ON p.id = c.lenser_id
  WHERE p.user_id = auth.uid()
    AND c.revoked_at IS NULL
  ORDER BY c.provider, c.capability, c.created_at DESC;
$$;


ALTER FUNCTION "public"."fn_oauth_list_connections"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_oauth_resolve_connection"("p_lenser_id" "uuid", "p_ref" "text", "p_required_scopes" "text"[] DEFAULT '{}'::"text"[], "p_workspace_id" "uuid" DEFAULT NULL::"uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'vault'
    AS $$
DECLARE
  v_conn         public.user_oauth_connections%ROWTYPE;
  v_access_token text;
BEGIN
  SELECT * INTO v_conn
  FROM public.user_oauth_connections
  WHERE lenser_id = p_lenser_id
    AND ref       = p_ref
    AND (p_workspace_id IS NULL OR workspace_id = p_workspace_id)
    AND is_active = true
    AND revoked_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'oauth_resolve_not_found: ref=% lenser=%', p_ref, p_lenser_id
      USING ERRCODE = 'P0002';
  END IF;

  -- Scope containment check: required ⊆ granted
  IF array_length(p_required_scopes, 1) > 0 THEN
    IF NOT (p_required_scopes <@ v_conn.granted_scopes) THEN
      RAISE EXCEPTION
        'oauth_resolve_scope_mismatch: ref=%, required=%, granted=%',
        p_ref, p_required_scopes, v_conn.granted_scopes
        USING ERRCODE = '42501';
    END IF;
  END IF;

  -- Retrieve access token from vault
  SELECT decrypted_secret INTO v_access_token
  FROM vault.decrypted_secrets
  WHERE id = v_conn.access_token_id;

  IF v_access_token IS NULL THEN
    RAISE EXCEPTION 'oauth_resolve_vault_miss: vault secret missing for ref=%', p_ref
      USING ERRCODE = 'P0001';
  END IF;

  RETURN v_access_token;
END;
$$;


ALTER FUNCTION "public"."fn_oauth_resolve_connection"("p_lenser_id" "uuid", "p_ref" "text", "p_required_scopes" "text"[], "p_workspace_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_oauth_revoke_connection"("p_connection_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  SELECT id INTO v_lenser_id
  FROM lensers.profiles
  WHERE user_id = auth.uid();

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'oauth_revoke_unauthorized: no profile for caller'
      USING ERRCODE = '42501';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.user_oauth_connections
    WHERE id = p_connection_id
      AND lenser_id = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'oauth_revoke_forbidden: connection not found or not owned'
      USING ERRCODE = '42501';
  END IF;

  UPDATE public.user_oauth_connections
  SET
    is_active  = false,
    revoked_at = now(),
    updated_at = now()
  WHERE id = p_connection_id
    AND lenser_id = v_lenser_id;
END;
$$;


ALTER FUNCTION "public"."fn_oauth_revoke_connection"("p_connection_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_oauth_upsert_connection"("p_lenser_id" "uuid", "p_workspace_id" "uuid", "p_provider" "text", "p_capability" "text", "p_label" "text", "p_access_token" "text", "p_refresh_token" "text" DEFAULT NULL::"text", "p_granted_scopes" "text"[] DEFAULT '{}'::"text"[], "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'vault'
    AS $$
DECLARE
  v_ref            text;
  v_access_name    text;
  v_refresh_name   text;
  v_access_id      uuid;
  v_refresh_id     uuid;
  v_conn_id        uuid;
BEGIN
  v_ref          := p_provider || '.' || p_capability || '.' || p_label;
  v_access_name  := 'oauth_access_'  || p_lenser_id::text || '_' || v_ref;
  v_refresh_name := 'oauth_refresh_' || p_lenser_id::text || '_' || v_ref;

  -- Store or rotate access token in vault
  SELECT id INTO v_access_id
  FROM vault.secrets
  WHERE name = v_access_name
  LIMIT 1;

  IF v_access_id IS NULL THEN
    INSERT INTO vault.secrets (name, secret, description)
    VALUES (v_access_name, p_access_token, 'OAuth access token: ' || v_ref)
    RETURNING id INTO v_access_id;
  ELSE
    UPDATE vault.secrets
    SET secret = p_access_token
    WHERE id = v_access_id;
  END IF;

  -- Store or rotate refresh token in vault (if provided)
  IF p_refresh_token IS NOT NULL THEN
    SELECT id INTO v_refresh_id
    FROM vault.secrets
    WHERE name = v_refresh_name
    LIMIT 1;

    IF v_refresh_id IS NULL THEN
      INSERT INTO vault.secrets (name, secret, description)
      VALUES (v_refresh_name, p_refresh_token, 'OAuth refresh token: ' || v_ref)
      RETURNING id INTO v_refresh_id;
    ELSE
      UPDATE vault.secrets
      SET secret = p_refresh_token
      WHERE id = v_refresh_id;
    END IF;
  END IF;

  -- Upsert the connection row (on conflict: update tokens + scopes + expiry)
  INSERT INTO public.user_oauth_connections (
    lenser_id,
    workspace_id,
    provider,
    capability,
    connection_label,
    ref,
    access_token_id,
    refresh_token_id,
    granted_scopes,
    expires_at,
    is_active,
    revoked_at,
    updated_at
  )
  VALUES (
    p_lenser_id,
    p_workspace_id,
    p_provider,
    p_capability,
    p_label,
    v_ref,
    v_access_id,
    v_refresh_id,
    p_granted_scopes,
    p_expires_at,
    true,
    NULL,
    now()
  )
  ON CONFLICT (lenser_id, workspace_id, ref) DO UPDATE
    SET access_token_id  = EXCLUDED.access_token_id,
        -- Only update refresh_token_id if a new one was provided
        refresh_token_id = COALESCE(
          CASE WHEN p_refresh_token IS NOT NULL THEN EXCLUDED.refresh_token_id END,
          user_oauth_connections.refresh_token_id
        ),
        granted_scopes   = EXCLUDED.granted_scopes,
        expires_at       = EXCLUDED.expires_at,
        is_active        = true,
        revoked_at       = NULL,
        updated_at       = now()
  RETURNING id INTO v_conn_id;

  RETURN v_conn_id;
END;
$$;


ALTER FUNCTION "public"."fn_oauth_upsert_connection"("p_lenser_id" "uuid", "p_workspace_id" "uuid", "p_provider" "text", "p_capability" "text", "p_label" "text", "p_access_token" "text", "p_refresh_token" "text", "p_granted_scopes" "text"[], "p_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_ops_submit_contact"("p_name" "text", "p_email" "text", "p_subject" "text", "p_message" "text", "p_kvkk_approved" boolean DEFAULT false, "p_ip_address" "text" DEFAULT NULL::"text", "p_user_agent" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'lensers', 'auth'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  -- Basic sanity guards
  IF trim(p_name) = '' OR trim(p_email) = '' OR trim(p_message) = '' THEN
    RAISE EXCEPTION 'name, email, and message are required' USING ERRCODE = '22023';
  END IF;

  IF NOT p_kvkk_approved THEN
    RAISE EXCEPTION 'KVKK consent is required' USING ERRCODE = '22023';
  END IF;

  -- Resolve optional lenser_id from auth context
  IF auth.uid() IS NOT NULL THEN
    SELECT id INTO v_lenser_id
    FROM lensers.profiles
    WHERE user_id = auth.uid()
    LIMIT 1;
  END IF;

  INSERT INTO analytics.contact (
    lenser_id,
    name,
    email,
    subject,
    message,
    kvkk_approved,
    ip_address,
    user_agent
  ) VALUES (
    v_lenser_id,
    trim(p_name),
    lower(trim(p_email)),
    trim(p_subject),
    trim(p_message),
    p_kvkk_approved,
    p_ip_address::inet,
    p_user_agent
  );
END;
$$;


