CREATE OR REPLACE FUNCTION "public"."fn_profile_completion_score"("p_lenser_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'xp', 'battles', 'public'
    AS $$
DECLARE
  v_score     integer := 0;
  v_bio       text;
  v_avatar    text;
  v_location  text;
  v_website   text;
  v_battles   bigint;
  v_total_xp  bigint;
BEGIN
  SELECT
    p.bio,
    p.avatar_url,
    p.location,
    p.website_url
  INTO v_bio, v_avatar, v_location, v_website
  FROM lensers.profiles p
  WHERE p.id = p_lenser_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  IF v_bio IS NOT NULL AND length(trim(v_bio)) > 0 THEN
    v_score := v_score + 25;
  END IF;
  IF v_avatar IS NOT NULL AND length(trim(v_avatar)) > 0 THEN
    v_score := v_score + 25;
  END IF;
  IF v_location IS NOT NULL AND length(trim(v_location)) > 0 THEN
    v_score := v_score + 15;
  END IF;
  IF v_website IS NOT NULL AND length(trim(v_website)) > 0 THEN
    v_score := v_score + 15;
  END IF;

  -- Battle participation ('cancelled' is not a valid battles.battle_status_enum value)
  SELECT COUNT(*) INTO v_battles
  FROM battles.contenders bc
  JOIN battles.battles b ON b.id = bc.battle_id
  WHERE bc.contender_ref_id = p_lenser_id
    AND b.status <> 'draft'::battles.battle_status_enum;

  IF v_battles > 0 THEN
    v_score := v_score + 10;
  END IF;

  -- XP earned (any positive amount)
  SELECT COALESCE(SUM(xp), 0) INTO v_total_xp
  FROM xp.events
  WHERE lenser_id = p_lenser_id;

  IF v_total_xp > 0 THEN
    v_score := v_score + 10;
  END IF;

  RETURN LEAST(v_score, 100);
END;
$$;


ALTER FUNCTION "public"."fn_profile_completion_score"("p_lenser_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_profile_completion_score"("p_lenser_id" "uuid") IS 'Returns a 0–100 profile completion score. Breakdown: bio +25, avatar +25, location +15, website +15, battles >0 +10, XP >0 +10.';



CREATE OR REPLACE FUNCTION "public"."fn_promote_scratchpad_to_memory"("p_run_id" "uuid", "p_memory_profile_id" "uuid") RETURNS "agents"."memory_profiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_run     agents.scratchpad_runs;
  v_profile agents.memory_profiles;
BEGIN
  SELECT * INTO v_run FROM agents.scratchpad_runs WHERE id = p_run_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'scratchpad run not found' USING ERRCODE = 'P0002';
  END IF;

  SELECT * INTO v_profile FROM agents.memory_profiles WHERE id = p_memory_profile_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory profile not found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_run.ai_lenser_id)
     OR NOT agents.can_manage_ai_lenser(v_profile.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized' USING ERRCODE = '42501';
  END IF;

  UPDATE agents.memory_profiles
  SET seed = seed || jsonb_build_array(jsonb_build_object(
        'source', 'scratchpad',
        'run_id', v_run.id,
        'prompt', v_run.prompt,
        'output', v_run.output,
        'promoted_at', now()
      )),
      updated_at = now()
  WHERE id = p_memory_profile_id
  RETURNING * INTO v_profile;

  RETURN v_profile;
END;
$$;


ALTER FUNCTION "public"."fn_promote_scratchpad_to_memory"("p_run_id" "uuid", "p_memory_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_publish_battle"("p_battle_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'extensions', 'public'
    AS $$
DECLARE
  v_lenser_id UUID := lensers.get_auth_lenser_id();
  v_hash TEXT;
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM battles.battles
    WHERE id = p_battle_id
      AND creator_lenser_id = v_lenser_id
      AND status = 'draft'::battles.battle_status_enum
      AND deleted_at IS NULL
  ) THEN
    RAISE EXCEPTION 'not_authorized_or_invalid_state' USING ERRCODE = '42501';
  END IF;

  v_hash := public.fn_create_battle_config_snapshot(p_battle_id, 'publish');

  UPDATE battles.battles
     SET status = 'open'::battles.battle_status_enum,
         published_at = now(),
         updated_at = now()
   WHERE id = p_battle_id;

  INSERT INTO audit.attestations (
    entity_type, entity_id, attested_by, attestation_type, proof_payload
  )
  VALUES (
    'battle', p_battle_id, v_lenser_id, 'battle_published',
    jsonb_build_object('snapshot_hash', v_hash, 'battle_id', p_battle_id)
  );

  INSERT INTO battles.events (battle_id, event_type, actor_id, metadata)
  VALUES (
    p_battle_id,
    'published',
    v_lenser_id,
    jsonb_build_object('snapshot_hash', v_hash)
  );

  RETURN jsonb_build_object(
    'snapshot_hash', v_hash,
    'status', 'open',
    'battle_id', p_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_publish_battle"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_publish_battle"("p_battle_id" "uuid") IS 'Atomically publishes a battle: freezes rules into rule_snapshots, transitions status to ''open'', and records an audit attestation. Phase A fix: search_path now includes extensions for pgcrypto digest(). Only the battle creator may call this. Battle must be in ''draft'' status. Direct UPDATE on battles.battles.status is restricted to service_role via column-level revoke (see A3 below).';



