CREATE OR REPLACE FUNCTION "public"."fn_resolve_execution_model"("p_provider_override" "text" DEFAULT NULL::"text", "p_model_override" "text" DEFAULT NULL::"text") RETURNS TABLE("model_id" "uuid", "model_key" "text", "provider_id" "uuid", "provider_key" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'ai'
    AS $$
DECLARE
  v_provider_id uuid;
BEGIN
  -- Resolve optional provider override to a provider_id
  IF p_provider_override IS NOT NULL THEN
    SELECT p.id INTO v_provider_id
    FROM ai.providers p
    WHERE p.key = p_provider_override
    LIMIT 1;
  END IF;

  RETURN QUERY
  SELECT m.id, m.key, m.provider_id,
         (SELECT pr.key FROM ai.providers pr WHERE pr.id = m.provider_id LIMIT 1)
  FROM ai.models m
  WHERE m.is_active = true
    AND (v_provider_id IS NULL OR m.provider_id = v_provider_id)
    AND (
      p_model_override IS NULL
      OR m.id::text = p_model_override
      OR m.key      = p_model_override
    )
  ORDER BY m.created_at ASC
  LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."fn_resolve_execution_model"("p_provider_override" "text", "p_model_override" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_resolve_execution_model"("p_provider_override" "text", "p_model_override" "text") IS 'Security wrapper: resolve the best active AI model, optionally filtered by provider key and/or model key/id. Returns model_id, model_key, provider_id, provider_key.';



CREATE OR REPLACE FUNCTION "public"."fn_resolve_handle_to_email"("p_handle" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $_$
DECLARE
  v_normalized text;
  v_user_id    uuid;
  v_email      text;
BEGIN
  -- 1. Normalise: strip leading @, trim whitespace, fold to lowercase
  v_normalized := lower(trim(regexp_replace(p_handle, '^@+', '')));

  -- 2. Reject inputs that cannot possibly be a stored handle
  --    (stored format: ^[a-z0-9._]{4,24}$)
  IF v_normalized !~ '^[a-z0-9._]{4,24}$' THEN
    RETURN NULL;
  END IF;

  -- 3. Look up the lenser profile — human accounts only, not deleted
  SELECT user_id
    INTO v_user_id
    FROM lensers.profiles
   WHERE handle = v_normalized
     AND type   = 'human'
     AND status NOT IN ('deleted'::lenser_status, 'pending_deletion'::lenser_status)
   LIMIT 1;

  IF v_user_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- 4. Fetch the email from auth.users
  SELECT email
    INTO v_email
    FROM auth.users
   WHERE id         = v_user_id
     AND deleted_at IS NULL
   LIMIT 1;

  -- Returns NULL when auth record is gone (orphaned profile)
  RETURN v_email;
END;
$_$;


ALTER FUNCTION "public"."fn_resolve_handle_to_email"("p_handle" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_resolve_handle_to_email"("p_handle" "text") IS 'Resolves a profile handle (username) to the associated auth.users email. Used exclusively by login flows to support handle+password authentication. Returns NULL for missing, deleted, or non-human handles. SECURITY: never surface the return value or its NULL state to end users; always return a generic "Invalid login credentials" error to callers.';



CREATE OR REPLACE FUNCTION "public"."fn_resolve_mentions"("p_ids" "uuid"[]) RETURNS TABLE("id" "uuid", "title" "text", "link" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'content', 'lensers', 'auth'
    AS $$
  SELECT
    l.id,
    COALESCE(t.title, '') AS title,
    '/lenses/' || l.id::text AS link
  FROM lenses.lenses l
  LEFT JOIN content.entity_translations t
    ON  t.entity_id   = l.id
    AND t.entity_type = 'lens'
    AND t.is_original = true
  WHERE l.id = ANY(p_ids)
    AND (
      l.visibility = 'public'
      OR l.lenser_id = lensers.get_auth_lenser_id()
    );
$$;


ALTER FUNCTION "public"."fn_resolve_mentions"("p_ids" "uuid"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_resolve_mentions"("p_ids" "uuid"[]) IS 'Batch-resolves lens mention IDs to (id, title, link). Caller sees their own private lenses; other private lenses are excluded. Replaces N+1 getLensDetail calls in mentionService.';



CREATE OR REPLACE FUNCTION "public"."fn_resolve_run_incident"("p_incident_id" "uuid", "p_resolution" "text") RETURNS "void"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
  UPDATE agents.run_incidents ri
  SET resolved_at = now(), resolution = p_resolution
  FROM agents.run_reports rr
  WHERE ri.id = p_incident_id
    AND ri.run_report_id = rr.id
    AND rr.ai_lenser_id IN (
      SELECT o.ai_lenser_id FROM agents.ownerships o
      WHERE o.owner_lenser_id = lensers.get_auth_lenser_id()
        AND o.revoked_at IS NULL
    );
$$;


ALTER FUNCTION "public"."fn_resolve_run_incident"("p_incident_id" "uuid", "p_resolution" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_actor UUID;
BEGIN
  v_actor := auth.uid();
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'P0001';
  END IF;

  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'Forbidden: super_admin required' USING ERRCODE = 'P0003';
  END IF;

  UPDATE audit.vote_anomalies
     SET resolved_at  = now(),
         resolved_by  = v_actor
   WHERE id = p_anomaly_id
     AND resolved_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Anomaly not found or already resolved' USING ERRCODE = 'P0002';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") IS 'CA: Marks an anomaly resolved. Requires super_admin.';



