CREATE OR REPLACE FUNCTION "public"."fn_rls_unprotected_tables"() RETURNS TABLE("schema_name" "text", "table_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT n.nspname::text, c.relname::text
  FROM pg_catalog.pg_class c
  JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
  WHERE c.relkind = 'r'
    AND n.nspname IN (
      'agents', 'lenses', 'battles', 'workflows',
      'audit', 'execution', 'devices', 'connectors'
    )
    AND NOT c.relrowsecurity
  ORDER BY n.nspname, c.relname;
$$;


ALTER FUNCTION "public"."fn_rls_unprotected_tables"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_rls_unprotected_tables"() IS 'BY: Returns tables in security-sensitive schemas that have relrowsecurity=false. Used by lf security rls-audit CLI command. SECURITY DEFINER; service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_run_evaluation"("p_evaluation_id" "uuid", "p_model_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_eval  agents.evaluations;
  v_run   agents.evaluation_runs;
BEGIN
  SELECT * INTO v_eval FROM agents.evaluations WHERE id = p_evaluation_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'evaluation not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT (v_eval.owner_lenser_id = auth.uid()
          OR (v_eval.ai_lenser_id IS NOT NULL AND agents.can_manage_ai_lenser(v_eval.ai_lenser_id))) THEN
    RAISE EXCEPTION 'not authorized' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.evaluation_runs (evaluation_id, model_id, status)
  VALUES (p_evaluation_id, p_model_id, 'queued')
  RETURNING * INTO v_run;

  RETURN v_run.id;
END;
$$;


