CREATE OR REPLACE FUNCTION "public"."fn_runner_bind_device"("p_runner_id" "uuid", "p_device_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'execution', 'devices', 'lensers', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_binding_id UUID;
BEGIN
  SELECT id INTO v_lenser_id
  FROM lensers.profiles
  WHERE user_id = auth.uid() AND status = 'active'
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'active_lenser_required' USING ERRCODE = '42501';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM execution.runners r
    WHERE r.id = p_runner_id AND r.lenser_id = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'runner_not_found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM devices.registered_devices d
    WHERE d.id = p_device_id
      AND d.lenser_id = v_lenser_id
      AND d.trust_level IN ('approved','trusted')
  ) THEN
    RAISE EXCEPTION 'device_not_found_or_not_trusted' USING ERRCODE = '42501';
  END IF;

  INSERT INTO execution.runner_device_bindings (runner_id, device_id, status)
  VALUES (p_runner_id, p_device_id, 'active')
  ON CONFLICT (runner_id, device_id) DO UPDATE
    SET status = 'active', bound_at = now()
  RETURNING id INTO v_binding_id;

  RETURN v_binding_id;
END;
$$;


ALTER FUNCTION "public"."fn_runner_bind_device"("p_runner_id" "uuid", "p_device_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_runner_enable"("p_adapter_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'execution', 'lensers', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
BEGIN
  SELECT lp.id INTO v_lenser_id
  FROM lensers.profiles lp
  WHERE lp.user_id = auth.uid() AND lp.status = 'active'
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'active_lenser_required' USING ERRCODE = '42501';
  END IF;

  UPDATE execution.runners
     SET is_active = true,
         updated_at = now()
   WHERE id = p_adapter_id
     AND lenser_id = v_lenser_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'runner_not_found' USING ERRCODE = 'P0002';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_runner_enable"("p_adapter_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_runner_get"("p_adapter_id" "uuid") RETURNS TABLE("id" "uuid", "name" "text", "adapter_type" "text", "is_active" boolean, "config" "jsonb", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "last_probed_at" timestamp with time zone, "last_probe_status" "text")
