CREATE OR REPLACE FUNCTION "public"."fn_runner_probe"("p_adapter_id" "uuid", "p_prompt" "text" DEFAULT 'Hello, are you available?'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'execution', 'lensers', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_runner    execution.runners%ROWTYPE;
BEGIN
  SELECT lp.id INTO v_lenser_id
  FROM lensers.profiles lp
  WHERE lp.user_id = auth.uid() AND lp.status = 'active'
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'active_lenser_required' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_runner
    FROM execution.runners
   WHERE id = p_adapter_id
     AND lenser_id = v_lenser_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'runner_not_found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT v_runner.is_active THEN
    RAISE EXCEPTION 'runner_inactive' USING ERRCODE = 'P0001';
  END IF;

  UPDATE execution.runners
     SET last_probed_at = now(),
         last_probe_status = 'queued',
         updated_at = now()
   WHERE id = p_adapter_id;

  RETURN jsonb_build_object(
    'runner_id',     v_runner.id,
    'adapter_type',  v_runner.adapter_type,
    'probe_status',  'queued',
    'response',      'Probe queued; daemon will execute when reachable.',
    'note',          'Network probes are performed by lf-gatewayd, not the database.'
  );
END;
$$;


ALTER FUNCTION "public"."fn_runner_probe"("p_adapter_id" "uuid", "p_prompt" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_runner_register"("p_name" "text", "p_adapter_type" "text", "p_config" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'execution', 'lensers', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_runner_id UUID;
BEGIN
  SELECT id INTO v_lenser_id
  FROM lensers.profiles
  WHERE user_id = auth.uid() AND status = 'active'
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'active_lenser_required' USING ERRCODE = '42501';
  END IF;

  IF p_adapter_type NOT IN ('openai-agents','langchain','crewai','mcp','ollama','http','custom') THEN
    RAISE EXCEPTION 'invalid_adapter_type: %', p_adapter_type USING ERRCODE = '22023';
  END IF;

  INSERT INTO execution.runners (lenser_id, name, adapter_type, config)
  VALUES (v_lenser_id, p_name, p_adapter_type, COALESCE(p_config, '{}'))
  RETURNING id INTO v_runner_id;

  RETURN v_runner_id;
END;
$$;


ALTER FUNCTION "public"."fn_runner_register"("p_name" "text", "p_adapter_type" "text", "p_config" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_runner_remove"("p_adapter_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'execution', 'lensers', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
BEGIN
  SELECT lp.id INTO v_lenser_id
  FROM lensers.profiles lp
  WHERE lp.user_id = auth.uid() AND lp.status = 'active'
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'active_lenser_required' USING ERRCODE = '42501';
  END IF;

  -- Soft-deactivate (preserve audit trail).
  UPDATE execution.runners
     SET is_active = false,
         updated_at = now()
   WHERE id = p_adapter_id
     AND lenser_id = v_lenser_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'runner_not_found' USING ERRCODE = 'P0002';
  END IF;

  -- Pause any active device bindings; do not delete (keeps history intact).
  UPDATE execution.runner_device_bindings
     SET status = 'paused'
   WHERE runner_id = p_adapter_id
     AND status = 'active';
END;
$$;


ALTER FUNCTION "public"."fn_runner_remove"("p_adapter_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_save_workflow_node_config"("p_node_id" "uuid", "p_config" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  v_lenser_id := lensers.get_auth_lenser_id();

  -- Guard: caller must own the workflow that contains this node
  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_nodes n
    JOIN lenses.workflows w ON w.id = n.workflow_id
    WHERE n.id = p_node_id
      AND w.lenser_id = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'node_not_found_or_forbidden';
  END IF;

  UPDATE lenses.workflow_nodes
  SET config = p_config
  WHERE id = p_node_id;
END;
$$;


ALTER FUNCTION "public"."fn_save_workflow_node_config"("p_node_id" "uuid", "p_config" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_schedule_account_deletion"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_uid uuid;
  v_deadline timestamptz;
  v_profile RECORD;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT id, user_id, status
  INTO v_profile
  FROM lensers.profiles
  WHERE user_id = v_uid
  FOR UPDATE;

  IF NOT FOUND OR v_profile.status NOT IN ('active', 'deactivated') THEN
    RETURN jsonb_build_object('success', false, 'reason', 'not_eligible');
  END IF;

  v_deadline := now() + interval '30 days';

  -- Step 1: set the deletion timestamps. Existing trigger may temporarily move
  -- active profiles to `deactivated`, so we normalize status in step 2.
  UPDATE lensers.profiles
  SET deletion_requested_at = COALESCE(deletion_requested_at, now()),
      deletion_deadline_at = v_deadline,
      updated_at = now()
  WHERE id = v_profile.id;

  -- Step 2: persist the intended grace-period state used by purge + auth flow.
  UPDATE lensers.profiles
  SET status = 'pending_deletion',
      deletion_deadline_at = v_deadline,
      updated_at = now()
  WHERE id = v_profile.id;

  PERFORM lensers.log_account_lifecycle_event(
    v_profile.id,
    v_profile.user_id,
    'deletion_scheduled',
    v_profile.status,
    'pending_deletion'::lensers.lenser_status,
    'user_action',
    jsonb_build_object('deletion_deadline_at', v_deadline)
  );

  RETURN jsonb_build_object('success', true, 'status', 'pending_deletion', 'deadline', v_deadline);
END;
$$;


ALTER FUNCTION "public"."fn_schedule_account_deletion"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_schedule_battle"("p_battle_id" "uuid", "p_execution_starts_at" timestamp with time zone, "p_voting_duration_hours" integer DEFAULT 24, "p_auto_publish" boolean DEFAULT true) RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "task_prompt" "text", "status" "text", "total_vote_count" integer, "published_at" timestamp with time zone, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "handicap_config" "jsonb", "creator_lenser_id" "uuid", "forum_thread_id" "text", "workflow_id" "uuid", "lens_id" "uuid", "execution_starts_at" timestamp with time zone, "auto_publish" boolean, "voting_duration_hours" integer, "vote_velocity" numeric, "og_image_url" "text", "winner_contender_id" "uuid", "parent_battle_id" "uuid", "deleted_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required.' USING ERRCODE = '42501';
  END IF;

  IF p_execution_starts_at IS NULL THEN
    RAISE EXCEPTION 'execution_starts_at must not be null.' USING ERRCODE = '22000';
  END IF;

  IF p_execution_starts_at <= now() THEN
    RAISE EXCEPTION 'execution_starts_at must be in the future (got %).',
      p_execution_starts_at USING ERRCODE = '22000';
  END IF;

  RETURN QUERY
  UPDATE battles.battles AS b
  SET
    execution_starts_at   = p_execution_starts_at,
    voting_duration_hours = COALESCE(p_voting_duration_hours, 24),
    auto_publish          = COALESCE(p_auto_publish, true)
  WHERE b.id = p_battle_id
    AND b.creator_lenser_id = v_lenser_id
  RETURNING
    b.id, b.slug, b.title, b.task_prompt, b.status::text, b.total_vote_count, b.published_at,
    b.voting_opens_at, b.voting_closes_at, b.battle_type::text, b.voter_eligibility::text, b.handicap_config,
    b.creator_lenser_id, b.forum_thread_id::text, b.workflow_id, b.lens_id,
    b.execution_starts_at, b.auto_publish, b.voting_duration_hours, b.vote_velocity, b.og_image_url,
    b.winner_contender_id, b.parent_battle_id, b.deleted_at;
END;
$$;


ALTER FUNCTION "public"."fn_schedule_battle"("p_battle_id" "uuid", "p_execution_starts_at" timestamp with time zone, "p_voting_duration_hours" integer, "p_auto_publish" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_search_lensers"("p_query" "text", "p_limit" integer DEFAULT 8) RETURNS TABLE("id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "type" "lensers"."lenser_type")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lensers', 'public'
    AS $$
  SELECT
    p.id,
    p.handle,
    p.display_name,
    p.avatar_url,
    p.type
  FROM lensers.profiles p
  WHERE
    p.status                = 'active'
    AND p.deletion_requested_at IS NULL
    AND (
      p.visibility::text = 'public'
      OR (p.visibility::text = 'community' AND lensers.get_auth_lenser_id() IS NOT NULL)
      OR p.id = lensers.get_auth_lenser_id()
    )
    AND (
      CASE
        WHEN left(p_query, 1) = '@' THEN
          p.handle ILIKE '%' || substring(p_query FROM 2) || '%'
        ELSE
          p.handle       ILIKE '%' || p_query || '%'
          OR p.display_name ILIKE '%' || p_query || '%'
      END
    )
  ORDER BY
    CASE
      WHEN left(p_query, 1) = '@' THEN
        CASE
          WHEN p.handle = lower(substring(p_query FROM 2))              THEN 0
          WHEN p.handle ILIKE lower(substring(p_query FROM 2)) || '%'   THEN 1
          ELSE 2
        END
      ELSE
        CASE
          WHEN p.handle = lower(p_query)     THEN 0
          WHEN p.handle ILIKE p_query || '%' THEN 1
          ELSE 2
        END
    END,
    p.handle
  LIMIT LEAST(COALESCE(p_limit, 8), 20);
$$;


ALTER FUNCTION "public"."fn_search_lensers"("p_query" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_search_lensers"("p_query" "text", "p_limit" integer) IS 'Search lensers by handle or display_name for battle invite / contender picker. Returns lenser type (human|ai) for wizard UI. Respects profile visibility: public=all, community=authenticated, private=self only. Prefix @ to restrict to handle-only search. LIMIT capped at 20. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_search_memory_entries"("p_query" "text", "p_profile_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "profile_id" "uuid", "ai_lenser_id" "uuid", "scope" "text", "source" "text", "content" "text", "confidence" numeric, "is_redacted" boolean, "created_at" timestamp with time zone, "rank" real)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'agents', 'public'
    AS $$
DECLARE
  v_limit integer := LEAST(GREATEST(COALESCE(p_limit, 20), 1), 50);
  v_query tsquery;
BEGIN
  IF p_query IS NULL OR length(trim(p_query)) = 0 THEN
    RETURN;
  END IF;

  v_query := plainto_tsquery('english', p_query);

  IF v_query::text = '' THEN
    -- The query string contained only stopwords; nothing to search for.
    RETURN;
  END IF;

  RETURN QUERY
    SELECT
      m.id,
      m.profile_id,
      m.ai_lenser_id,
      m.scope,
      m.source,
      m.content,
      m.confidence,
      m.is_redacted,
      m.created_at,
      ts_rank(to_tsvector('english', m.content), v_query) AS rank
    FROM agents.memories m
    WHERE
      (p_profile_id IS NULL OR m.profile_id = p_profile_id)
      AND m.is_redacted = false
      AND to_tsvector('english', m.content) @@ v_query
    ORDER BY rank DESC, m.created_at DESC
    LIMIT v_limit;
END;
$$;


ALTER FUNCTION "public"."fn_search_memory_entries"("p_query" "text", "p_profile_id" "uuid", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_search_memory_entries"("p_query" "text", "p_profile_id" "uuid", "p_limit" integer) IS 'Phase N1: Full-text search over agents.memories.content using a plain english tsquery. Honors RLS via SECURITY INVOKER. Returns up to 50 rows ranked by ts_rank.';



CREATE OR REPLACE FUNCTION "public"."fn_security_definer_no_search_path"() RETURNS TABLE("schema_name" "text", "function_name" "text", "full_signature" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT
    n.nspname::text                          AS schema_name,
    p.proname::text                          AS function_name,
    pg_catalog.pg_get_function_identity_arguments(p.oid)::text AS full_signature
  FROM pg_catalog.pg_proc p
  JOIN pg_catalog.pg_namespace n ON n.oid = p.pronamespace
  WHERE p.prosecdef = true                          -- SECURITY DEFINER
    AND n.nspname IN ('public', 'agents', 'lenses',
                      'battles', 'audit', 'execution')
    AND NOT EXISTS (
      SELECT 1 FROM pg_catalog.pg_options_to_table(p.proconfig) AS opt(option_name, option_value)
      WHERE opt.option_name = 'search_path'
    )
  ORDER BY n.nspname, p.proname;
$$;


ALTER FUNCTION "public"."fn_security_definer_no_search_path"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_security_definer_no_search_path"() IS 'BY: Returns SECURITY DEFINER functions that have no SET search_path configured. Used by lf security rls-audit CLI command. SECURITY DEFINER; service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_set_evaluation_baseline"("p_evaluation_id" "uuid", "p_run_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_score  numeric;
  v_result jsonb;
BEGIN
  SELECT score INTO v_score FROM agents.evaluation_runs WHERE id = p_run_id;

  INSERT INTO agents.evaluation_baselines (evaluation_id, run_id, score)
  VALUES (p_evaluation_id, p_run_id, v_score)
  ON CONFLICT (evaluation_id)
  DO UPDATE SET run_id = EXCLUDED.run_id, score = EXCLUDED.score
  RETURNING to_jsonb(agents.evaluation_baselines.*) INTO v_result;

  RETURN v_result;
END;
$$;


