CREATE OR REPLACE FUNCTION "public"."fn_upsert_provider_config"("p_ai_lenser_id" "uuid", "p_provider_key" "text", "p_base_url" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT 'unconfigured'::"text", "p_ai_key_id" "uuid" DEFAULT NULL::"uuid") RETURNS "agents"."provider_configs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_row agents.provider_configs;
BEGIN
  IF p_status NOT IN ('healthy', 'error', 'unconfigured') THEN
    RAISE EXCEPTION 'invalid status value: %', p_status USING ERRCODE = '22023';
  END IF;

  INSERT INTO agents.provider_configs (
    ai_lenser_id,
    provider_key,
    ai_key_id,
    base_url,
    status,
    configured_at,
    last_checked_at,
    updated_at
  )
  VALUES (
    p_ai_lenser_id,
    p_provider_key,
    p_ai_key_id,
    p_base_url,
    p_status,
    -- configured_at: set on first key association; preserved on subsequent updates
    CASE WHEN p_ai_key_id IS NOT NULL THEN now() ELSE NULL END,
    -- last_checked_at: set whenever a health check result (healthy/error) is recorded
    CASE WHEN p_status IN ('healthy', 'error') THEN now() ELSE NULL END,
    now()
  )
  ON CONFLICT (ai_lenser_id, provider_key) DO UPDATE
    SET ai_key_id       = COALESCE(EXCLUDED.ai_key_id,   provider_configs.ai_key_id),
        base_url        = COALESCE(EXCLUDED.base_url,    provider_configs.base_url),
        status          = EXCLUDED.status,
        configured_at   = CASE
                            WHEN EXCLUDED.ai_key_id IS NOT NULL
                              AND provider_configs.configured_at IS NULL
                            THEN now()
                            ELSE provider_configs.configured_at
                          END,
        last_checked_at = CASE
                            WHEN EXCLUDED.status IN ('healthy', 'error')
                            THEN now()
                            ELSE provider_configs.last_checked_at
                          END,
        updated_at      = now()
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."fn_upsert_provider_config"("p_ai_lenser_id" "uuid", "p_provider_key" "text", "p_base_url" "text", "p_status" "text", "p_ai_key_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_upsert_provider_config"("p_ai_lenser_id" "uuid", "p_provider_key" "text", "p_base_url" "text", "p_status" "text", "p_ai_key_id" "uuid") IS 'Upserts a provider config row. ai_key_id: COALESCE-preserves existing key reference if not passed (health-check updates). base_url: COALESCE-preserves existing value if not passed. configured_at: set only on first key association (not overwritten on re-health-check). last_checked_at: updated whenever status is healthy or error. Called by authenticated users (after fn_store_api_key) and by test-provider Edge Function (service_role).';



CREATE OR REPLACE FUNCTION "public"."fn_upsert_workflow_edges"("p_workflow_id" "uuid", "p_edges" "jsonb") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "source_node_id" "uuid", "target_node_id" "uuid", "source_output_key" "text", "target_param_label" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id AND w.lenser_id = v_caller_id
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller does not own workflow %', p_workflow_id
      USING ERRCODE = '42501';
  END IF;

  -- Full replace: delete all existing edges for this workflow
  DELETE FROM lenses.workflow_edges
  WHERE lenses.workflow_edges.workflow_id = p_workflow_id;

  -- Insert incoming edges (skip if array is empty)
  IF jsonb_array_length(p_edges) > 0 THEN
    INSERT INTO lenses.workflow_edges (
      id,
      workflow_id,
      source_node_id,
      target_node_id,
      source_output_key,
      target_param_label
    )
    SELECT
      COALESCE((e->>'id')::uuid, gen_random_uuid()),
      p_workflow_id,
      (e->>'source_node_id')::uuid,
      (e->>'target_node_id')::uuid,
      COALESCE(e->>'source_output_key', 'output'),
      e->>'target_param_label'
    FROM jsonb_array_elements(p_edges) AS e;
  END IF;

  -- Return ALL edges for the workflow (not just the ones we inserted)
  RETURN QUERY
    SELECT
      we.id,
      we.workflow_id,
      we.source_node_id,
      we.target_node_id,
      we.source_output_key,
      we.target_param_label
    FROM lenses.workflow_edges we
    WHERE we.workflow_id = p_workflow_id;
END;
$$;


ALTER FUNCTION "public"."fn_upsert_workflow_edges"("p_workflow_id" "uuid", "p_edges" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_upsert_workflow_edges"("p_workflow_id" "uuid", "p_edges" "jsonb") IS 'Bulk-upserts workflow edges for a workflow the caller owns.';



CREATE OR REPLACE FUNCTION "public"."fn_upsert_workflow_nodes"("p_workflow_id" "uuid", "p_nodes" "jsonb") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "lens_id" "uuid", "version_id" "uuid", "position_x" double precision, "position_y" double precision, "label" "text", "ordinal" integer, "config" "jsonb", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id AND w.lenser_id = v_caller_id
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller does not own workflow %', p_workflow_id
      USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  INSERT INTO lenses.workflow_nodes (
    id,
    workflow_id,
    lens_id,
    version_id,
    position_x,
    position_y,
    label,
    ordinal,
    config
  )
  SELECT
    COALESCE((n->>'id')::uuid, gen_random_uuid()),
    p_workflow_id,
    (n->>'lens_id')::uuid,
    (n->>'version_id')::uuid,
    COALESCE((n->>'position_x')::float, 0),
    COALESCE((n->>'position_y')::float, 0),
    n->>'label',
    COALESCE((n->>'ordinal')::integer, 0),
    COALESCE(n->'config', '{}'::jsonb)
  FROM jsonb_array_elements(p_nodes) AS n
  ON CONFLICT ON CONSTRAINT workflow_nodes_pkey DO UPDATE SET
    position_x = EXCLUDED.position_x,
    position_y = EXCLUDED.position_y,
    label      = EXCLUDED.label,
    ordinal    = EXCLUDED.ordinal,
    version_id = EXCLUDED.version_id,
    config     = EXCLUDED.config
  RETURNING
    lenses.workflow_nodes.id,
    lenses.workflow_nodes.workflow_id,
    lenses.workflow_nodes.lens_id,
    lenses.workflow_nodes.version_id,
    lenses.workflow_nodes.position_x,
    lenses.workflow_nodes.position_y,
    lenses.workflow_nodes.label,
    lenses.workflow_nodes.ordinal,
    lenses.workflow_nodes.config,
    lenses.workflow_nodes.created_at;
END;
$$;


