CREATE OR REPLACE FUNCTION "public"."fn_upsert_workflow_schedule"("p_workflow_id" "uuid", "p_schedule_id" "uuid" DEFAULT NULL::"uuid", "p_cron_expr" "text" DEFAULT '* * * * *'::"text", "p_timezone" "text" DEFAULT 'UTC'::"text", "p_description" "text" DEFAULT NULL::"text", "p_approval_policy" "jsonb" DEFAULT '{"requiresApproval": true}'::"jsonb", "p_is_active" boolean DEFAULT true, "p_global_model_id" "text" DEFAULT NULL::"text", "p_assignee_id" "uuid" DEFAULT NULL::"uuid", "p_workflow_assignment_id" "uuid" DEFAULT NULL::"uuid", "p_retry_policy" "jsonb" DEFAULT '{"maxRetries": 1}'::"jsonb", "p_failure_policy" "jsonb" DEFAULT '{"mode": "isolate"}'::"jsonb", "p_queue_policy" "jsonb" DEFAULT '{"mode": "parallel"}'::"jsonb", "p_inputs_template" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "cron_expr" "text", "timezone" "text", "description" "text", "is_active" boolean, "assignee_type" "text", "assignee_id" "uuid", "workflow_assignment_id" "uuid", "approval_policy" "jsonb", "retry_policy" "jsonb", "failure_policy" "jsonb", "queue_policy" "jsonb", "inputs_template" "jsonb", "global_model_id" "text", "next_run_at" timestamp with time zone, "last_run_at" timestamp with time zone, "last_run_id" "uuid", "last_dispatch_status" "text", "last_error_at" timestamp with time zone, "last_error_message" "text", "last_completed_at" timestamp with time zone, "last_result" "jsonb", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_owner_id          uuid;
  v_active_id         uuid := lensers.get_auth_lenser_id();
  v_human_id          uuid := lensers.get_auth_human_lenser_id();
  v_ai_lenser_id      uuid;
  v_parts             text[];
  v_requires_approval boolean;
  v_spending_limit    numeric;
BEGIN
  -- Resolve workflow owner (human profile id)
  SELECT w.lenser_id INTO v_owner_id
  FROM lenses.workflows w
  WHERE w.id = p_workflow_id;

  -- Authorize when:
  --   a) Active session lenser owns the workflow (legacy human session), OR
  --   b) Human profile resolved from active session owns the workflow
  --      (agent workspace active; human still owns the workflow), OR
  --   c) Caller is an admin.
  IF v_owner_id IS NULL
     OR (v_owner_id <> v_active_id
         AND (v_human_id IS NULL OR v_owner_id <> v_human_id)
         AND NOT public.is_admin())
  THEN
    RAISE EXCEPTION 'not the owner of workflow %', p_workflow_id
      USING ERRCODE = '42501';
  END IF;

  -- CRON validation
  v_parts := regexp_split_to_array(trim(COALESCE(p_cron_expr, '')), '\s+');
  IF array_length(v_parts, 1) <> 5 THEN
    RAISE EXCEPTION 'Invalid CRON expression "%" — expected 5 fields', p_cron_expr
      USING ERRCODE = '22023';
  END IF;

  -- Cycle detection
  IF p_is_active AND lenses.fn_workflow_has_cycle(p_workflow_id) THEN
    RAISE EXCEPTION 'Cannot activate schedule for a workflow with cycles'
      USING ERRCODE = '22023', DETAIL = 'cycle_detected';
  END IF;

  -- Approval-bypass guard + audit (unchanged)
  IF p_is_active THEN
    v_requires_approval := COALESCE(
      (p_approval_policy->>'requiresApproval')::boolean,
      true
    );

    IF NOT v_requires_approval THEN
      SELECT al.id, pol.spending_limit_credits
        INTO v_ai_lenser_id, v_spending_limit
      FROM agents.ai_lensers al
      JOIN agents.policies pol ON pol.id = al.policy_id
      WHERE al.profile_id = v_owner_id
      LIMIT 1;

      IF v_spending_limit IS NULL THEN
        RAISE EXCEPTION
          'Cannot activate a schedule with requiresApproval=false and no spending_limit_credits. '
          'Set a spending limit on the agent policy before disabling approval gates.'
          USING ERRCODE = '23514';
      END IF;

      IF v_ai_lenser_id IS NOT NULL THEN
        INSERT INTO agents.action_logs (ai_lenser_id, action_type, result, metadata)
        VALUES (
          v_ai_lenser_id,
          'approval_bypass_attempted',
          'recorded',
          jsonb_build_object(
            'workflow_id',    p_workflow_id,
            'schedule_id',    p_schedule_id,
            'actor_lenser_id', v_owner_id,
            'spending_limit', v_spending_limit
          )
        );
      END IF;
    END IF;
  END IF;

  RETURN QUERY
  SELECT * FROM lenses.fn_upsert_workflow_schedule_internal(
    p_workflow_id, p_schedule_id, p_cron_expr, p_timezone, p_description,
    p_approval_policy, p_is_active, p_global_model_id, p_assignee_id,
    p_workflow_assignment_id, p_retry_policy, p_failure_policy,
    p_queue_policy, p_inputs_template
  );
END;
$$;


ALTER FUNCTION "public"."fn_upsert_workflow_schedule"("p_workflow_id" "uuid", "p_schedule_id" "uuid", "p_cron_expr" "text", "p_timezone" "text", "p_description" "text", "p_approval_policy" "jsonb", "p_is_active" boolean, "p_global_model_id" "text", "p_assignee_id" "uuid", "p_workflow_assignment_id" "uuid", "p_retry_policy" "jsonb", "p_failure_policy" "jsonb", "p_queue_policy" "jsonb", "p_inputs_template" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_upsert_workflow_schedule"("p_workflow_id" "uuid", "p_schedule_id" "uuid", "p_cron_expr" "text", "p_timezone" "text", "p_description" "text", "p_approval_policy" "jsonb", "p_is_active" boolean, "p_global_model_id" "text", "p_assignee_id" "uuid", "p_workflow_assignment_id" "uuid", "p_retry_policy" "jsonb", "p_failure_policy" "jsonb", "p_queue_policy" "jsonb", "p_inputs_template" "jsonb") IS 'Upsert a workflow schedule. Authorizes the active session lenser OR the resolved human owner OR an admin so the call succeeds after workspace switches.';



CREATE OR REPLACE FUNCTION "public"."fn_upsert_workflow_task"("p_phase_id" "uuid", "p_workflow_id" "uuid", "p_title" "text", "p_prompt_text" "text" DEFAULT NULL::"text", "p_output_type" "text" DEFAULT 'text'::"text", "p_model_hint" "text" DEFAULT NULL::"text", "p_ordinal" integer DEFAULT 0, "p_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id AND w.lenser_id = lensers.get_auth_lenser_id()
  ) THEN
    RAISE EXCEPTION 'upsert_workflow_task_forbidden' USING ERRCODE = '42501';
  END IF;

  IF p_id IS NOT NULL THEN
    UPDATE lenses.workflow_tasks
    SET title = p_title, prompt_text = p_prompt_text, output_type = p_output_type,
        model_hint = p_model_hint, ordinal = p_ordinal, updated_at = now()
    WHERE id = p_id AND phase_id = p_phase_id
    RETURNING to_jsonb(lenses.workflow_tasks.*) INTO v_result;
  END IF;

  IF v_result IS NULL THEN
    INSERT INTO lenses.workflow_tasks
      (phase_id, workflow_id, title, prompt_text, output_type, model_hint, ordinal)
    VALUES (p_phase_id, p_workflow_id, p_title, p_prompt_text, p_output_type, p_model_hint, p_ordinal)
    RETURNING to_jsonb(lenses.workflow_tasks.*) INTO v_result;
  END IF;

  RETURN v_result;
END;
$$;


