CREATE OR REPLACE FUNCTION "public"."fn_worker_run_auto_promote_cycle"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  r         RECORD;
  promoted  integer := 0;
BEGIN
  FOR r IN
    SELECT id
    FROM   battles.battles
    WHERE  status      = 'draft'
      AND  auto_promote = TRUE
  LOOP
    BEGIN
      IF public.fn_battles_auto_promote(r.id) THEN
        promoted := promoted + 1;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'fn_worker_run_auto_promote_cycle: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN promoted;
END;
$$;


