CREATE OR REPLACE VIEW "battles"."v_battle_feed_item" AS
 SELECT "b"."id",
    "b"."slug",
    "b"."title",
    "b"."status",
    "b"."battle_type",
    "b"."voter_eligibility",
    "b"."total_vote_count",
    "b"."published_at",
    "b"."voting_opens_at",
    "b"."voting_closes_at",
    "b"."winner_contender_id",
    "b"."created_at",
    "b"."content_type",
    "ca"."id" AS "contender_a_id",
    "ca"."display_name" AS "contender_a_name",
    "ca"."contender_type" AS "contender_a_type",
    "cb"."id" AS "contender_b_id",
    "cb"."display_name" AS "contender_b_name",
    "cb"."contender_type" AS "contender_b_type",
        CASE
            WHEN ("b"."winner_contender_id" = "ca"."id") THEN 'A'::"text"
            WHEN ("b"."winner_contender_id" = "cb"."id") THEN 'B'::"text"
            ELSE NULL::"text"
        END AS "winner_slot"
   FROM (("battles"."battles" "b"
     LEFT JOIN "battles"."contenders" "ca" ON ((("ca"."battle_id" = "b"."id") AND ("ca"."slot" = 'A'::"bpchar") AND ("ca"."contender_status" = 'active'::"text"))))
     LEFT JOIN "battles"."contenders" "cb" ON ((("cb"."battle_id" = "b"."id") AND ("cb"."slot" = 'B'::"bpchar") AND ("cb"."contender_status" = 'active'::"text"))))
  WHERE (("b"."deleted_at" IS NULL) AND ("b"."status" = ANY (ARRAY['voting'::"battles"."battle_status_enum", 'scoring'::"battles"."battle_status_enum", 'closed'::"battles"."battle_status_enum", 'published'::"battles"."battle_status_enum", 'archived'::"battles"."battle_status_enum"])));


ALTER VIEW "battles"."v_battle_feed_item" OWNER TO "postgres";


COMMENT ON VIEW "battles"."v_battle_feed_item" IS 'Denormalized battle card for BattlesFeedPage. Used by fn_get_battles_feed. Includes contender names, winner_slot, and content_type for media-type badges. Only exposes post-draft statuses (voting, scoring, closed, published, archived).';



CREATE OR REPLACE VIEW "battles"."v_benchmark_dataset" AS
 SELECT "b"."id" AS "battle_id",
    "b"."title" AS "battle_title",
    "b"."task_source",
    "b"."challenge_type",
    "b"."contender_structure",
    "b"."judging_mode",
    ("b"."benchmark_config" ->> 'game_key'::"text") AS "benchmark_game_key",
    ("b"."benchmark_config" ->> 'dataset_schema_version'::"text") AS "dataset_schema_version",
    "b"."status" AS "battle_status",
    "b"."created_at" AS "battle_created_at",
    "gc"."id" AS "challenge_id",
    "gc"."challenge_type" AS "challenge_game_type",
    "gc"."content_hash" AS "challenge_hash",
    "gc"."difficulty",
    "gc"."language",
    "gc"."time_limit_seconds",
    "gc"."scoring_mode",
    "gc"."input_snapshot" AS "challenge_input_params",
    "gc"."question_text" AS "challenge_question",
    "gc"."question_payload" AS "challenge_payload",
    "gc"."answer_key_hash",
    "gc"."generator_lens_id",
    "gc"."generator_version_id",
    "gc"."execution_run_id" AS "generator_run_id",
    "gc"."locked_at" AS "challenge_locked_at",
    "b"."shared_input_snapshot",
    "co"."id" AS "contender_id",
    "co"."slot" AS "contender_slot",
    "co"."contender_type",
    "s"."id" AS "submission_id",
    "s"."integrity_hash" AS "submission_hash",
    "s"."output_modality",
    "s"."submitted_at",
    "s"."execution_run_id" AS "contender_run_id",
    "er"."latency_ms",
    "er"."token_input",
    "er"."token_output",
    "er"."credit_cost",
        CASE
            WHEN (("b"."benchmark_config" ->> 'anonymization_policy'::"text") = 'full'::"text") THEN NULL::"text"
            ELSE ("er"."model_id")::"text"
        END AS "model_id",
    "b"."winner_contender_id",
    "b"."normalized_score",
    "ajv"."score" AS "ai_judge_score",
        CASE
            WHEN (("b"."benchmark_config" ->> 'anonymization_policy'::"text") = 'full'::"text") THEN NULL::"text"
            ELSE "ajv"."model_key"
        END AS "ai_judge_model_key",
    ("b"."benchmark_config" ->> 'anonymization_policy'::"text") AS "anonymization_policy"
   FROM ((((("battles"."battles" "b"
     LEFT JOIN "battles"."generated_challenges" "gc" ON (("gc"."id" = "b"."generated_challenge_id")))
     LEFT JOIN "battles"."contenders" "co" ON (("co"."battle_id" = "b"."id")))
     LEFT JOIN "battles"."submissions" "s" ON ((("s"."battle_id" = "b"."id") AND ("s"."contender_id" = "co"."id") AND ("s"."is_final" = true))))
     LEFT JOIN "execution"."runs" "er" ON (("er"."id" = "s"."execution_run_id")))
     LEFT JOIN "battles"."ai_judge_verdicts" "ajv" ON ((("ajv"."battle_id" = "b"."id") AND ("ajv"."contender_id" = "co"."id"))))
  WHERE (((("b"."benchmark_config" ->> 'export_eligible'::"text"))::boolean IS TRUE) AND ("b"."status" = ANY (ARRAY['closed'::"battles"."battle_status_enum", 'published'::"battles"."battle_status_enum", 'archived'::"battles"."battle_status_enum"])) AND ("b"."deleted_at" IS NULL));


ALTER VIEW "battles"."v_benchmark_dataset" OWNER TO "postgres";


COMMENT ON VIEW "battles"."v_benchmark_dataset" IS 'Safe benchmark dataset export view. Filters to export_eligible=true battles in closed/published/archived state. Masks model_id and ai_judge_model_key when anonymization_policy=full. Never exposes answer_key_encrypted, API keys, private instructions, or BYOK references.';



CREATE OR REPLACE VIEW "battles"."v_execution_jobs_public" AS
 SELECT "id",
    "battle_id",
    "slot",
    "status",
    "claimed_at",
    "completed_at",
    "retry_count",
    "created_at"
   FROM "battles"."battle_execution_jobs" "j";


ALTER VIEW "battles"."v_execution_jobs_public" OWNER TO "postgres";


