CREATE TABLE IF NOT EXISTS "public"."user_oauth_connections" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "workspace_id" "uuid" NOT NULL,
    "provider" "text" NOT NULL,
    "capability" "text" NOT NULL,
    "connection_label" "text" NOT NULL,
    "ref" "text" NOT NULL,
    "auth_strategy" "text" DEFAULT 'oauth2'::"text" NOT NULL,
    "provider_config" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "access_token_id" "uuid" NOT NULL,
    "refresh_token_id" "uuid",
    "granted_scopes" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "expires_at" timestamp with time zone,
    "is_active" boolean DEFAULT true NOT NULL,
    "revoked_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "uoc_auth_strategy_check" CHECK (("auth_strategy" = ANY (ARRAY['oauth2'::"text", 'api_key'::"text", 'webhook'::"text", 'none'::"text"]))),
    CONSTRAINT "uoc_capability_check" CHECK (("capability" = ANY (ARRAY['database'::"text", 'page'::"text", 'gmail'::"text", 'drive'::"text", 'sheets'::"text", 'docs'::"text", 'calendar'::"text", 'tasks'::"text", 'boards'::"text", 'webhooks'::"text", 'chat'::"text", 'repos'::"text", 'issues'::"text", 'projects'::"text", 'lists'::"text", 'records'::"text", 'crm'::"text", 'messages'::"text", 'channels'::"text", 'files'::"text", 'events'::"text", 'http'::"text"]))),
    CONSTRAINT "uoc_label_format" CHECK (("connection_label" ~ '^[a-z0-9][a-z0-9_-]{0,47}$'::"text")),
    CONSTRAINT "uoc_provider_check" CHECK (("provider" = ANY (ARRAY['notion'::"text", 'google'::"text", 'asana'::"text", 'monday'::"text", 'zapier'::"text", 'slack'::"text", 'github'::"text", 'gitlab'::"text", 'jira'::"text", 'linear'::"text", 'trello'::"text", 'airtable'::"text", 'hubspot'::"text", 'salesforce'::"text", 'discord'::"text", 'microsoft_teams'::"text", 'microsoft_outlook'::"text", 'microsoft_onedrive'::"text", 'microsoft_excel'::"text", 'dropbox'::"text", 'box'::"text", 'calendly'::"text", 'clickup'::"text", 'todoist'::"text", 'custom_http'::"text"]))),
    CONSTRAINT "uoc_ref_format" CHECK ((("ref" ~ '^[a-z][a-z0-9_]*\.[a-z][a-z0-9_]*\.[a-z0-9][a-z0-9_-]{0,47}$'::"text") AND ("char_length"("ref") <= 120))),
    CONSTRAINT "uoc_revoke_consistency" CHECK (((("is_active" = true) AND ("revoked_at" IS NULL)) OR (("is_active" = false) AND ("revoked_at" IS NOT NULL))))
);


ALTER TABLE "public"."user_oauth_connections" OWNER TO "postgres";


COMMENT ON TABLE "public"."user_oauth_connections" IS 'Per-user OAuth connections to external providers. Tokens stored in Supabase Vault (never in this table). The ref column is the stable identifier for [[:connector:ref]] expression syntax. All writes go through SECURITY DEFINER RPCs; direct INSERT/UPDATE/DELETE is revoked from the authenticated role.';



COMMENT ON COLUMN "public"."user_oauth_connections"."ref" IS 'Stable connector reference slug, e.g. ''google.gmail.primary''. Used as the key in [[:connector:google.gmail.primary]] expressions.';



COMMENT ON COLUMN "public"."user_oauth_connections"."access_token_id" IS 'vault.secrets.id for the OAuth access token. Decrypted only server-side.';



COMMENT ON COLUMN "public"."user_oauth_connections"."refresh_token_id" IS 'vault.secrets.id for the OAuth refresh token. Null if provider does not issue one.';



CREATE OR REPLACE VIEW "public"."v_workflow_run_cost_breakdown" WITH ("security_invoker"='on') AS
 SELECT "r"."id" AS "run_id",
    "r"."workflow_id",
    "r"."status" AS "run_status",
    "r"."triggered_by",
    "count"("nr"."id") AS "total_nodes",
    "count"("nr"."id") FILTER (WHERE ("nr"."status" = 'completed'::"text")) AS "completed_nodes",
    "count"("nr"."id") FILTER (WHERE ("nr"."status" = ANY (ARRAY['failed'::"text", 'timed_out'::"text", 'invalidated'::"text", 'blocked'::"text"]))) AS "failed_nodes",
    "count"("nr"."id") FILTER (WHERE ("nr"."status" = 'skipped'::"text")) AS "skipped_nodes",
    COALESCE("sum"("nr"."input_tokens"), (0)::bigint) AS "total_input_tokens",
    COALESCE("sum"("nr"."output_tokens"), (0)::bigint) AS "total_output_tokens",
    COALESCE("sum"("nr"."cost_credits"), (0)::bigint) AS "total_cost_credits",
    COALESCE("sum"("nr"."retry_count"), (0)::bigint) AS "total_retries",
    (COALESCE("avg"("nr"."duration_ms"), (0)::numeric))::integer AS "avg_duration_ms",
    COALESCE("max"("nr"."duration_ms"), 0) AS "max_duration_ms",
    (COALESCE("avg"("nr"."ttfb_ms"), (0)::numeric))::integer AS "avg_ttfb_ms"
   FROM ("lenses"."workflow_runs" "r"
     LEFT JOIN "lenses"."workflow_node_results" "nr" ON (("nr"."run_id" = "r"."id")))
  GROUP BY "r"."id", "r"."workflow_id", "r"."status", "r"."triggered_by";


ALTER VIEW "public"."v_workflow_run_cost_breakdown" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_workflow_run_cost_breakdown" IS 'Phase 6 — Per-run token + credit + latency rollup. Drives cost dashboards and per-lenser usage reports.';



CREATE OR REPLACE VIEW "public"."v_workflow_run_health" WITH ("security_invoker"='on') AS
 SELECT "id" AS "run_id",
    "workflow_id",
    "status",
    "run_worker_id",
    "heartbeat_at",
    "started_at",
    "completed_at",
    "parent_run_id",
    "recursion_depth",
    EXTRACT(epoch FROM ("now"() - COALESCE("heartbeat_at", "started_at"))) AS "seconds_since_heartbeat",
        CASE
            WHEN ("status" = ANY (ARRAY['completed'::"text", 'failed'::"text", 'cancelled'::"text", 'timed_out'::"text"])) THEN 'terminal'::"text"
            WHEN ("heartbeat_at" IS NULL) THEN 'no_heartbeat'::"text"
            WHEN (("now"() - "heartbeat_at") > '00:01:00'::interval) THEN 'stale'::"text"
            ELSE 'live'::"text"
        END AS "liveness",
    ( SELECT "count"(*) AS "count"
           FROM "lenses"."workflow_node_results" "nr"
          WHERE (("nr"."run_id" = "r"."id") AND ("nr"."status" = ANY (ARRAY['pending'::"text", 'awaiting_dependency'::"text", 'queued'::"text"])))) AS "pending_nodes",
    ( SELECT "count"(*) AS "count"
           FROM "lenses"."workflow_node_results" "nr"
          WHERE (("nr"."run_id" = "r"."id") AND ("nr"."status" = ANY (ARRAY['running'::"text", 'streaming'::"text", 'retrying'::"text"])))) AS "in_flight_nodes",
    ( SELECT "count"(*) AS "count"
           FROM "lenses"."workflow_node_results" "nr"
          WHERE (("nr"."run_id" = "r"."id") AND ("nr"."status" = ANY (ARRAY['completed'::"text", 'skipped'::"text"])))) AS "done_nodes"
   FROM "lenses"."workflow_runs" "r";


ALTER VIEW "public"."v_workflow_run_health" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_workflow_run_health" IS 'Phase 6 + 7 — Liveness + progress signals per run. `liveness` maps to recovery actions: live = leave alone, stale = candidate for fn_claim_stale_workflow_run, no_heartbeat = never advanced past queued, terminal = finished.';



CREATE OR REPLACE VIEW "public"."v_workflow_run_timeline" WITH ("security_invoker"='on') AS
 SELECT "r"."id" AS "run_id",
    "r"."workflow_id",
    "r"."status" AS "run_status",
    "r"."started_at" AS "run_started_at",
    "nr"."node_id",
    "n"."label" AS "node_label",
    "nr"."status" AS "node_status",
    "nr"."started_at" AS "node_started_at",
    "nr"."completed_at" AS "node_completed_at",
    "nr"."retry_count",
    "nr"."duration_ms",
    "nr"."ttfb_ms",
    "nr"."error_message",
    EXTRACT(epoch FROM ("nr"."started_at" - "r"."started_at")) AS "rel_start_s",
    EXTRACT(epoch FROM ("nr"."completed_at" - "r"."started_at")) AS "rel_end_s"
   FROM (("lenses"."workflow_runs" "r"
     JOIN "lenses"."workflow_node_results" "nr" ON (("nr"."run_id" = "r"."id")))
     LEFT JOIN "lenses"."workflow_nodes" "n" ON (("n"."id" = "nr"."node_id")))
  ORDER BY "r"."id", "nr"."started_at", "nr"."node_id";


ALTER VIEW "public"."v_workflow_run_timeline" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_workflow_run_timeline" IS 'Phase 6 — Chronological timeline of node execution within a run. Used by the monitoring UI to render Gantt-style lanes.';



