CREATE OR REPLACE VIEW "public"."vw_xp_leaderboard_season" AS
 WITH "ranked" AS (
         SELECT "st"."season_id",
            "s"."slug" AS "season_slug",
            "st"."app_id",
            "st"."lenser_id",
            "st"."total_xp",
            "rank"() OVER (PARTITION BY "st"."season_id", "st"."app_id" ORDER BY "st"."total_xp" DESC, "st"."lenser_id") AS "rank"
           FROM ("xp"."season_totals" "st"
             JOIN "xp"."seasons" "s" ON (("s"."id" = "st"."season_id")))
        ), "top100" AS (
         SELECT "ranked"."season_id",
            "ranked"."season_slug",
            "ranked"."app_id",
            "ranked"."lenser_id",
            "ranked"."total_xp",
            "ranked"."rank"
           FROM "ranked"
          WHERE ("ranked"."rank" <= 100)
        ), "me" AS (
         SELECT "ranked"."season_id",
            "ranked"."season_slug",
            "ranked"."app_id",
            "ranked"."lenser_id",
            "ranked"."total_xp",
            "ranked"."rank"
           FROM "ranked"
          WHERE ("ranked"."lenser_id" = "auth"."uid"())
        )
 SELECT "t"."season_id",
    "t"."season_slug",
    "t"."app_id",
    "t"."rank",
    "t"."lenser_id",
    "t"."total_xp",
    "jsonb_build_object"('display_name', "l"."display_name", 'handle', "l"."handle", 'avatar_url', "l"."avatar_url") AS "user"
   FROM ("top100" "t"
     JOIN "lensers"."profiles" "l" ON (("l"."id" = "t"."lenser_id")))
UNION
 SELECT "m"."season_id",
    "m"."season_slug",
    "m"."app_id",
    "m"."rank",
    "m"."lenser_id",
    "m"."total_xp",
    "jsonb_build_object"('display_name', "l"."display_name", 'handle', "l"."handle", 'avatar_url', "l"."avatar_url") AS "user"
   FROM ("me" "m"
     JOIN "lensers"."profiles" "l" ON (("l"."id" = "m"."lenser_id")));


ALTER VIEW "public"."vw_xp_leaderboard_season" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."workflow_integration_credentials" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "integration_type" "text" NOT NULL,
    "label" "text",
    "encrypted_config" "bytea" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "chk_wic_label_length" CHECK ((("label" IS NULL) OR ("length"("label") <= 100))),
    CONSTRAINT "chk_wic_type_valid" CHECK (("integration_type" = ANY (ARRAY['email'::"text", 'slack'::"text", 'discord'::"text", 'github'::"text", 'notion'::"text", 'google_sheets'::"text"])))
);


ALTER TABLE "public"."workflow_integration_credentials" OWNER TO "postgres";


