   FROM "battles"."battles" "b"
  WHERE ((("b"."id")::"text" = ("storage"."foldername"("objects"."name"))[1]) AND (("b"."status")::"text" = ANY (ARRAY['voting'::"text", 'scoring'::"text", 'closed'::"text", 'published'::"text"])))))));



