     JOIN "battles"."contender_entity_map" "cem" ON (("cem"."contender_id" = "c"."id")))
  WHERE ((("c"."battle_id")::"text" = ("storage"."foldername"("objects"."name"))[1]) AND (("c"."id")::"text" = ("storage"."foldername"("objects"."name"))[2]) AND ("cem"."profile_id" = "auth"."uid"()))))));



